INSERT INTO public.questions VALUES ('c0f09f74-6e4c-4d8c-b235-9309974d728e', 'ce4ef4e6-ff7e-44b9-9971-b6987f01c5ad', 'matrix', 'Questions 27–30', NULL, '<p>Label the diagram below.</p>
<p>Write the correct letter, <strong>A-G</strong>, next to questions 27-30.</p>
<p><img decoding="async" src="data:image/png;base64," width="406" height="385" loading="lazy"></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Metal container", "correctCategoryLetter": "D"}, {"itemText": "Integral strainer", "correctCategoryLetter": "F"}, {"itemText": "Drip tip", "correctCategoryLetter": "G"}, {"itemText": "Pottery container", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('528f2e92-93f5-4be6-986c-ca7a9622c496', '0f9633d5-3ad8-457f-9bce-f725a346e2bc', 'matrix', 'Questions 14–18', '', '<p><span class="fontstyle0">Write the correct letter, </span><strong><span class="fontstyle2">A–H</span></strong><span class="fontstyle0">, in boxes 14–18 on your answer sheet.</span></p>
<p><span class="fontstyle2"><strong>NB</strong> </span><span class="fontstyle0">You may use any letter more than once.</span> </p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "reference to how play can develop children’s verbal skills", "correctCategoryLetter": "B"}, {"itemText": "mention of a change in the amount of free play children engage in", "correctCategoryLetter": "A"}, {"itemText": "an account of some research indicating that free play stimulates children’s creativity", "correctCategoryLetter": "G"}, {"itemText": "evidence of the link between antisocial behaviour and a lack of free play", "correctCategoryLetter": "C"}, {"itemText": "a comparison between free play and other forms of play", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. B — {reference to how play can develop children’s verbal skills}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p id=\"p-rc_50968e829dc31142-30\" data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Studies <span class=\"citation-363 citation-364\">show that </span><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"30\"><span class=\"citation-363 citation-364\">children use more sophisticated language when playing with other children</span></strong><span class=\"citation-363 citation-364\"> than when playing with adults. In pretend play, for instance, they have to communicate about something that''s not physically present, </span><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"238\"><span class=\"citation-363 citation-364 citation-end-364\">so they have to use complicated<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span><span class=\"citation-363 citation-end-363\"> language<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span> to communicate what it is that they''re trying to say</strong>...”</em></p>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Verbal skills\" (kỹ năng ngôn ngữ/ngôn từ) được paraphrase bằng các từ \"language\" (ngôn ngữ), \"sophisticated language\" (ngôn ngữ phức tạp/tinh tế) và \"communicate\" (giao tiếp). Đoạn B giải thích rất rõ việc chơi cùng bạn bè ép trẻ phải dùng ngôn từ phức tạp để diễn đạt những thứ không có mặt ở đó, từ đó phát triển năng lực ngôn ngữ của trẻ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. A — {mention of a change in the amount of free play children engage in}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"12\">In the past, few children grew up without ample free-play time. But youngsters'' leisure hours are now filled with structured activities</strong> such as music lessons and sports... so why are experts worried that <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"216\">these activities are eating into free play</strong>?”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"A change in the amount\" (một sự thay đổi về mặt số lượng/thời lượng). Đoạn A mô tả sự thay đổi rõ rệt giữa quá khứ và hiện tại: Ngày xưa trẻ có rất nhiều thời gian chơi tự do (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"189\">ample free-play time</em>), nhưng ngày nay thời gian rảnh đó đã bị lấp đầy bởi các hoạt động có cấu trúc (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"290\">structured activities</em>) như học nhạc, thể thao, dẫn đến việc thời gian chơi tự do bị cắt giảm (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"384\">eating into free play</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. G — {an account of some research indicating that free play stimulates children’s creativity}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“In a classic study, researchers told a group of preschool children to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"82\">play freely with some common objects</strong>... The kids who had played with the objects named, on average, <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"182\">three times as many nonstandard, creative uses for the objects</strong> as those in either of the other two groups did, <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"293\">suggesting that play fosters imaginative thinking</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Stimulates children’s creativity\" (kích thích sự sáng tạo của trẻ) đồng nghĩa với cụm \"fosters imaginative thinking\" (nuôi dưỡng tư duy giàu tưởng tượng) và \"creative uses\" (những cách sử dụng sáng tạo). Đoạn G thuật lại một nghiên cứu (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"250\">an account of some research</em>) chứng minh nhóm trẻ được chơi tự do nghĩ ra nhiều cách dùng sáng tạo gấp 3 lần các nhóm khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. C — {evidence of the link between antisocial behaviour and a lack of free play}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“If play helps children become socialized, then <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"59\">lack of play should impede social development – and research suggests that it does</strong>. A study of children in Michigan revealed that kids who enrolled in play-oriented preschools were more socially adjusted later in life – and <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"283\">less likely to commit a felony or be suspended from work – than kids who attended play-free preschools</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Antisocial behaviour\" (hành vi chống đối xã hội) được minh họa cụ thể bằng hành động phạm tội đại hình (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"117\">commit a felony</em>) hoặc bị đình chỉ công tác (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"161\">be suspended from work</em>). Đoạn C đưa ra bằng chứng (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"212\">evidence/study</em>) cho thấy những đứa trẻ học ở ngôi trường thiếu vắng trò chơi (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"290\">play-free</em>) có tỷ lệ gặp các vấn đề bất ổn/chống đối xã hội cao hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. A — {a comparison between free play and other forms of play}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“Most <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"17\">games</strong> are fun... But, Pellegrini explains, <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"60\">“games have predetermined rules – set up in advance and followed. Play, on the other hand, does not have rules, so affords more creative responses</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A thực hiện một phép so sánh đối chiếu (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"57\">a comparison</strong>) trực tiếp giữa hai hình thức chơi: Trò chơi có luật (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"124\">Games</em> - có quy tắc định sẵn bắt buộc tuân theo) và Chơi tự do (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"187\">Play</em> - không có luật lệ, kích thích các phản ứng sáng tạo và sự tưởng tượng).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('a74c93eb-0727-4528-a464-156dcec8029a', '490e3d0f-d86d-43ad-9c94-b5b7621286ca', 'fillup', 'Questions 1–10', '<p>Write <strong>NO MORE THAN TWO WORDS</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Horseback- trip</strong></span></p>
<p>Length of trip: two days</p>
<p>Best month to go: September</p>
<p>Might see large numbers of {birds}</p>
<p>Type of accommodation: a {tent}</p>
<p><strong>Day one</strong></p>
<p>Final destination: {mountains}</p>
<p>Evening activity: chance to have a {swim}</p>
<p><strong>Day two</strong></p>
<p>Explore the valley and have lunch by a {waterfall}</p>
<p>Afternoon trip to a {cave}</p>
<p><strong>Tips for the holiday</strong></p>
<p>· unsuitable if you have {back} problems</p>
<p>· rocky paths so take {walking boots}</p>
<p><strong>Booking details</strong></p>
<p>Book online to get a {discount}</p>
<p>Inform your {insurance} company about the type of holiday booked</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<h2 data-path-to-node=\"2\">PART 1</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Jenny:</strong> hi Greg great to see you and thanks for emailing me with the details of the horseback riding trip you went on. I looked at the website and it looks great.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Greg:</strong> yeah I went on the 2 day mini break. Is that what you’re thinking about?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Jenny:</strong> yes that’s the one. Do you think they’d have places now in July or will it be full?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Greg:</strong> if you can hang on till September, that’s when I went and it was a really great time to go. It’s not so hot for a start.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Jenny:</strong> that’d suit me better anyway.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Greg:</strong> and also at one point when we stopped for a picnic, I was lying in a field looking up and saw a huge flock of <strong data-path-to-node=\"8\" data-index-in-node=\"116\">(1) birds</strong>. They were obviously migrating. That’s another reason why it’s a good time to go.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Jenny:</strong> oh great.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Greg:</strong> oh and another thing. You don’t stay in a hotel, you stay in a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"10\" data-index-in-node=\"69\">(2) tent</strong></span>, so you don’t have to come back to town in the evening.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Jenny:</strong> I’m up for that. So where do you go on the first day?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Greg:</strong> through some amazing wooded valleys full of chestnut and beech trees. But that’s just the morning. Where you’re really heading for is the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"12\" data-index-in-node=\"144\">(3) mountains</strong></span>, and when you set out, you can only see them in the far distance. You don’t actually get there until sunset.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Jenny:</strong> is it hard work riding all day?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Greg:</strong> no the pace is easy, and there are plenty of breaks built in for picnics and even a snooze. But on that first evening, when you’ve been riding all day, you get the opportunity to go for a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"14\" data-index-in-node=\"194\">(4) swim</strong></span> and you’ll really enjoy that.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Jenny:</strong> so relaxing. And what’s on day 2? You said something about the national park?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Greg:</strong> no, day two you go up this incredible valley. At the end of it there’s a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"16\" data-index-in-node=\"79\">(5) waterfall</strong></span>. It’s an amazing place to stop for lunch. We even spotted an eagle while we were sitting there. And in the afternoon there’s a trip that goes to a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"16\" data-index-in-node=\"240\">(6) cave</strong></span>. You can even ride into it.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Jenny:</strong> wow that sounds great I can’t wait.</p>\n<hr data-path-to-node=\"18\" />\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Greg:</strong> okay so what are your tips for horseback riding weekend?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Jenny:</strong> well I had a sore knee before I went and I was pretty worried about that. It was okay actually, but what you’ve got to watch for is that you don’t have any trouble with your <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"20\" data-index-in-node=\"181\">(7) back</strong></span>. Riding can really aggravate that.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Jenny:</strong> no problem there. And comfortable clothes I guess?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Greg:</strong> yeah, but another thing I hadn’t realized is that you actually walk the horses down some pretty steep and uneven paths, so make sure you have <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"22\" data-index-in-node=\"148\">(8) walking boots</strong></span>, not just normal riding boots. And even if you’re going in the autumn, make sure you don’t get sunburnt. Even if it looks cloudy take sunscreen, lots of it.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Jenny:</strong> I think you’ve convinced me to sign up. When I was looking at the website, I saw that if I register online, I can get a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"23\" data-index-in-node=\"127\">(9) discount</strong></span>. Did you do that or go through a travel agency?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Greg:</strong> I registered online of course. I just have to let my boss know when I want to take time off. And then the other important thing I read was that you have to make sure that your <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"24\" data-index-in-node=\"182\">(10) insurance</strong> </span>company know that you’re going on an adventure trip to make sure that you’re covered in case anything happens. I’m sure it won’t, but better be safe than sorry.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('ca96f3b0-c946-4037-8da7-37a8d02ba974', '1a17c47a-6a8d-4aef-aa6d-f45bb3014b3f', 'checkbox', 'Questions 20 and 21', '', '<p data-path-to-node="10">Choose <strong data-path-to-node="10" data-index-in-node="7">TWO</strong> letters, <strong data-path-to-node="10" data-index-in-node="20">A–E</strong>.</p>
<p data-path-to-node="11"><em data-path-to-node="11" data-index-in-node="0">Write the correct letters in boxes 20 and 21 on your answer sheet.</em></p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A They often used stolen vessels to carry out pirate attacks."}, {"correct": true, "option_text": "B They managed to escape capture by the authorities because they knew the area so well."}, {"correct": false, "option_text": "C They paid for information about the routes merchant ships would take."}, {"correct": true, "option_text": "D They depended more on the sea for their livelihood than on farming."}, {"correct": false, "option_text": "E They stored many of the goods taken in pirate attacks in coves along the coastline."}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">20.B. They managed to escape capture by the authorities because they knew the area so well. — {ĐÚNG}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"In addition, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"34\">knowledge of the local area</strong> helped the pirates to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"84\">avoid retaliation</strong> once a state fleet arrived.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc có kiến thức về địa phương (knowledge of the local area) đã giúp họ tránh được sự trả đũa/truy bắt (avoid retaliation) từ phía chính quyền khi hạm đội nhà nước đến. Điều này khớp hoàn toàn với ý \"escape capture\" nhờ \"knew the area so well\".</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">21.D. They depended more on the sea for their livelihood than on farming. — {ĐÚNG}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p id=\"p-rc_5f779076bbb5fc04-19\" data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"<span class=\"citation-35\">While the Mediterranean region is predominantly fertile, some parts are </span><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"93\"><span class=\"citation-35\">rugged and hilly, even mountainous</span></strong><span class=\"citation-35\">. In the ancient times, the inhabitants of these areas </span><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"182\"><span class=\"citation-35\">relied heavily on marine resources</span></strong><span class=\"citation-35 citation-end-35\">, including fish and sa<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>lt.\"</em></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Do địa hình hiểm trở, đồi núi (không thuận tiện cho canh tác nông nghiệp), cư dân ở những vùng này phải phụ thuộc nặng nề vào tài nguyên biển (marine resources). Cụm \"relied heavily on marine resources\" tương ứng với \"depended more on the sea for their livelihood\".</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('4e2aea39-6085-4bdc-a84d-1cfd8cb3f368', 'ca3db063-e6c2-4448-a7f4-e485eeb4bb0e', 'fillup', 'Question 1-10', '<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p><span style="font-size: 14pt;"><strong>Holiday Job</strong></span></p>
<p>Location {Jamieson} Island</p>
<p>Start date {11 July|11th July}</p>
<p>Available jobs</p>
<p>Vacancy 1: Calypso Bistro</p>
<p style="padding-left: 40px;">– working as a {waiter}</p>
<p style="padding-left: 40px;">– no experience needed</p>
<p>Vacancy 2: Guest Liaison</p>
<p style="padding-left: 40px;">– must be able to {sing}</p>
<p>Vacancy 3: Activities staff</p>
<p style="padding-left: 40px;">– help with games and water sports</p>
<p style="padding-left: 40px;">– need experience with {children}</p>
<p>Vacancy 4: In reception</p>
<p style="padding-left: 40px;">– as a porter</p>
<p style="padding-left: 40px;">– must be able to {drive}</p>
<p>Benefits: For all jobs,</p>
<p style="padding-left: 40px;">– there is free {transport}</p>
<p style="padding-left: 40px;">– {meals} are provided</p>
<p>Interview</p>
<p style="padding-left: 40px;">– to be held on {Thursday} at 2pm</p>
<p style="padding-left: 40px;">– bring a CV and a {photo}</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<h2>(Section 1)</h2>\n<p><strong>Narrator:</strong> You will hear a student phoning a student careers office about a job at a holiday resort. First you have some time to look at questions 1 to 6 on page two. You will see that there is an example that has been done for you. On this occasion only the conversation relating to this will be played first.</p>\n<p><strong>Agent:</strong> Hello. I saw an advert for holiday staff on the notice board and I’m very interested. Can you tell me something about the resort?</p>\n<p><strong>Career Office:</strong> Let me see, yes. Those jobs are at the Sandy Shores Resort. You may have heard of it, as it’s quite well known in the area.</p>\n<hr />\n<p><strong>Narrator:</strong> The name of the resort is Sandy Shores, so Sandy has been written in the space. Now we shall begin. You should answer the questions as you listen because you will not hear the recording a second time. Listen carefully and answer questions 1 to six.</p>\n<p><strong>Agent:</strong> Hello. I saw an advert for holiday staff on the notice board and I’m very interested. Can you tell me something about the resort?</p>\n<p><strong>Career Office:</strong> Let me see, yes. Those jobs are at the Sandy Shores Resort. You may have heard of it, as it’s quite well known in the area.</p>\n<p><strong>Student:</strong> I’m not sure where exactly is it?</p>\n<p><strong>Career Office:</strong> It’s on <strong>(1) Jamison</strong> Island.</p>\n<p><strong>Student:</strong> I haven’t heard of that one. Uh, how do you spell it?</p>\n<p><strong>Career Office:</strong> J-A-M-I-E-S-O-N. It was named after a famous explorer.</p>\n<p><strong>Student:</strong> Oh, sounds interesting.</p>\n<p><strong>Career Office:</strong> Yes, it’s a beautiful place, and as it’s a large resort, they have vacancies in a few different areas. When would they want someone to start?</p>\n<p><strong>Student:</strong> It looks like the applications close by May 12th, and they would need you to begin from <strong>(2) July 11th</strong>.</p>\n<p><strong>Student:</strong> Oh, that’s perfect. My exams finish on July 5th. Can you tell me something about the jobs?</p>\n<p><strong>Career Office:</strong> Well, first of all, there is a vacancy in the Calypso Bistro. That’s for a <strong>(3) waiter</strong>. The work is quite easy, taking orders and serving meals. You don’t need any experience as they will train you. That’s good.</p>\n<p><strong>Career Office:</strong> They’ve also got a few vacancies in what is called the Guest Liaison department. They are involved with the entertainment in the resort, especially the daily music shows and parades. They definitely need people who can <strong>(4) sing</strong>.</p>\n<p><strong>Student:</strong> What’s your voice like?</p>\n<p><strong>Career Office:</strong> It’s shocking! But I can play piano, would that be useful?</p>\n<p><strong>Career Office:</strong> I don’t think so, they already have a band. OK. So what else is there?</p>\n<p><strong>Career Office:</strong> Among the most popular things for guests are the games and water sports activities which take place on the beach that belongs to the resort. They are always looking for fit, young people to help out with things like volleyball, surfing and cricket, but they definitely need people who have worked with <strong>(5) children</strong> for that vacancy.</p>\n<p><strong>Student:</strong> Well, I coach junior basketball. Sounds great.</p>\n<p><strong>Career Office:</strong> Finally, there are vacancies in the reception area. You’d work as part of the Concierge department, carrying bags to and from rooms. A requirement for this role is that you can <strong>(6) drive</strong>. That might seem strange, but some of the Villas are quite far away from the resort hub, so they have little golf buggies to take the bags over to them.</p>\n<hr />\n<p><strong>Narrator:</strong> Before you hear the rest of the conversation, you have some time to look at questions 7 to 10 on page two. Now listen and answer questions 7 to ten.</p>\n<p><strong>Career Office:</strong> I expect you’d like to know a bit more about the general benefits for staff.</p>\n<p><strong>Student:</strong> Yes please. Do they provide free accommodation for staff?</p>\n<p><strong>Career Office:</strong> It looks like they only provide it to permanent employees, but staff don’t have to pay for <strong>(7) transport</strong> to and from the island, so you’d have to stay in Port Thomas, but there are plenty of cheap places there.</p>\n<p><strong>Student:</strong> What about meals?</p>\n<p><strong>Career Office:</strong> Yes, <strong>(8) meals</strong> are provided when you’re on duty, so you would save money on groceries.</p>\n<p><strong>Career Office:</strong> If you are interested, we can set up an interview for you. I know the resort personnel manager wants interviews on Wednesday, Thursday and Friday here at the college. Which day would suit you?</p>\n<p><strong>Student:</strong> Can we do it on <strong>(9) Thursday</strong> as I work on Wednesdays?</p>\n<p><strong>Career Office:</strong> Fine. Is 2:00 OK?</p>\n<p><strong>Student:</strong> Perfect.</p>\n<p><strong>Career Office:</strong> OK, I’ve booked you in for then. Is there anything I need to take to the interview?</p>\n<p><strong>Career Office:</strong> Let me see, yes. You need to bring a CV giving details of your work experience and qualifications, and because they are planning on interviewing a lot of people, they’ve asked everyone to provide a <strong>(10) photo</strong> as well, so they can remember who is who. Do you have any questions?</p>\n<p><strong>Narrator:</strong> That is the end of Section 1. You now have half a minute to check your answers. Now turn to Section 2 on page 3.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('c7c6f450-dd74-47f6-a573-dfece46c5e9a', '2975629a-6c7d-42c8-ac92-2da835611311', 'fillup', 'Questions 31–40', '<p data-start="101" data-end="169">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><strong><span style="font-size: 14pt;">Using natural building materials</span></strong></p>
<p>With all methods of building using natural materials, a good {foundation} is needed</p>
<p data-start="307" data-end="325"><strong>Rammed earth</strong></p>
<p>• A framework made from wood filled with soil</p>
<p>• The best soil has large quantities of {sand}</p>
<p data-start="439" data-end="462"><strong>Adobe (mud brick)</strong></p>
<p>• The most suitable soil for adobe bricks contains lots of {clay}</p>
<p>Advantages</p>
<ul data-start="557" data-end="646">
<li data-start="557" data-end="589">
<p>cheap and {convenient}</p>
</li>
<li data-start="590" data-end="646">
<p>little {training} is needed for brick-making</p>
</li>
</ul>
<p>Disadvantage</p>
<ul data-start="663" data-end="723">
<li data-start="663" data-end="723">
<p>a lot of water, time and {labour| labor} are required</p>
</li>
</ul>
<p data-start="730" data-end="747"><strong>Straw bales</strong></p>
<p>• Bales – large rectangular blocks of straw</p>
<p>• A {roof} needs to be constructed first</p>
<p>• The bales are covered with plaster for protection against {insects}</p>
<p>Advantage</p>
<ul data-start="941" data-end="982">
<li data-start="941" data-end="982">
<p>the bales act as efficient insulation</p>
</li>
</ul>
<p data-start="989" data-end="1001"><strong>Bamboo</strong></p>
<p>• This is a versatile material</p>
<p>Advantage</p>
<ul data-start="1048" data-end="1112">
<li data-start="1048" data-end="1112">
<p>the shape of the bamboo stalks gives them {strength}</p>
</li>
</ul>
<p>Disadvantages</p>
<ul data-start="1130" data-end="1183">
<li data-start="1130" data-end="1154">
<p>not widely available</p>
</li>
<li data-start="1155" data-end="1183">
<p>risk of {fire}</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: NATURAL BUILDING MATERIALS</strong></span></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> There is growing interest in building structures using natural materials these days. I’ll begin this lecture by looking at how some of these materials work, some advantages and problems associated with each.</p>\n<p data-path-to-node=\"4\">However, I must start by saying that all these materials and construction techniques require, first and foremost, a solid <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"122\">(31) foundation</strong></span>, which will most often need to be made of concrete. Thus the goal of using 100% natural materials may have to be slightly compromised.</p>\n<hr data-path-to-node=\"5\">\n<h3 data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">RAMMED EARTH</strong></h3>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Lecturer:</strong> One type of natural building material is what is known as rammed earth. Rammed earth is a construction method whereby a framework constructed of wood is set in place to act as temporary walls, and then damp earth or soil is placed within this framework. As it is added, the earth is packed down and subjected to intense compression, either by hand or by using specialized machinery.</p>\n<p data-path-to-node=\"8\">Across parts of Africa today, you can see military fortifications built in this way over 10,000 years ago still standing in remarkably good condition. The most appropriate type of soil for this construction method is one with a high concentration of <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"250\">(32) sand</strong></span> in it, though other kinds of soil are sometimes successfully used. Rammed earth buildings are well suited to dry, arid climates.</p>\n<hr data-path-to-node=\"9\">\n<h3 data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">ADOBE (MUD BRICK)</strong></h3>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Lecturer:</strong> Another form of natural construction is called the Adobe method, or sometimes the mud brick method. This utilizes bricks which can be made from a variety of soils, but are most suitable when made from a soil rich in <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"226\">(33) clay</strong></span>. The bricks have got to be carefully made to prevent them from cracking.</p>\n<p data-path-to-node=\"12\">The main advantage of this Adobe brick method is that the materials are cheap and also that it’s <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"97\">(34) convenient</strong></span> for people in many geographical areas. Thus, Adobe buildings have been traditional forms of construction in many societies and today can be found all over the world. The construction method is also popular because making the bricks requires minimal <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"362\">(35) training</strong>.</span></p>\n<p data-path-to-node=\"13\">However, the Adobe method does have its drawbacks. For proper preparation of the bricks, large quantities of water are required, and because these bricks are manufactured by hand, the process demands significant investment of time as well as <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"242\">(36) labor</strong></span> (hoặc labour), which can be backbreaking and exhausting.</p>\n<hr data-path-to-node=\"14\">\n<h3 data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">STRAW BALES</strong></h3>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Lecturer:</strong> A natural building material which has been popularized in the US is the use of straw bales to create walls. Straw is, of course, dried stalks of plants, especially tall grasses. The straw is shaped into large rectangular blocks called bales, tightly bound together, and these are excellent for use in the building of walls.</p>\n<p data-path-to-node=\"17\">When building with straw bales, the first thing that needs to be done is to construct a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"88\">(37) roof</strong> </span>supported by poles so that work can continue even if it rains. Then the straw bales are stacked up to form walls. The bales are then coated with a layer of plaster which seals and protects them and keeps the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"306\">(38) insects</strong></span> out of them. The most common reason for their use in building today is the fact that they provide a very effective means of insulation for the building.</p>\n<hr data-path-to-node=\"18\">\n<h3 data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">BAMBOO</strong></h3>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Lecturer:</strong> Another great building material is bamboo. This highly versatile plant is one of the fastest-growing plants in the world. One of its primary advantages is due to the hollow, round, and segmented shape of its individual stalks, which give it its <strong data-path-to-node=\"20\" data-index-in-node=\"255\"><span style=\"background-color: #f1c40f;\">(39) strength</span></strong>. And because of its lightweight, it is easy to handle.</p>\n<p data-path-to-node=\"21\">A significant drawback, however, is that the large varieties of bamboo which are best suited for construction grow only in tropical and subtropical regions of the world. And also, because it catches <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"199\">(40) fire</strong></span> easily, bamboo can be problematic and potentially dangerous.</p>\n<p data-path-to-node=\"22\">Now let’s take a look at possible sources of…</p>"}]', 0);
INSERT INTO public.questions VALUES ('34fc3c60-7fe1-4e44-aa5e-c4f71a404574', '0f9633d5-3ad8-457f-9bce-f725a346e2bc', 'matrix', 'Questions 19–22', '', '<p>Write the correct letter, <strong>A</strong>, <strong>B</strong>, <strong>C </strong>or <strong>D</strong>, in boxes 19–22 on your answer sheet.</p>
<p><strong>NB </strong>You may use any letter more than once. </p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "It encourages children to take other people’s wishes into account.", "correctCategoryLetter": "A"}, {"itemText": "It can serve to relieve stress.", "correctCategoryLetter": "C"}, {"itemText": "It prepares children for dealing with unpredictable situations.", "correctCategoryLetter": "D"}, {"itemText": "It is less useful for children when adults are involved.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Anthony Pellegrini", "categoryLetter": "A"}, {"categoryText": "Jaak Panksepp", "categoryLetter": "B"}, {"categoryText": "Stephen Siviy", "categoryLetter": "C"}, {"categoryText": "Marc Bekoff", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">19. A (Anthony Pellegrini) — {It encourages children to take other people’s wishes into account.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“They [kids] want this thing to keep going, so <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"67\">they''re willing to ‘go the extra mile'' to accommodate their playmates'' desires</strong>. Keeping things friendly requires communication... says educational psychologist <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"227\">Anthony Pellegrini</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Take other people’s wishes into account\" (bận tâm/gánh vác/đáp ứng mong muốn của người khác) đồng nghĩa với cụm \"accommodate their playmates'' desires\" (đáp ứng những khao khát/mong muốn của bạn chơi). Người đưa ra luận điểm này là <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"244\">Anthony Pellegrini</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">20. C (Stephen Siviy) — {It can serve to relieve stress.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“...The researchers then introduced another rat... and it began playing with one of the rats. ‘Shortly thereafter, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"135\">the first rat relaxed and became calm</strong>,’ says <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"180\">Siviy</strong>, ‘<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"188\">suggesting that play helped lessen its anxiety</strong>.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Relieve stress\" (giải tỏa căng thẳng/áp lực) đồng nghĩa với cụm \"lessen its anxiety\" (làm giảm sự lo âu) và giúp cơ thể thư giãn, bình tĩnh trở lại (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"162\">relaxed and became calm</em>). Thí nghiệm trên chuột này do nhà thần kinh học <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"235\">Stephen Siviy</strong> thực hiện và đúc kết.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">21. D (Marc Bekoff) — {It prepares children for dealing with unpredictable situations.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn H):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“‘Play is like a kaleidoscope,’ says evolutionary biologist <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"80\">Marc Bekoff</strong>, ‘in that it is random and creative. <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"129\">It encourages flexibility and creativity that may, in the future, be advantageous in unexpected situations or new environments</strong>.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Dealing with unpredictable situations\" (đối phó với những tình huống không thể dự đoán trước) đồng nghĩa với cụm \"advantageous in unexpected situations\" (có lợi trong những tình huống bất ngờ/ngoài dự kiến). Người phát biểu câu này là <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"248\">Marc Bekoff</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">22. A (Anthony Pellegrini) — {It is less useful for children when adults are involved.}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p id=\"p-rc_7ec60a35dd719e27-33\" data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"21\">Studies <span class=\"citation-412\">show that children use more sophisticated language when playing with other children than when playing with adults</span></strong><span class=\"citation-412 citation-end-412\">. In pretend play, for instance, they have to communicate about something that''s not physically present, so they have to use complicated language...’<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"292\">Pellegrini</strong> explains.”</em></p>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"When adults are involved\" (khi có người lớn tham gia vào). Bài đọc chỉ ra rằng trẻ em dùng ngôn ngữ tinh tế/phức tạp hơn nhiều khi chơi với các bạn đồng lứa (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"171\">with other children</em>) so với khi chơi với người lớn (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"223\">with adults</em>). Điều này có nghĩa là khi có người lớn tham gia, hoạt động chơi sẽ kém hiệu quả/ít hữu ích hơn trong việc phát triển ngôn ngữ của trẻ (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"371\">less useful</strong>). Luận điểm này do <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"402\">Pellegrini</strong> giải thích (đáp án A được dùng lại 2 lần).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('9c9a06cd-1244-4741-a305-592a2a4684f0', '4ab334fb-2f99-4645-8bcc-f7efaf9fdab3', 'radio', ' Questions 27–30', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "They need to try harder to be different from one another."}, {"option_text": "They share a similar understanding of consumer psychology."}, {"option_text": "They depend too much on the latest technology."}, {"option_text": "They should do more to analyse how consumers think."}], "question": "What does the writer suggest about supermarkets in the first paragraph?"}, {"correct": 3, "options": [{"option_text": "to give customers time to decide what they want to buy."}, {"option_text": "to present customers with a range of interesting bargains."}, {"option_text": "to ensure customers feel under no pressure to buy anything."}, {"option_text": "to help customers slowly prepare themselves to go shopping."}], "question": "The writer says the function of the ‘chill zone’ in supermarkets is"}, {"correct": 0, "options": [{"option_text": "ensures the customers will feel good about the first products they buy."}, {"option_text": "reduces the risk of customers damaging these products later on."}, {"option_text": "encourages customers to buy more of these products than they intended."}, {"option_text": "makes customers consider healthier options in other sections they visit."}], "question": "According to the writer, placing fruit and vegetables near the front of the store"}, {"correct": 2, "options": [{"option_text": "They spend more time in stores than they realise."}, {"option_text": "They believe stores make life unnecessarily difficult for them."}, {"option_text": "They are aware of some of the techniques used by stores."}, {"option_text": "They are confused by frequent changes in the layout of stores."}], "question": "What point does the writer make about shoppers in the third paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27: What does the writer suggest about supermarkets in the first paragraph?</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"8\">They share a similar understanding of consumer psychology.</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1, dòng 3–5.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It is more that they are all <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"41\">well-versed in the science of persuading people to buy things</strong> – a science that… is beginning to understand what motivates consumers…”</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả bác bỏ ý kiến cho rằng các siêu thị thiếu sáng tạo khi trông giống hệt nhau. Lý do thực sự là họ đều am hiểu “khoa học thuyết phục” (tâm lý học khách hàng) để thúc đẩy việc mua sắm.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28: The writer says the function of the ‘chill zone’ in supermarkets is</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"8\">to help customers slowly prepare themselves to go shopping.</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 1–4.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It takes a while for the mind to get into a shopping mode. People need to make a <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"93\">gentle start and take stock of the surroundings</strong>. This is why some supermarkets have a so-called ‘chill zone’…”</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Tâm trí con người cần thời gian để chuyển sang “chế độ mua sắm”. Khu vực “chill zone” (đọc báo, xem DVD) giúp khách hàng bắt đầu một cách nhẹ nhàng trước khi thực sự đi vào các gian hàng chính.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29 According to the writer, placing fruit and vegetables near the front of the store</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"8\">ensures the customers will feel good about the first products they buy.</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 8–10.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…selecting wholesome fresh food is an <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"52\">uplifting way to start shopping</strong>, and it makes people <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"105\">feel less guilty</strong> about reaching for the less nutritious stuff later on.”</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc chọn thực phẩm tươi sạch ngay đầu buổi mua sắm tạo cảm giác phấn chấn (uplifting) và giúp khách hàng bớt thấy tội lỗi khi mua những đồ ăn kém lành mạnh sau đó.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30: What point does the writer make about shoppers in the third paragraph?</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"8\">They are aware of some of the techniques used by stores.</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 4–5.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “But supermarkets <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"29\">know shoppers know this</strong>, so they use other tricks…”</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Người mua hàng đã “nắm thóp” (worked out) được rằng các mặt hàng thiết yếu như sữa thường bị để ở cuối cửa hàng. Cụm từ “supermarkets know shoppers know this” khẳng định khách hàng có nhận thức về các kỹ thuật sắp đặt này.</span></p>"}]', 0);
INSERT INTO public.questions VALUES ('6af1c046-2f01-4afe-ab61-a96dd97bf737', '4ab334fb-2f99-4645-8bcc-f7efaf9fdab3', 'radio', 'Questions 31–35', '', '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong>  if it is impossible to say what the writer thinks about this.</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Cheaper products are placed on lower shelves to minimise the likelihood that they will be bought."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Head offices should be more flexible about how products are arranged by supermarkets."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "There is widespread agreement on how products should be arranged on shelves."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Security cameras are a serious threat to customers’ privacy"}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Technology is the best tool for determining why shoppers fail to make purchases."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">31. Cheaper products are placed on lower shelves to minimise the likelihood that they will be bought.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 1–3.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…stores encourage customers to buy expensive branded products by arranging them at eye-level, <strong data-path-to-node=\"14,2,0\" data-index-in-node=\"108\">with cheaper ones lower down.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"14,3,0\"><strong data-path-to-node=\"14,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Siêu thị ưu tiên hàng đắt tiền ngang tầm mắt để khách dễ thấy và mua nhất, trong khi hàng rẻ bị đẩy xuống thấp để hạn chế sự chú ý.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. Head offices should be more flexible about how products are arranged by supermarkets.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong> (Lưu ý: Đáp án trong hình của bạn ghi là YES, nhưng thực tế đoạn 5 mô tả sự kiểm soát gắt gao của trụ sở chính).</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 3–5.</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Often head offices specify where everything has to be placed and <strong data-path-to-node=\"16,2,0\" data-index-in-node=\"77\">spot-checks are carried out</strong> to make sure instructions are followed to the letter.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,3,0\"><strong data-path-to-node=\"16,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc cho thấy các trụ sở chính đang áp đặt quy tắc cứng nhắc và kiểm tra đột xuất, không có sự linh hoạt. Câu hỏi mang tính chất kiến nghị dựa trên mâu thuẫn được nêu ở dòng tiếp theo về tranh cãi trong cách xếp hàng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. There is widespread agreement on how products should be arranged on shelves.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 5–7.</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “But shelf-positioning is <strong data-path-to-node=\"18,2,0\" data-index-in-node=\"37\">extremely controversial</strong>. Despite all the academic papers… <strong data-path-to-node=\"18,2,0\" data-index-in-node=\"97\">retailers have their own views.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"18,3,0\"><strong data-path-to-node=\"18,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Trái với “widespread agreement”, việc sắp xếp hàng hóa gây tranh cãi gay gắt và mỗi nhà bán lẻ lại có quan điểm riêng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. Security cameras are a serious threat to customers’ privacy.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 1–4.</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…security cameras in stores may be doing considerably more than watching out for theft. Pictures showing shoppers… can now be analysed.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,3,0\"><strong data-path-to-node=\"20,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ đề cập camera được dùng để phân tích hành vi mua sắm thay vì chỉ chống trộm, nhưng không hề bàn luận liệu điều này có phải là “mối đe dọa nghiêm trọng đến quyền riêng tư” hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. Technology is the best tool for determining why shoppers fail to make purchases.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 4–8.</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…data collected electronically <strong data-path-to-node=\"22,2,0\" data-index-in-node=\"45\">tells them little about why</strong> so many customers leave without making a purchase. <strong data-path-to-node=\"22,2,0\" data-index-in-node=\"124\">Face-to-face interviews reveal</strong> [more]…”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,3,0\"><strong data-path-to-node=\"22,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Công nghệ cao kể rất ít lý do, trong khi cách “low-tech” là phỏng vấn trực tiếp lại hiệu quả hơn trong việc giải thích tại sao khách hàng rời đi tay không.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('f74b62c2-44b5-4d53-aabc-1a00ed5c48f3', '0f9633d5-3ad8-457f-9bce-f725a346e2bc', 'fillup', 'Questions 23–26', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 23–26 on your answer sheet.</p>
<p style="text-align: center;"><span style="font-size: 14pt;"><strong>Animal research into the value of play</strong></span></p>
<ul>
<li>
<p>In studies researching links between play and social learning, experiments analysing protein levels in the {brains} of rats noted significant differences between rats which had played and those which had not.</p>
</li>
<li>
<p>In another study, rats made distressed by an object smelling of a {cat} experienced a noticeable reduction in their {anxiety} levels after they had been allowed to play.</p>
</li>
<li>
<p>A further experiment, in which rats had to move a {ball} in order to reach a reward, indicated that rats deprived of play were less skilled at dealing with problems. </p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">23. brains — {experiments analysing protein levels in the brains of rats noted significant differences...}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Examination revealed that the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"51\">brains of the rats</strong> which had played contained <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"97\">much higher levels of BDNF – a protein</strong> that stimulates the growth of new neurons – than those of the animals that had not.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thí nghiệm phân tích mức độ protein (cụ thể là protein BDNF) trong bộ não (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"87\">brains</strong>) của loài chuột và nhận thấy sự khác biệt lớn giữa nhóm được chơi và nhóm bị cô lập.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">24. cat — {...rats made distressed by an object smelling of a cat...}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“In 2008, neuroscientist Stephen Siviy put rats into a chamber and <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"87\">exposed them to a collar previously worn by a cat, making them visibly anxious</strong>. Later, the chamber was cleaned to <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"201\">remove the cat odor</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Distressed\" (bị hoảng loạn/lo âu) đồng nghĩa với từ \"visibly anxious\". \"An object\" (một vật thể) trong bài đọc chính là chiếc vòng cổ (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"148\">collar</em>). Vật thể này có mùi của một con mèo (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"193\">cat</strong> / <em data-path-to-node=\"7,1,0\" data-index-in-node=\"199\">cat odor</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">25. anxiety — {...experienced a noticeable reduction in their anxiety levels after they had been allowed to play.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“The researchers then introduced another rat... and it began playing with one of the rats. ‘Shortly thereafter, the first rat relaxed and became calm,’ says Siviy, ‘<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"185\">suggesting that play helped lessen its anxiety</strong>.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"A noticeable reduction\" (một sự sụt giảm rõ rệt) đồng nghĩa với động từ làm giảm bớt (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"99\">lessen</em>). Sau khi được cho chơi cùng một chú chuột khác, mức độ lo âu (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"169\">anxiety</strong>) của chú chuột bị stress đã giảm xuống, giúp nó bình tĩnh lại (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"240\">relaxed and became calm</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">26. ball — {...in which rats had to move a ball in order to reach a reward...}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn H):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“The researchers taught these rats... to <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"61\">pull a rubber ball out of the way to get a food treat</strong>. A few days later they switched the setup so the rats would have to <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"183\">push the same ball to get the treat</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Move\" (di chuyển) bao gồm cả hai hành động kéo (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"61\">pull</em>) và đẩy (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"75\">push</em>) được nhắc đến trong bài. \"A reward\" (phần thưởng) tương ứng với món đồ ăn ngon (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"161\">a food treat / the treat</em>). Vật thể mà lũ chuột phải di chuyển để giành phần thưởng chính là quả bóng (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"263\">ball</strong>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('f81c525d-cd84-478a-9ca4-c52f214abd1f', '67f52183-7612-453f-999e-03cde874f5f6', 'fillup', 'Questions 8–13', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><span style="font-size: 12pt;"><strong>History of the Pyramid of Cestius</strong></span></p>
<p><strong>Construction of Cestius’ pyramid</strong></p>
<ul>
<li data-list="bullet">it was made from {brick}<span class="fill-history-correct"> </span>, marble and cement</li>
<li data-list="bullet">its {shape} is different to the pyramids found in Egypt</li>
<li data-list="bullet">it was originally built in the {countryside} as building tombs in the city was forbidden</li>
<li data-list="bullet">Emperor Aurelian ordered that a wall had to be built around it</li>
</ul>
<p><strong>Restoration of Cestius’ pyramid in the 1660s</strong></p>
<ul>
<li data-list="bullet">in the 1660s, some broken {statues} were found next to it</li>
<li data-list="bullet">the {tunnel} inside the tomb suggests that robbers had been there</li>
<li data-list="bullet">the frescoes show mythological scenes, and images of vases</li>
</ul>
<p><strong>Restoration of Cestius’ pyramid today</strong></p>
<ul>
<li data-list="bullet">a Japanese businessman paid for its restoration</li>
<li data-list="bullet">climbers are helping to get rid of signs of {pollution}</li>
</ul>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">8. brick</strong></p>\n<p data-path-to-node=\"2,0,1,0,0\"><strong data-path-to-node=\"2,0,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn B, dòng 2–3.</p>\n<p data-path-to-node=\"2,0,1,1,0\"><strong data-path-to-node=\"2,0,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…and was constructed from <strong data-path-to-node=\"2,0,1,1,0\" data-index-in-node=\"40\">brick</strong> held together by a basic kind of cement on the inside.”.</p>\n<p data-path-to-node=\"2,0,1,2,0\"><strong data-path-to-node=\"2,0,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản liệt kê các vật liệu xây dựng nên kim tự tháp bao gồm: lớp đá cẩm tháp (marble) bên ngoài, gạch (<strong data-path-to-node=\"2,0,1,2,0\" data-index-in-node=\"117\">brick</strong>) và xi măng (cement) ở bên trong.</p>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">9. shape</strong></p>\n<p data-path-to-node=\"2,1,1,0,0\"><strong data-path-to-node=\"2,1,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn B, dòng 4–5.</p>\n<p data-path-to-node=\"2,1,1,1,0\"><strong data-path-to-node=\"2,1,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…so that the <strong data-path-to-node=\"2,1,1,1,0\" data-index-in-node=\"27\">shape</strong> of Cestius pyramid is quite unlike that of typical Egyptian ones.”.</p>\n<p data-path-to-node=\"2,1,1,2,0\"><strong data-path-to-node=\"2,1,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh rằng vì độ dốc của nó rất lớn, nên <strong data-path-to-node=\"2,1,1,2,0\" data-index-in-node=\"65\">hình dạng (shape)</strong> của kim tự tháp Cestius khác biệt so với các kim tự tháp điển hình ở Ai Cập.</p>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">10. countryside</strong></p>\n<p data-path-to-node=\"2,2,1,0,0\"><strong data-path-to-node=\"2,2,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn C, dòng 1–3.</p>\n<p data-path-to-node=\"2,2,1,1,0\"><strong data-path-to-node=\"2,2,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…since there was a strict Roman law prohibiting the placement of tombs within the city itself, the Pyramid of Cestius would have stood in <strong data-path-to-node=\"2,2,1,1,0\" data-index-in-node=\"152\">countryside</strong>.”.</p>\n<p data-path-to-node=\"2,2,1,2,0\"><strong data-path-to-node=\"2,2,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Do luật pháp La Mã nghiêm cấm đặt lăng mộ trong thành phố, nên ban đầu kim tự tháp này được xây dựng ở vùng <strong data-path-to-node=\"2,2,1,2,0\" data-index-in-node=\"120\">nông thôn (countryside)</strong>.</p>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">11. statues</strong></p>\n<p data-path-to-node=\"5,0,1,0,0\"><strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn D, dòng 8–10.</p>\n<p data-path-to-node=\"5,0,1,1,0\"><strong data-path-to-node=\"5,0,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…as well as fragments of bronze <strong data-path-to-node=\"5,0,1,1,0\" data-index-in-node=\"46\">statues</strong> that had once stood on them on either side of the pyramid.”.</p>\n<p data-path-to-node=\"5,0,1,2,0\"><strong data-path-to-node=\"5,0,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong quá trình khai quật vào những năm 1660, các mảnh vỡ (fragments) của các bức <strong data-path-to-node=\"5,0,1,2,0\" data-index-in-node=\"94\">tượng (statues)</strong> bằng đồng đã được tìm thấy ở phía trước kim tự tháp.</p>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">12. tunnel</strong></p>\n<p data-path-to-node=\"5,1,1,0,0\"><strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn D, dòng 11–13.</p>\n<p data-path-to-node=\"5,1,1,1,0\"><strong data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The people employed to excavate the pyramid did not find the urn… but they did come across a <strong data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"107\">tunnel</strong>.”.</p>\n<p data-path-to-node=\"5,1,1,2,0\"><strong data-path-to-node=\"5,1,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà khảo cổ không tìm thấy bình đựng tro cốt nhưng lại phát hiện ra một đường <strong data-path-to-node=\"5,1,1,2,0\" data-index-in-node=\"94\">hầm (tunnel)</strong>. Sự xuất hiện của đường hầm này là bằng chứng cho thấy những kẻ trộm mộ có thể đã đột nhập vào từ trước.</p>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">13. pollution</strong></p>\n<p data-path-to-node=\"8,0,1,0,0\"><strong data-path-to-node=\"8,0,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn G, dòng 2–3.</p>\n<p data-path-to-node=\"8,0,1,1,0\"><strong data-path-to-node=\"8,0,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The white exterior of the Pyramid of Cestius will have to be cleaned every few months to remove the layer of urban <strong data-path-to-node=\"8,0,1,1,0\" data-index-in-node=\"127\">pollution</strong>.”.</p>\n<p data-path-to-node=\"8,0,1,2,0\"><strong data-path-to-node=\"8,0,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Hiện nay, một nhóm người leo núi (climbers) được thuê để làm sạch bề mặt bên ngoài của kim tự tháp nhằm loại bỏ các dấu vết của sự <strong data-path-to-node=\"8,0,1,2,0\" data-index-in-node=\"143\">ô nhiễm (pollution)</strong> từ đô thị.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('99e044b1-8e2d-4d7b-9077-606a7e1b59de', 'a673a9c0-921b-48d4-9683-64f1920b7fe8', 'radio', 'Questions 1–8', '', '<p>Choose <strong>TRUE</strong> if the statement agrees with the information ,<strong>FALSE</strong> if the statement contradicts the information ,<strong>NOT GIVEN</strong> if there is no information about this</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Harvard and Yale were the first universities to benefit from philanthropy."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Merchants liked to donate to the same universities they attended themselves"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The first gift to the University of Auckland came in 1884."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The University of Otago often received larger gifts than Gillies’ gift to Auckland."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In the 1930s the government wanted to close Auckland’s engineering school."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "After raising $6,500, Crookes returned to academic life"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In the 1950s the best lecturers chose to work in Britain or Australia rather than Auckland."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "A single philanthropist was responsible for the new Medical School."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">1. Harvard and Yale were the first universities to benefit from philanthropy. — {FALSE}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“This has been true from some of the <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"57\">oldest universities such as Bologna, Oxford and Cambridge in the twelfth century, to relative newcomers like the universities of Harvard and Yale in the seventeenth century</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ ra rằng các trường đại học lâu đời ở thế kỷ XII (Bologna, Oxford, Cambridge) đã được hưởng lợi từ việc hiến tặng trước. Harvard và Yale được gọi là \"những trường đến sau\" (<em data-path-to-node=\"8,1,0\" data-index-in-node=\"196\">relative newcomers</em>) ở thế kỷ XVII. Vì vậy, khẳng định Harvard và Yale là những trường <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"282\">đầu tiên</strong> (<em data-path-to-node=\"8,1,0\" data-index-in-node=\"292\">the first</em>) nhận tài trợ là sai sự thật (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"332\">FALSE</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">2. Merchants liked to donate to the same universities they attended themselves. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"10,0,0\" data-index-in-node=\"21\">Wealthy merchants</strong> gave young institutions money, land, libraries and rare items.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc các thương nhân giàu có (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"62\">wealthy merchants</em>) hiến tặng tiền bạc, đất đai, thư viện cho các trường đại học non trẻ. Tuy nhiên, bài viết <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"171\">hoàn toàn không đề cập</strong> đến việc họ có xu hướng quyên góp cho chính ngôi trường mà họ từng theo học (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"271\">the same universities they attended</em>) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">3. The first of the gifts to the University of Auckland came in 1884. — {TRUE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">“In <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"24\">1884</strong> Mr Justice Gillies made history when he gave $3,000 to the then very young University of Auckland, and so <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"135\">became its original philanthropist</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chữ \"original\" mang nghĩa là đầu tiên, nguyên bản. Việc ông Gillies tặng tiền vào năm 1884 và trở thành nhà hảo tâm đầu tiên (<em data-path-to-node=\"12,1,0\" data-index-in-node=\"138\">original philanthropist</em>) đồng nghĩa với việc món quà đầu tiên đến vào năm 1884. Đáp án là <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"228\">TRUE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">4. The University of Otago often received larger gifts than Gillies’ gift to Auckland. — {FALSE}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"20\">“Gillies’ gift was <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"39\">more generous even than those regularly given to New Zealand’s older University of Otago</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc viết rằng món quà của Gillies thậm chí còn \"hào phóng hơn\" (<em data-path-to-node=\"14,1,0\" data-index-in-node=\"80\">more generous</em>) những món quà thường xuyên được tặng cho Đại học Otago. Do đó, việc câu hỏi nói Đại học Otago thường nhận được những món quà \"lớn hơn\" (<em data-path-to-node=\"14,1,0\" data-index-in-node=\"231\">larger gifts</em>) món quà của Gillies là hoàn toàn ngược lại (<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"289\">FALSE</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">5. In the 1930s the government wanted to close Auckland’s engineering school. — {TRUE}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">“In that decade [1930s] a local engineer... launched a fund to save the engineering school in Auckland, <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"124\">which the state was determined to see discontinued</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"The state\" đóng vai trò paraphrase cho \"the government\" (chính phủ/nhà nước). Cụm từ \"determined to see discontinued\" (quyết tâm muốn thấy nó bị đình chỉ/dừng hoạt động) đồng nghĩa với việc muốn đóng cửa ngôi trường đó (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"233\">wanted to close</strong>). Đáp án là <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"261\">TRUE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">6. After raising $6,500, Crookes returned to academic life. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"18,0,0\" data-index-in-node=\"20\">“...and raised over $6,500 in three years.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói Samuel Crookes là một cựu giảng viên (<em data-path-to-node=\"18,1,0\" data-index-in-node=\"65\">former lecturer</em>) và ông đã gây quỹ thành công hơn 6.500 đô-la trong 3 năm. Tuy nhiên, bài viết <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"160\">không hề nhắc đến</strong> việc sau khi gây quỹ xong thì ông có quay trở lại con đường nghiên cứu/giảng dạy học thuật (<em data-path-to-node=\"18,1,0\" data-index-in-node=\"270\">returned to academic life</em>) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">7. In the 1950s the best lecturers chose to work in Britain or Australia rather than Auckland. — {TRUE}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"20,0,0\" data-index-in-node=\"20\">“In Auckland the problem largely resulted from the fact that academic salaries had slipped well behind those available in Britain and Australia, so <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"168\">the strongest candidates tended to be recruited to those countries</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"The strongest candidates\" tương ứng với những giảng viên giỏi nhất (<strong data-path-to-node=\"20,1,0\" data-index-in-node=\"81\">the best lecturers</strong>). Do mức lương ở Auckland thấp hơn nhiều so với Anh và Úc, những người giỏi nhất này có xu hướng được tuyển dụng/chọn làm việc ở các quốc gia đó (<em data-path-to-node=\"20,1,0\" data-index-in-node=\"246\">tended to be recruited to those countries</em>). Đáp án là <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"300\">TRUE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">8. A single philanthropist was responsible for the new Medical School. — {FALSE}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"22,0,0\" data-index-in-node=\"20\">“But when the new Medical School opened in 1968, it <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"72\">attracted significant gifts for academic positions and equipment from an unusually wide range of donors, including individuals, trusts, charitable foundations, societies and community groups</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trường Y mới mở nhận được sự tài trợ từ một mạng lưới các nhà tài trợ vô cùng rộng lớn và đa dạng (<em data-path-to-node=\"22,1,0\" data-index-in-node=\"111\">an unusually wide range of donors</em>) bao gồm nhiều cá nhân, các quỹ tín thác, quỹ từ thiện, các hội đoàn và nhóm cộng đồng. Vì vậy, câu hỏi khẳng định chỉ có một nhà hảo tâm duy nhất (<strong data-path-to-node=\"22,1,0\" data-index-in-node=\"293\">a single philanthropist</strong>) chịu trách nhiệm cho trường này là sai hoàn toàn (<strong data-path-to-node=\"22,1,0\" data-index-in-node=\"368\">FALSE</strong>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('eb8d3766-17ae-4b0f-a867-62d75cd5e125', '52f04971-e253-4ad5-ae74-3ea8118e5169', 'radio', 'Questions 31-35', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the information given in the text, choose <strong>NO </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Roy Grounds’s design failed to recognise the importance of functions and performances in museums"}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Mario Bellini’s new NGV rejects international museum design trends"}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Mario Bellini’s work on subsequent museum projects has been less successful than that on the NGV"}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The NGV monitors the number of first-time visitors to permanent collections"}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Too much change may have negative impacts on museums"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. Roy Grounds’s design failed to recognise the importance of functions and performances in museums.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a vast Great Hall, which represented an unprecedented emphasis on the ancillary roles of corporate functions and public performances…”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngược lại với câu hỏi, thiết kế của Roy Grounds đã rất chú trọng đến các chức năng phụ trợ và biểu diễn công cộng thông qua sảnh Great Hall.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">32. Mario Bellini’s new NGV rejects international museum design trends.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"8\">NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…his design reflects what the new, improved, twenty-first-century global museum feels it should be emphasizing to its visitors.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thiết kế của Bellini thực chất là đang “phản ánh” (reflects) các xu hướng bảo tàng toàn cầu thế kỷ 21 chứ không phải bác bỏ chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. Mario Bellini’s work on subsequent museum projects has been less successful than that on the NGV.</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ tập trung vào công việc của Bellini tại NGV, không có thông tin so sánh với các dự án sau đó của ông.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. The NGV monitors the number of first-time visitors to permanent collections.</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù bài đọc có nhắc đến “first-time visitors”, nhưng không có thông tin nào nói về việc bảo tàng có “monitor” (theo dõi/giám sát) con số này hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. Too much change may have negative impacts on museums.</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"8\">YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…and the effect of too much innovation in museums can be disastrous.”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong data-path-to-node=\"23,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định việc đổi mới quá mức có thể gây ra những hậu quả thảm khốc (disastrous), tương ứng với “negative impacts”.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('b64b0826-ba16-4dbd-bd72-d97fada35d1a', 'aa8132aa-4cfc-4f48-9552-a816e6b5e417', 'fillup', 'Questions 7-9', '<p>Complete the flow-chart below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p class="ql-align-center" style="text-align: center;"><strong>How ambergris is formed</strong></p>
<p class="ql-align-center" style="text-align: center;">Ambergris is formed in whales because of problems digesting the {beaks}<span class="fill-history-correct"> </span>of giant squid.</p>
<h3 class="ql-align-center" style="text-align: center;"><strong>↓</strong></h3>
<p class="ql-align-center" style="text-align: center;">Black liquid is produced and is {vomited up| vomited}from time to time</p>
<h3 class="ql-align-center" style="text-align: center;"><strong>↓</strong></h3>
<p class="ql-align-center" style="text-align: center;">The liquid {hardens}<strong> </strong>on contact with the air.</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">7. beaks</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Câu hỏi thường gặp:</strong> Cá voi nhà táng không thể tiêu hóa được bộ phận nào của mực khổng lồ?</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"3,1,0\" data-index-in-node=\"20\">“It is from the problems the whales have in digesting the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"78\">beaks</strong> of such creatures that ambergris has its origins.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cá voi ăn mực khổng lồ, nhưng mỏ mực (<strong data-path-to-node=\"3,2,0\" data-index-in-node=\"50\">beaks</strong>) rất cứng và sắc nhọn, khiến hệ tiêu hóa của cá voi không thể phân hủy được.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">8. (lower) intestine</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Câu hỏi thường gặp:</strong> Những bộ phận sắc nhọn này gây kích ứng cho bộ phận nào của cá voi?</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"5,1,0\" data-index-in-node=\"20\">“The beak is sharp and irritates the whale’s <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"65\">lower intestine</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những chiếc mỏ mực này không trôi đi mà gây trầy xước, kích ứng bên trong <strong data-path-to-node=\"5,2,0\" data-index-in-node=\"86\">ruột dưới</strong> (lower intestine) của cá voi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">9. vomited (up)</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Câu hỏi thường gặp:</strong> Cá voi phản ứng lại sự kích ứng này bằng cách làm gì với hỗn hợp đó?</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"7,1,0\" data-index-in-node=\"20\">“…from time to time large quantities of the liquid are <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"77\">vomited up</strong> by the whale.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Để bảo vệ ruột, cá voi tiết ra một chất lỏng đen bọc lấy mỏ mực, sau đó định kỳ <strong data-path-to-node=\"7,2,0\" data-index-in-node=\"92\">nôn ra</strong> (vomit/vomited up) hỗn hợp này ra biển.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('a33c30a2-a1af-40d8-89ba-97fdc56e4832', '5b2d3314-b656-47a8-825f-7ee54c4c608b', 'radio', 'Questions 1–6', NULL, '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Early Maori healers learned their skills through studying written texts."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The first Europeans in New Zealand were surprised by how long the Maori lived."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": " Diseases of the gods were believed to be more serious than physical diseases."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The leaves of the pepper tree were used to treat toothache."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Western religion was one reason why traditional Maori medicine became less popular."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Modern day Maori healers often reach the same conclusion about the type of treatment which is best."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">1. Early Maori healers learned their skills through studying written texts.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng cuối và đoạn 8, dòng 2: “…schools of higher learning which had trained healers… training is highly variable, usually <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"145\">informal</strong>… knowledge and ability that has been <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"193\">passed down from their ancestors</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Hệ thống giáo dục của người Maori cổ đại là truyền miệng và thông qua các “ngôi trường học thuật cao” (houses of higher learning), không phải qua văn bản viết (<em data-path-to-node=\"7,2,0\" data-index-in-node=\"172\">written texts</em>). Thực tế, văn hóa Maori truyền thống là văn hóa truyền miệng trước khi người Châu Âu đến.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">2. The first Europeans in New Zealand were surprised by how long the Maori lived.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 1, dòng 3-5: “When Europeans first visited New Zealand, the average age of death for Maori adults was around 30. However… the people were fit and healthy…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nêu tuổi thọ trung bình của người Maori lúc đó là khoảng 30 tuổi và họ rất khỏe mạnh. Tuy nhiên, bài <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"124\">không đề cập</strong> đến việc người Châu Âu có “ngạc nhiên” (<em data-path-to-node=\"9,2,0\" data-index-in-node=\"177\">surprised</em>) về tuổi thọ này hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">3. Diseases of the gods were believed to be more serious than physical diseases.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3: “In Maori culture, illnesses were divided into diseases of the gods (mate atua) and physical diseases (mate tangata).”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ phân loại bệnh tật thành hai nhóm dựa trên nguồn gốc (tâm linh hay thể chất) chứ <strong data-path-to-node=\"11,2,0\" data-index-in-node=\"105\">không so sánh</strong> xem loại nào “nghiêm trọng hơn” (<em data-path-to-node=\"11,2,0\" data-index-in-node=\"152\">more serious</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">4. The leaves of the pepper tree were used to treat toothache.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, dòng 5-6: “People who had toothache were instructed to <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"74\">chew the leaves of this same tree</strong> [pepper tree], and this was found to be of considerable benefit.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông tin trong bài khớp hoàn toàn với câu hỏi: lá cây tiêu được dùng để trị đau răng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">5. Western religion was one reason why traditional Maori medicine became less popular.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 6-8: “…many Maori accepted this explanation [from Western missionaries] and <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"102\">turned to Christianity</strong>… the tradition of the Maori healer declined.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà truyền giáo phương Tây cho rằng bệnh tật lây lan là do người Maori không tin vào Kitô giáo. Khi các thầy thuốc bản địa không chữa được bệnh mới, người dân chuyển sang tôn giáo mới, dẫn đến sự suy giảm của y học truyền thống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">6. Modern day Maori healers often reach the same conclusion about the type of treatment which is best.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 8, dòng 6-7: “As a result, their modern day work has <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"69\">no standard system of diagnosis or widespread agreement about treatments</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “no widespread agreement” (không có sự thống nhất rộng rãi) trái ngược hoàn toàn với “reach the same conclusion” (đi đến cùng một kết luận). Các thầy thuốc hiện đại thử nghiệm và kết hợp nhiều phương pháp khác nhau nên không có tiêu chuẩn chung.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('0622b181-30e6-4224-88ef-a3b70918fcae', '2bf85cb9-d6e3-4f91-b1d5-eda8252081cf', 'checkbox', 'Questions 23 and 24', '', '<p>Choose <strong>TWO</strong> letters, A-E.</p>
<p>Which are the <strong>TWO</strong> requirements to do the PSW programme?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "high school completion"}, {"correct": false, "option_text": " a maths course"}, {"correct": false, "option_text": "a language qualification"}, {"correct": false, "option_text": "a clear driving record"}, {"correct": true, "option_text": "First Aid training"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('048da684-f096-4a09-8d0b-269aae616dfb', '5b2d3314-b656-47a8-825f-7ee54c4c608b', 'fillup', 'Questions 7–13', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write<strong> ONE WORD ONLY</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><span style="font-size: 12pt;"><strong>A short history of Maori healing</strong></span></p>
<p><strong>Pre-European arrival</strong></p>
<p>– Maori were using plant based remedies, as well as treatment including massage.</p>
<p>– Diseases sent from the gods were thought to be caused by disobeying a spiritual {rule}.</p>
<p>– Sickness could be attributed to eating food from a sacred {river} or burning sacred wood</p>
<p><strong>After European arrival</strong></p>
<p><strong>1800s</strong></p>
<p>– The inability of Maori healers to cure new diseases meant the Maori people lost <span class="fill-history-correct">{confidence}</span> in them.</p>
<p>– Eventually the {schools} for Maori healing began shutting down.</p>
<p><strong>1970s</strong></p>
<p>– Published {statistics} showed that Maori were not as healthy as Europeans.</p>
<p><strong>2000s</strong></p>
<p>– Maori healers can be seen working with Western doctors in {clinics} in cities.</p>
<p>– Many patients appreciate the fact that the Maoris {language} in used by healers.</p>
</div>
</div>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">7. rule</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3, dòng 2-3: “Diseases sent by the gods were often attributed to attacks by evil spirits, because the person had broken a religious <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"148\">rule</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bệnh do thần linh gửi đến được cho là hậu quả của việc vi phạm một quy tắc (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"88\">rule</strong>) tôn giáo hoặc tâm linh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">8. river</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3, dòng 4-5: “…if someone took food from a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"61\">river</strong> where someone had died… it was believed that the gods could punish them…”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc lấy thức ăn từ một con sông (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"46\">river</strong>) linh thiêng (nơi có người chết) được coi là hành động thiếu tôn trọng dẫn đến bệnh tật.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">9. confidence</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 3-4: “…this failure still strongly affected Maori <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"76\">confidence</strong> in their healers.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi các thầy thuốc bản địa không thể chữa được những căn bệnh mới từ Châu Âu, người Maori đã mất niềm tin (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"119\">confidence</strong>) vào họ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">10. schools</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 8-9: “Over time the <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"44\">schools</strong> of higher learning which had trained healers started to close…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Theo thời gian, những ngôi trường (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"47\">schools</strong>) đào tạo thầy thuốc bắt đầu bị đóng cửa, dẫn đến sự suy thoái của y học truyền thống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">11. statistics</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, dòng 3-4: “…<strong data-path-to-node=\"15,0,0\" data-index-in-node=\"33\">statistics</strong> from the 1970s came out revealing that Maori health continued to be poorer than that of other New Zealanders.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những số liệu thống kê (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"36\">statistics</strong>) được công bố vào những năm 1970 cho thấy tình trạng sức khỏe của người Maori vẫn kém hơn so với những người New Zealand khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">12. clinics</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 8, dòng 4-5: “Many modern healers work in urban <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"64\">clinics</strong>, some alongside mainstream health professionals.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hiện nay, nhiều thầy thuốc Maori làm việc tại các phòng khám (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"74\">clinics</strong>) ở thành phố, đôi khi kết hợp cùng với các bác sĩ Tây y.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">13. language</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 8, dòng cuối: “The Maori <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"41\">language</strong> is also seen as important by many of those receiving treatment.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những bệnh nhân hiện nay đánh giá cao việc ngôn ngữ (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"65\">language</strong>) Maori được các thầy thuốc sử dụng trong quá trình điều trị.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('1a15946f-e37c-402a-849f-2e3baefa6d8d', '5659ac7c-e9b4-4d3f-a0f6-3a9967b1cefd', 'checkbox', 'Questions 25 and 26', '', '<p>Choose <strong>TWO</strong> letters, <strong>A–E</strong>.</p>
<p>Write the correct letters in boxes 25 and 26 on your answer sheet.</p>
<p>Which <strong>TWO</strong> of the following statements does the writer make about garment assembly? </p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A The majority of sewing is done by computer-operated machines."}, {"correct": false, "option_text": "B Highly skilled workers are the most important requirement."}, {"correct": true, "option_text": "C Most businesses use other companies to manufacture their products."}, {"correct": true, "option_text": "D Fasteners and labels are attached after the clothes have been made up."}, {"correct": false, "option_text": "E Manufacturers usually produce one range of women’s clothing annually"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">25. C. Most businesses use other companies to manufacture their products.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p id=\"p-rc_08cca3af44f65315-23\" data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“<span class=\"citation-157\">Some companies use their own production facilities for some or all of the manufacturing process, </span><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"118\"><span class=\"citation-157 citation-end-157\">but the majority rely on separately owned manufacturing firms or contractors to produce garments to their specifications<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span></strong>.”</em></p>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định \"phần lớn các công ty\" (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"55\">the majority</em>) dựa vào các hãng sản xuất độc lập hoặc bên nhà thầu (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"122\">separately owned manufacturing firms or contractors</em>) để sản xuất quần áo theo yêu cầu. Ý này trùng khớp hoàn toàn với câu C: \"Hầu hết các doanh nghiệp (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"274\">Most businesses</em>) sử dụng các công ty khác (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"317\">other companies</em>) để sản xuất sản phẩm của họ\".</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">26. D. Fasteners and labels are attached after the clothes have been made up.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">Assembled items then go through various processes collectively known as ‘finishing’. These include the addition of decorative elements, fasteners, brand-name labels</strong> and other labels...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Quá trình \"made up\" (ráp/khâu may xong xuôi quần áo) tương ứng với từ \"assembled items\" (các món đồ đã được lắp ráp/may xong). Sau công đoạn này, chúng mới trải qua các bước hoàn thiện (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"198\">finishing</em>) bao gồm việc đính thêm cúc/khóa kéo (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"246\">fasteners</strong>) và nhãn mác (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"270\">labels</strong>). Do đó câu D là một khẳng định hoàn toàn chính xác.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('3b7535f7-9d20-471b-8fca-94134918d8e0', '52f04971-e253-4ad5-ae74-3ea8118e5169', 'matching', 'Questions 36-40', NULL, '<p>Complete each sentence with the correct ending, <strong>A–G</strong>, below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A. the museum programme will lose its individuality."}, {"optionText": "B. the museum will lose credibility."}, {"optionText": "C. the art loses its importance."}, {"optionText": "D. it will have to balance opposing demands."}, {"optionText": "E. this will encourage museum visitors in the future."}, {"optionText": "F. it will have the capability of increasing revenue."}, {"optionText": "G. the architect’s reputation might suffer."}], "matchingItems": [{"questionPart": "If a large space is available in the museum,", "correctAnswer": "F. it will have the capability of increasing revenue.", "sectionContent": null}, {"questionPart": "If children are allowed to move freely in parts of the gallery,", "correctAnswer": "E. this will encourage museum visitors in the future.", "sectionContent": null}, {"questionPart": "If too much emphasis is placed on the museum building itself,", "correctAnswer": "C. the art loses its importance.", "sectionContent": null}, {"questionPart": "If there is an over-reliance on ‘blockbuster’ exhibitions,", "correctAnswer": "A. the museum programme will lose its individuality.", "sectionContent": null}, {"questionPart": "If the NGV wants to continue to be successful,", "correctAnswer": "D. it will have to balance opposing demands.", "sectionContent": null}]}', 'null', '[{"content": "<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">36. If a large space is available in the museum, (F)</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"8\">F (It will have the capability of increasing revenue.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…emphasis on corporate sponsorship and the need to generate additional funds via room hire [in the Great Hall].”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong data-path-to-node=\"27,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Không gian lớn (như Great Hall) cho phép bảo tàng cho thuê phòng để tổ chức sự kiện, từ đó tăng doanh thu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">37. If children are allowed to move freely in parts of the gallery, (E)</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"29,0,0\" data-index-in-node=\"8\">E (This will encourage museum visitors in the future.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “As an unintimidating introduction to the lifelong rigors of visiting art museums, its impact on attendance cannot be overestimated.”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong data-path-to-node=\"29,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc trẻ em được tự do khám phá giúp chúng không cảm thấy sợ bảo tàng, tạo thói quen đi bảo tàng suốt đời (lifelong rigors).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">38. If too much emphasis is placed on the museum building itself, (C)</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"31,0,0\" data-index-in-node=\"8\">C (The art loses its importance.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…construction of new buildings that supplant the artworks inside them, becoming the major attractions themselves.”</p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong data-path-to-node=\"31,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi tòa nhà trở thành điểm thu hút chính, nó sẽ “thay thế” (supplant) và làm giảm đi tầm quan trọng của các tác phẩm nghệ thuật bên trong.</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">39. If there is an over-reliance on blockbuster exhibitions, (A)</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"33,0,0\" data-index-in-node=\"8\">A (The museum programme will lose its individuality.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…cannot help but introduce a certain ‘off-the-rack’ feeling to the institution’s exhibition program.”</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong data-path-to-node=\"33,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các triển lãm thuê mướn (rental blockbusters) làm chương trình của bảo tàng trở nên “may sẵn” (off-the-rack), đánh mất đi bản sắc riêng (individuality).</p>\n</li>\n</ul>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">40. If the NGV wants to continue to be successful, (D)</strong></p>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong data-path-to-node=\"35,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"35,0,0\" data-index-in-node=\"8\">D (It will have to balance opposing demands.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong data-path-to-node=\"35,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…needs to be able to juggle numerous, often conflicting priorities…”</p>\n</li>\n<li>\n<p data-path-to-node=\"35,2,0\"><strong data-path-to-node=\"35,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Để thành công, bảo tàng phải “tung hứng” (juggle) hay chính là cân bằng giữa các ưu tiên trái ngược nhau (học thuật vs tiếp cận đại chúng).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('f1416534-1926-41f4-a501-88f1be31187e', 'd00b1528-ca79-4421-bf76-08eed0c53c4c', 'fillup', 'Questions 31–40', '<p data-start="91" data-end="155">Complete the notes below.<br data-start="116" data-end="119">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><strong><span style="font-size: 12pt;">Inventing a Universal Language</span></strong></p>
<p data-start="193" data-end="211"><strong>Introduction</strong></p>
<p>• Most languages were not invented – they evolved.<br data-start="262" data-end="265">• Early invented languages were used for religious purposes or for {trade}.<br data-start="339" data-end="342">• We know of about 900 invented languages, but many have been lost.</p>
<p data-start="413" data-end="434"><strong>William Spencer</strong></p>
<p>• He wrote books about {science} so he needed an accurate language.<br data-start="499" data-end="502">• At first he tried to base his language on {numbers}.<br data-start="553" data-end="556">• Later he classified words in the same way that was used for plants.</p>
<p data-start="629" data-end="650"><strong>Ludwig Zamenhof</strong></p>
<p>• He mixed together existing European languages.<br data-start="699" data-end="702">• He wrote {songs} to help develop his new language.<br data-start="753" data-end="756">• He wanted simplicity, e.g. one prefix to make words {negative}.<br data-start="817" data-end="820">• He sent {letter} to his friends to publicise his language.<br data-start="878" data-end="881">• He created the most successful invented language.</p>
<p data-start="936" data-end="954"><strong>Bruce Goldie</strong></p>
<p>• Each word of his language was based on a {picture}.<br data-start="1005" data-end="1008">• His language did not get academic recognition at first.<br data-start="1065" data-end="1068">• Children in a Canadian {hospital} learned to read using his language.</p>
<p data-start="1139" data-end="1192"><strong>Conclusion: why have invented languages failed?</strong></p>
<p>• They cannot express {emotions}.<br data-start="1222" data-end="1225">• English became the global language.<br data-start="1262" data-end="1265">• They are now invented by {writers}, just for entertainment.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: INVENTING A UNIVERSAL LANGUAGE</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Good morning. Welcome back to the series of linguistics lectures. Today I will be talking about the idea of inventing a universal language.</p>\n<p data-path-to-node=\"4\">What does that mean? Well, most human languages were never invented; instead they evolved over time, and the result is, you know, they’re irregular and difficult to learn. So for centuries, people have dreamed of inventing a perfect universal language.</p>\n<p data-path-to-node=\"5\">The early invented languages that did exist were either created by priests to be used for religious purposes or developed to help establish <strong data-path-to-node=\"5\" data-index-in-node=\"140\">(31) trade</strong> between different nations. Scholars have found evidence that around 900 languages have been invented over the centuries in various parts of the world, but the linguist Erika Okrent believes that the exact figure is unclear because she suspects many of these languages are now lost—no record of them survives.</p>\n<hr data-path-to-node=\"6\">\n<h3 data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">WILLIAM SPENCER</strong></h3>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Lecturer:</strong> The first really serious attempt to invent a language was made by William Spencer in the 17th century. Like so many others, he was frustrated by the irregularities in all existing languages. Accuracy was particularly important for Spencer because he wrote books—his subject was <strong data-path-to-node=\"8\" data-index-in-node=\"288\">(32) science</strong>.</p>\n<p data-path-to-node=\"9\">As a result, he wanted to create a language where words had only one meaning, so everyone would understand precisely what they meant. At first he thought the only way to do this was, instead of using the usual letters of the alphabet—A, B, C and so on—he tried to substitute <strong data-path-to-node=\"9\" data-index-in-node=\"275\">(33) numbers</strong> for them.</p>\n<p data-path-to-node=\"10\">However, this attempt failed, mostly because he couldn’t describe complex ideas in this way. So Spencer went back to using the alphabet, but he grouped words together in a different way. When his dictionary was published in 1668, the words weren’t classified in alphabetical order. What he’d done was he’d used the same system with which plants were divided up into groups based on their type.</p>\n<hr data-path-to-node=\"11\">\n<h3 data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">LUDWIG ZAMENHOF</strong></h3>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Lecturer:</strong> Another important attempt to invent a universal language was made by Ludwig Zamenhof, who was born in 1859. Zamenhof’s language reflects his own background; he grew up speaking Polish, English, French, German and Russian. So rather than create a completely new language, he mixed together five or six existing European languages.</p>\n<p data-path-to-node=\"14\">Then Zamenhof used an interesting technique to help him develop his new language: he used it to write quite a few different <strong data-path-to-node=\"14\" data-index-in-node=\"124\">(34) songs</strong>, and this made his work more enjoyable. He also thought that most European languages were too complicated, which meant that it was very difficult for people to learn them.</p>\n<p data-path-to-node=\"15\">Zamenhof wanted to create a more simple language, so for example, he had a single prefix that was used before adjectives or verbs to make them <strong data-path-to-node=\"15\" data-index-in-node=\"143\">(35) negative</strong>, which is obviously much easier than English.</p>\n<p data-path-to-node=\"16\">Then finally he published a book introducing his language to the world in 1887. Unfortunately, like other invented languages, no one was very interested at first. So again Zamenhof used an interesting approach in order to publicise the completed language: he made a list of everyone he knew and posted a <strong data-path-to-node=\"16\" data-index-in-node=\"304\">(36) letter</strong> to all of them using the new language. Many people were surprised how easily they could understand it, and the language began to attract attention. Zamenhof’s language was never used all around the world as he had hoped, but still, it’s probably the most successful of all the invented languages.</p>\n<hr data-path-to-node=\"17\">\n<h3 data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">BRUCE GOLDIE</strong></h3>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Lecturer:</strong> In the 20th century, an Australian named Bruce Goldie tried something completely different. Goldie thought that a universal language would be easier to use if the starting point for each word was a <strong data-path-to-node=\"19\" data-index-in-node=\"208\">(37) picture</strong>.</p>\n<p data-path-to-node=\"20\">Goldie spent more than 20 years designing his new language and eventually published a book giving all the details in 1949. He also went on a lecture tour to promote it, but although the general public were often quite interested, much to Goldie’s disappointment, his language was ignored by all of the major universities despite frequent attempts to make them interested.</p>\n<p data-path-to-node=\"21\">It wasn’t until the 1970s that his language had some success. This was in Canada in fact, where it was used to teach a group of disabled children in a <strong data-path-to-node=\"21\" data-index-in-node=\"151\">(38) hospital</strong> to read, and as a result, Goldie got some recognition for his work.</p>\n<hr data-path-to-node=\"22\">\n<h3 data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">CONCLUSION</strong></h3>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Lecturer:</strong> So what can we say in conclusion? Well, the truth is all attempts to create a universal language have failed, and there are a number of reasons for this.</p>\n<p data-path-to-node=\"25\">Firstly, most universal languages have been seen as rather technical and plain. They’re not good at conveying <strong data-path-to-node=\"25\" data-index-in-node=\"110\">(39) emotions</strong>, so they’ve never been very popular. Another reason is the spread of English as a global language in the 20th century, particularly resulting from the film industry in Hollywood.</p>\n<p data-path-to-node=\"26\">Then lastly, the type of people who invented the languages began to change. In the past it had been academics, but more recently, the languages have often been created by <strong data-path-to-node=\"26\" data-index-in-node=\"171\">(40) writers</strong>, usually for entertainment, so they haven’t been taken seriously.</p>"}]', 0);
INSERT INTO public.questions VALUES ('27eb60ce-fb8c-4082-8d74-c290a7c8df7f', '72a08353-7870-4d93-84b0-3241ff5d3d46', 'fillup', 'Questions 11–17', '<p data-start="78" data-end="157">Write <strong data-start="112" data-end="140">ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p style="text-align: left;" data-start="159" data-end="179"><span style="font-size: 12pt;"><strong data-start="163" data-end="179">Barton House</strong></span></p>
<p data-start="181" data-end="424">Before Barton bought this house, it was a {farm}.</p>
<p data-start="181" data-end="424">The Chinese wallpaper was painted in the {18th} century.</p>
<p data-start="181" data-end="424">Barton died in the {bird} room.</p>
<p data-start="181" data-end="424">The dining room has many antiques such as the {chairs} sold by Japanese.</p>
<p data-start="426" data-end="449"><strong>Backyard Garden</strong></p>
<p data-start="451" data-end="600">{rare} plants that have been there for years.</p>
<p data-start="451" data-end="600">{flamingos|flamingoes} were introduced by the government.</p>
<p data-start="451" data-end="600">The most popular animal is the {swans}.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 2</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Carly (Tour Guide):</strong> <span class=\"citation-324 citation-325 citation-end-325\">Good afternoon, welcome to Barton Museum. I am Carly and I am your tour guide. I would be taking you through all the places of interest in this museum.</span></p>\n<p data-path-to-node=\"4\"><span class=\"citation-322 citation-323 citation-end-323\">Before we actually set out to go, the first building we stop</span><span class=\"citation-322 citation-end-322\"> at is the Barton House which was built by the man himself, Ba</span>rton. When he first came to this area, it was largely uninhabited and as a matter of fact, this place was a vast expanse of land where an abandoned <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"4\" data-index-in-node=\"270\">(11) farm</strong></span> was situated.</p>\n<p data-path-to-node=\"5\">After he bought it, he began building and in about three years, the basic structure was complete, although he never really stopped building. As a man who loved the arts, Barton spent a good fortune on them. He had several paintings from all over the world and his gallery is still considered one of the best in town.</p>\n<p data-path-to-node=\"6\">One of the most notable of his collection is the Chinese Wallpaper, which was painted in the <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"6\" data-index-in-node=\"93\">(12) 18th</strong></span> century. Rumor has it that he paid hundreds of thousands of dollars for the piece of art.</p>\n<p data-path-to-node=\"7\">Barton kept adding some features to his house every year. He did this until the night he died. He was building a new <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"7\" data-index-in-node=\"117\">(13) bird </strong></span>room in which he collapsed and never came to himself.</p>\n<p data-path-to-node=\"8\">His dining room is also beautifully adorned with antiquity. From the tables to the stools to the mats—the <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"8\" data-index-in-node=\"106\">(14) <span class=\"citation-321\">chairs</span></strong></span><span class=\"citation-321 citation-end-321\"> were bought from some Japanese merchants in the area.</span></p>\n<p data-path-to-node=\"9\"><span class=\"citation-320 citation-end-320\">Then looking at the location of his house, which sits some feet higher than surrounding lands, it is possible to see areas of just green lush vegetation that run for miles.</span> <span class=\"citation-319 citation-end-319\">At the backyard, there is a garden which he started himself</span>. He used to care for the plants there personally and made sure they never lacked water.</p>\n<p data-path-to-node=\"10\">He detested fertilizers as he believed that it would spoil the cycle of growth of the plants. In the garden he had some trees—they are not ordinary trees but some <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"10\" data-index-in-node=\"163\">(15) rare</strong></span> ones, and they have been alive for decades now.</p>\n<p data-path-to-node=\"11\">Under one of those trees was his favorite spot and history tells us that he used to sing and pray under the tree. Recently, the government brought in some <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"11\" data-index-in-node=\"155\">(16) flamingos</strong></span> here as the environment supports their growth and development well.</p>\n<p data-path-to-node=\"12\">They are believed to make the scenery livelier and more beautiful. Although there are many exotic animals in the garden, <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"12\" data-index-in-node=\"121\">(17) swans</strong></span> are still the most popular animal here. They seem to be everywhere, and it was said that Barton thought that they were a gift from the heaven. It was forbidden to kill or hurt any of these animals in his time</p>\n<hr>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Carly:</strong> Now let’s take a look at other interesting places this site has to offer.</p>\n<p data-path-to-node=\"16\">Away from the backyard, there is a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"16\" data-index-in-node=\"35\">(18) gallery (C)</strong> just at the right side of the road, a few feet from the entrance, and there is usually a history exhibition every week.</span></p>\n<p data-path-to-node=\"17\">Halfway down the path to the east of the toilet, we have the<span style=\"background-color: #f3db7b;\"> <span style=\"text-decoration: underline;\"><strong data-path-to-node=\"17\" data-index-in-node=\"61\">(19) woodland (F)</strong> and the area is just beautiful. Barton decided to have it just because he loved the view.</span></span></p>\n<p data-path-to-node=\"18\"><span style=\"text-decoration: underline; background-color: #f3db7b;\">If you keep walking down the path in front of you to the west of the site, you will see a large <strong data-path-to-node=\"18\" data-index-in-node=\"96\">(20) gift shop (E)</strong> beside the toilet.</span> It has a large collection of handicrafts. These handicrafts are not actually made by Barton himself but are imitations of his artistic works.</p>\n<p data-path-to-node=\"19\">As you have heard enough about this man, we would now proceed to see these things for ourselves and I’m very sure that you will enjoy the tour.</p>"}]', 0);
INSERT INTO public.questions VALUES ('865e8fb2-4eba-46fc-a07b-62d881a41588', '4ab334fb-2f99-4645-8bcc-f7efaf9fdab3', 'matching', 'Questions 36–40', '', '<p>Complete the summary using the list of words and phrases, <strong>A-I</strong>, below.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>New technology could help retailers sell more</strong></p>\n<p>Research is providing insights into what makes people purchase particular products. Most shoppers believe that their choices are the result of {G rational decisions} . Research involving fMRI scanners, however, has revealed that certain {C unconscious factors} influence shoppers’ decisions to a significant extent. In the research, a comparison was made between participants’ stated opinions of a product and data from {A brain scans} , which often indicated a radically different {H emotional reaction} .As most new products are {E failures} , this data could be extremely valuable for marketing departments.</p>", "answerOptions": [{"optionText": "A brain scans"}, {"optionText": "B purpose"}, {"optionText": "C unconscious factors"}, {"optionText": "D questionnaire"}, {"optionText": "E failures"}, {"optionText": "F procedure"}, {"optionText": "G rational decisions"}, {"optionText": "H emotional reaction"}, {"optionText": "I achievements"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">36. Most shoppers believe that their choices are the result of {G rational decisions}.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “People tell market researchers that they make decisions about what to buy based on <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"95\">logic and common sense</strong>…” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Logic và lẽ thường tương ứng với các quyết định có tính toán/hợp lý (rational decisions).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">37. Research involving fMRI scanners, however, has revealed that certain {C unconscious factors} influence shoppers’ decisions to a significant extent.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…there are clearly other factors… such as certain feelings and memories which individuals are <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"110\">not fully aware of</strong>.” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những cảm xúc và ký ức mà chúng ta không nhận thức đầy đủ chính là các yếu tố vô thức (unconscious factors).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">38. …a comparison was made between participants’ stated opinions of a product and data from {A brain scans}…</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…while <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"21\">scanners reveal their brain activity</strong> as they respond.” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dữ liệu thu được từ máy quét fMRI chính là kết quả quét não (brain scans).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">39. …which often indicated a radically different {H emotional reaction}.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Often, <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"19\">major contradictions</strong> are apparent between what they say and what they are thinking.” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự mâu thuẫn giữa lời nói (logic giả tạo) và suy nghĩ thực tế thường liên quan đến phản ứng cảm xúc thật của họ đối với sản phẩm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">40. As most new products are {E failures}, this data could be extremely valuable for marketing departments.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"24,0,0\" data-index-in-node=\"12\">Eight out of ten new consumer products</strong> launched on the market <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"74\">do not succeed</strong>…” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tỷ lệ 8/10 sản phẩm không thành công đồng nghĩa với việc hầu hết là sự thất bại (failures).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('a38ece1c-d6a6-4eb1-96de-1a28623e8e46', 'bd7e4e44-1351-4772-9ce8-f2b6d73ef0cc', 'matching', 'Questions 14–20', NULL, '<p>The text has seven sections. Choose the correct heading for each section and move it into the gap.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "Packaging that allows consumers to use more of the product"}, {"optionText": "The many reasons for changes in packaging"}, {"optionText": "Packaging that includes utensils like spoons and forks"}, {"optionText": "Packaging that can be consumed with its contents"}, {"optionText": "Packaging that doesn’t take up a lot of space"}, {"optionText": "The history of food packaging"}, {"optionText": "Packaging that indicates when food is beginning to go rotten"}, {"optionText": "Packaging that can be reused"}, {"optionText": "Using packaging to communicate ideas and attract customers"}, {"optionText": "Packaging that vanishes or decomposes quickly"}], "matchingItems": null}', 'null', '[{"content": "<p><strong class=\"\" data-path-to-node=\"1\" data-index-in-node=\"0\">14. Section 1: Using packaging to communicate ideas and attract customers</strong></p>\n<ul data-path-to-node=\"2\">\n<li><strong class=\"\" data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 1.</span></li>\n<li><strong class=\"\" data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “Food companies spend a lot of time thinking about packaging as a way to </span><strong class=\"\" data-path-to-node=\"2,1,0\" data-index-in-node=\"84\">represent their brand</strong><span class=\"\">…</span><span class=\"\"> a food container can </span><strong class=\"\" data-path-to-node=\"2,1,0\" data-index-in-node=\"130\">suggest playfulness, environmental consciousness, or high technology</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này nói về việc sử dụng bao bì để truyền tải thông điệp về thương hiệu (ý tưởng) và tạo ấn tượng ban đầu để thu hút khách hàng.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">15. Section 2: The many reasons for changes in packaging</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 2.</span></li>\n<li><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “Consumers are becoming increasingly </span><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"48\">obsessed with sleek technology, reducing food waste, and minimizing health risks</strong><span class=\"\">…</span><span class=\"\"> In response,</span><span class=\"\"> food packaging is undergoing some interesting developments.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này liệt kê các nhu cầu và mối quan tâm mới của người tiêu dùng (công nghệ,</span><span class=\"\"> lãng phí,</span><span class=\"\"> sức khỏe),</span><span class=\"\"> vốn là những lý do thúc đẩy sự thay đổi trong ngành bao bì.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">16. Section 3: Packaging that can be consumed with its contents</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 3.</span></li>\n<li><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “</span><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"12\">Edible packaging</strong><span class=\"\"> has been proposed…</span><span class=\"\"> KFC…</span><span class=\"\"> edible coffee-cup.</span><span class=\"\"> Made from a </span><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"88\">hard cookie</strong><span class=\"\">…</span><span class=\"\"> Stonyfield Organic…</span><span class=\"\"> edible food wrappers…</span> <strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"149\">skin has no flavor and can be rinsed and eaten</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Toàn bộ đoạn này tập trung vào các loại bao bì có thể ăn được (edible) cùng với thực phẩm bên trong như bánh quy,</span><span class=\"\"> gelatin hay vỏ làm từ tinh bột khoai tây.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">17. Section 4: Packaging that allows consumers to use more of the product</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 4.</span></li>\n<li><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">nonstick packaging,</span><span class=\"\"> which can </span><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"45\">eliminate the 3 to 15 percent of sauces left inside</strong><span class=\"\"> traditional bottles…</span> <strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"120\">Liquiglide</strong><span class=\"\">…</span><span class=\"\"> allows viscous matter to </span><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"159\">slide off easily</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này giới thiệu công nghệ chống dính giúp người dùng lấy sạch phần nước sốt còn sót lại trong chai,</span><span class=\"\"> tức là sử dụng được nhiều sản phẩm hơn so với bao bì cũ.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">18. Section 5: Packaging that indicates when food is beginning to go rotten</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 5.</span></li>\n<li><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">detect and later prevent food from </span><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"50\">spoiling</strong><span class=\"\">…</span><span class=\"\"> tiny embedded </span><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"76\">sensors</strong><span class=\"\"> to first detect…</span><span class=\"\"> nanotechnology…</span><span class=\"\"> dedicated to making electronic sensors.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này nói về bao bì thông minh có cảm biến giúp nhận biết khi thực phẩm bắt đầu hư hỏng (rotten/spoiling) thay vì chỉ dựa vào hạn sử dụng ghi trên nhãn.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">19. Section 6: Packaging that vanishes or decomposes quickly</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong class=\"\" data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 6.</span></li>\n<li><strong class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “Another emerging technology is </span><strong class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"43\">packaging that disappears</strong><span class=\"\">…</span><span class=\"\"> water-soluble bags…</span> <strong class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"94\">dissolves</strong><span class=\"\">…</span><span class=\"\"> seaweed that ‘will </span><strong class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"126\">wither at the same rate as its content</strong><span class=\"\">’.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tiêu đề này khớp hoàn toàn với nội dung về các loại túi hòa tan hoặc bao bì từ rong biển tự héo và biến mất khi không còn sử dụng.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"0\">20. Section 7: Packaging that doesn’t take up a lot of space</strong></p>\n<ul data-path-to-node=\"14\">\n<li><strong class=\"\" data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 7.</span></li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"12\">Super-compressed packaging</strong> serves the increasing number of city dwellers who generally have <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"104\">tiny kitchens and no storage room</strong>.”</li>\n<li><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn cuối nói về các loại bao bì siêu nén, chiếm ít diện tích, phù hợp với người sống ở đô thị có không gian nhỏ.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('e2b10a86-4c4a-4a0a-b351-61c36cd10037', '7689bfb6-fc81-46b5-8145-38ec0d865c50', 'radio', 'Questions 21-25', '', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Choose the correct letter, A,B or C</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><span style="font-size: 12pt;"><strong>Product development presentation: mosquito net</strong></span></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A. an Aadministrator"}, {"option_text": "B. a doctor"}, {"option_text": "C. a friend"}], "question": "Edward heard about a type of mosquito net from"}, {"correct": 2, "options": [{"option_text": "A. China"}, {"option_text": "B. Japan"}, {"option_text": "C. Egypt"}], "question": "Edward believes that mosquito nets were first used in"}, {"correct": 1, "options": [{"option_text": "A. was first developed by a soldier"}, {"option_text": "B. made them potentially dangerous to users"}, {"option_text": "C. was made possible by modern textiles"}], "question": "Chemical treatment of mosquito nets in the mid-twentieth century"}, {"correct": 2, "options": [{"option_text": "A. are likely to find they have an unpleasant smell"}, {"option_text": "B. should avoid using them every night"}, {"option_text": "C. may have difficulty obtaining the necessary chemical"}], "question": "The owners of present-day nets"}, {"correct": 0, "options": [{"option_text": "A. remain effective for longer"}, {"option_text": "B. use a greater number of chemicals"}, {"option_text": "C. give protection against more types of insects"}], "question": "According to Edward, Olyset nets are better than other nets because they"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"0\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: PRODUCT DEVELOPMENT (MOSQUITO NETS)</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Tutor:</strong> Hello Edward. Sit down.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Edward:</strong> Thanks. I need some advice on my presentation about product development.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Tutor:</strong> Right. Have you decided what to focus on?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Edward:</strong> Yes, the product I’ve chosen is a particular type of mosquito net.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Tutor:</strong> Any reason for choosing that?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Edward:</strong> Hmm, I spent last summer travelling around Africa with a friend. He’s studying medicine, so when we were in a region where mosquitoes cause malaria, we visited a medical center.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Edward:</strong> Uh huh. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"9\" data-index-in-node=\"16\">(21) <span class=\"citation-621\">I chatted to an administrator [A]</span></strong></span><span class=\"citation-621 citation-end-621\"><span style=\"text-decoration: underline; background-color: #f3db7b;\"> </span>while my friend talked to one of the doctors, and I found out they’ve had far fewer cases of malaria since these mosquito nets became available locally. That made me interested in the<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>m.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<h3 class=\"\" data-path-to-node=\"2\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></h3>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Tutor:</strong> Hmm, okay. Mosquito nets have quite a long history, don’t they? I believe they’ve been used in Japan for centuries.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Edward:</strong> That’s right, though apparently, Queen Cleopatra slept under one in <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"11\" data-index-in-node=\"76\">(22) ancient Egypt [C]</strong></span>. That was probably where they were invented. And much later nets were used in China, so perhaps they were invented there independently.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Edward:</strong> Originally they were made of silk, but later cotton was used, and nowadays they’re mainly synthetic. <span style=\"background-color: #ffffff;\">It wasn’t until the middle of <span style=\"text-decoration: underline;\"><span style=\"background-color: #f3db7b;\"><strong>the 20th century</strong></span></span> that they developed nets treated with insecticides for use by the military.</span></p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Edward:</strong> And that was a major step forward.<span style=\"background-color: #f3db7b;\"><strong> (23) </strong></span><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong><span style=\"background-color: #f3db7b;\">T</span>hey used an insecticide called DDT, but it was later found that this could be harmful to people as well as mosquitoes [B].</strong></span></p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Tutor:</strong> Hmm. Is that still a problem with modern nets?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Edward:</strong> Oh no, the chemicals used nowadays are safe, even if people sleep under them every night, and the nets work and they’re odor-free. But they have to be treated fairly often with the chemical, which the owners need to do themselves.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Tutor:</strong> Hmm, uh, presumably distribution of the chemical can be a problem in <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"16\" data-index-in-node=\"76\">(24) remote areas [C]</strong>.</span> I mean, people may not be able to get hold of it easily.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Edward:</strong> That’s right.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Tutor:</strong> Hmm, okay. Tell me about this net you’re going to talk about.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Edward:</strong> Hmm, well, the brand name is Olyset, <span class=\"citation-620 citation-end-620\">and the product was invented by a Japanese company. These nets are an improvement on the alternatives because the insecticide is contained inside the fibre and released gradually. It’s not coated on the outside as with ordinary nets, so the chemicals don’t have to be repl<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span>aced.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<h3 class=\"\" data-path-to-node=\"2\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></h3>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Edward:</strong> Right, and Olyset nets are also tougher and don’t tear as easily.<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"20\" data-index-in-node=\"74\">(25) They give protection for at least five yea</strong><strong data-path-to-node=\"20\" data-index-in-node=\"74\">rs [A]</strong>, compared with a year or two for other nets. </span></span></p>\n<p data-path-to-node=\"20\"><span style=\"background-color: #ffffff;\"><strong data-path-to-node=\"3\" data-index-in-node=\"2399\">Tutor:</strong> Well, it sounds interesting. But for your seminar presentation, will you provide the bigger picture as well?</span></p>\n<p data-path-to-node=\"20\"><span style=\"background-color: #ffffff;\"><strong data-path-to-node=\"3\" data-index-in-node=\"2515\">Edward:</strong> Yes, it’ll be a case study of product development.</span></p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\"> Edward:</strong> I thought I’d introduce my presentation by describing the background to the new product… the general context.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Tutor:</strong> You mean the business context, where the investment’s coming from and that sort of thing?</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Edward:</strong> Hmm, well, I was thinking I’d talk first about insect-borne diseases, particularly malaria, and why there’s such an urgent need for new ways of fighting it. Some people might not know much about it.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"7\" data-index-in-node=\"418\">Tutor:</strong> Yes, that’s a good idea.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Edward:</strong> I’ve got some statistics about the numbers of people worldwide who get the disease each year. I thought I’d show those. They’re quite staggering.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Tutor:</strong> I can imagine. It’s one of the world’s biggest health problems after all. It would also be useful if you could find some statistical information on <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"27\" data-index-in-node=\"155\">(26) how malaria affects a country’s economic output</strong> <strong>[G] </strong>and present that too.</span></p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Edward:</strong> Hmm, OK. I’m sure I can find something. After that, I’ll talk about mosquito nets first—the historical development just briefly—and then I’ll introduce the Olyset mosquito net.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Tutor:</strong> Hmm, yes. Keep it simple. You could just present a bulleted list of <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"29\" data-index-in-node=\"75\">(27) its characteristics—the things that make it different from other types of net [D]</strong>—and talk that through.</span></p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Edward:</strong> Right. Then I thought I’d outline the production process.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Tutor:</strong> Fine. Should I give some information about <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"31\" data-index-in-node=\"50\">(28) where the money for the project has come from? There are lots of government and private sponsors [B]</strong>.</span></p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Edward:</strong> Hmm, definitely. That’s a very important aspect of any product development. Where are the nets being manufactured, by the way?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Edward:</strong> Oh, over half are made in Tanzania by a company called A to Z. They got an interest-free loan to buy in the necessary machinery.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Tutor:</strong> Well, I’d say a bit about the company profile as well, and then present <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"34\" data-index-in-node=\"79\">(29) figures about numbers of staff and the kinds of people they’re employing [A]</strong></span> on the Olyset project if you can find the details.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Edward:</strong> Hmm, OK. I haven’t included any information about marketing. I’ve got a lot of notes about it, but I’m not sure how to present them.</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Tutor:</strong> I wouldn’t mention that if I were you. You’ve only got a short time for your presentation and you’ve got quite a lot of material here already. But you should provide <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"36\" data-index-in-node=\"173\">(30) some figures about output. Have you found out from the company’s website how many nets they actually produce [F]?</strong></span></p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Edward:</strong> Yes, it’s over 30 million a year.</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Tutor:</strong> Hmm, right then. I’m not sure how to finish off. What do you think about including something on potential…</p>"}]', 0);
INSERT INTO public.questions VALUES ('daed4076-8a50-4102-99dd-dc645942f186', '7689bfb6-fc81-46b5-8145-38ec0d865c50', 'matching', 'Questions 26-30', '', '<p>Complete the flow-chart below.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-start=\"269\" data-end=\"293\"><strong>Seminar presentation</strong></p>\n<table style=\"border-collapse: collapse; width: 100%; border: 1px solid rgb(0, 0, 0); margin-left: 0px; margin-right: auto;\" border=\"1\"><colgroup><col style=\"width: 99.8584%;\"></colgroup>\n<tbody>\n<tr>\n<td style=\"border-color: #000000;\">\n<p><strong> Context: need for anti-malarial products</strong></p>\n<p> Figures relating to:</p>\n<ul>\n<li>\n<p>global incidence of the disease</p>\n</li>\n<li>\n<p>impact on {G National economics}</p>\n</li>\n</ul>\n</td>\n</tr>\n</tbody>\n</table>\n<p style=\"text-align: center;\" data-start=\"616\" data-end=\"654\">🔽</p>\n<table style=\"border-collapse: collapse; width: 100%; border: 1px solid rgb(0, 0, 0); margin-left: 0px; margin-right: auto;\" border=\"1\"><colgroup><col style=\"width: 99.8584%;\"></colgroup>\n<tbody>\n<tr>\n<td style=\"border-color: #000000;\">\n<p><strong> Mosquito nets</strong></p>\n<ul>\n<li>\n<p>History</p>\n</li>\n<li>\n<p>{D unique features of the product}</p>\n</li>\n</ul>\n</td>\n</tr>\n</tbody>\n</table>\n<p style=\"text-align: center;\" data-start=\"616\" data-end=\"654\">🔽</p>\n<table style=\"border-collapse: collapse; width: 100%; border: 1px solid rgb(0, 0, 0); margin-left: 0px; margin-right: auto;\" border=\"1\"><colgroup><col style=\"width: 100%;\"></colgroup>\n<tbody>\n<tr>\n<td style=\"border-color: #000000;\">\n<p><strong> Production</strong></p>\n<ul>\n<li>\n<p>information about {B sources of funding}</p>\n</li>\n<li>\n<p>profile of manufacturer with description of {A workforce} </p>\n</li>\n<li>\n<p>{F production figures national economies} (according to website)</p>\n</li>\n</ul>\n</td>\n</tr>\n</tbody>\n</table>\n<p> </p>", "answerOptions": [{"optionText": "A workforce"}, {"optionText": "B sources of funding"}, {"optionText": "C investment opportunities"}, {"optionText": "D unique features of the product"}, {"optionText": "E future developments"}, {"optionText": "F production figures national economies"}, {"optionText": "G National economics"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('64c9a212-a1ef-4670-bbe2-b69304d5b87b', '557154f0-bc0c-42d2-adfc-d6753e8dd64f', 'fillup', 'Questions 8–13', '<p id="p-rc_7a928e36d3c9eadf-72" data-path-to-node="9"><strong data-path-to-node="9" data-index-in-node="0"><span class="citation-4404 citation-end-4404">Complete the notes below.<sup class="superscript" data-turn-source-index="47"><!----></sup></span></strong></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_7a928e36d3c9eadf-73" data-path-to-node="10"><span class="citation-4403">Choose </span><strong data-path-to-node="10" data-index-in-node="7"><span class="citation-4403">ONE WORD ONLY</span></strong><span class="citation-4403 citation-end-4403"> from the passage for each answer.<sup class="superscript" data-turn-source-index="48"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_7a928e36d3c9eadf-74" data-path-to-node="11"><span class="citation-4402 citation-end-4402">Write your answers in boxe<sup class="superscript" data-turn-source-index="49"><!----></sup></span>s 8–13 on your answer sheet.</p>
<table style="border-collapse: collapse; width: 99.9592%; height: 212.688px; border-spacing: 2px; border: 2px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr style="height: 212.688px;">
<td style="border-width: 2px; padding: 2px; border-color: #000000;">
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>The tennis racket and how it has changed</strong></span></p>
<ul>
<li>
<p>Mike and Bob Bryan made changes to the types of {paint} used on their ra<span class="citation-4399 citation-4400 citation-4401 citation-end-4401">cket frames.</span></p>
</li>
<li>
<p><span class="citation-4399 citation-4400 citation-4401 citation-end-4401"><sup class="superscript" data-turn-source-index="50"><!----></sup></span><span class="citation-4399 citation-4400 citation-end-4400"><sup class="superscript" data-turn-source-index="51"><!----></sup></span><span class="citation-4399 citation-end-4399"><sup class="superscript" data-turn-source-index="52"><!----></sup></span><span class="citation-4396 citation-4397 citation-4398">Players were not allowed to use the spaghetti-strung racket because of the amount of {topspin}</span><span class="citation-4396 citation-4397 citation-4398 citation-end-4398"> it created.</span></p>
</li>
<li>
<p><span class="citation-4396 citation-4397 citation-4398 citation-end-4398"><sup class="superscript" data-turn-source-index="53"><!----></sup></span><span class="citation-4396 citation-4397 citation-end-4397"><sup class="superscript" data-turn-source-index="54"><!----></sup></span><span class="citation-4396 citation-end-4396"><sup class="superscript" data-turn-source-index="55"><!----></sup></span><span class="citation-4393 citation-4394 citation-4395">Changes to rackets can be regarded as being as important as players’ diets or the {training}</span><span class="citation-4393 citation-4394 citation-4395 citation-end-4395"> they do.</span></p>
</li>
<li>
<p><span class="citation-4393 citation-4394 citation-4395 citation-end-4395"><sup class="superscript" data-turn-source-index="56"><!----></sup></span><span class="citation-4393 citation-4394 citation-end-4394"><sup class="superscript" data-turn-source-index="57"><!----></sup></span><span class="citation-4393 citation-end-4393"><sup class="superscript" data-turn-source-index="58"><!----></sup></span><span class="citation-4390 citation-4391 citation-4392">All rackets used to have natural strings made from the {intestines|gut}</span><span class="citation-4390 citation-4391 citation-4392 citation-end-4392"> of animals.</span></p>
</li>
<li>
<p><span class="citation-4390 citation-4391 citation-4392 citation-end-4392"><sup class="superscript" data-turn-source-index="59"><!----></sup></span><span class="citation-4390 citation-4391 citation-end-4391"><sup class="superscript" data-turn-source-index="60"><!----></sup></span><span class="citation-4390 citation-end-4390"><sup class="superscript" data-turn-source-index="61"><!----></sup></span><span class="citation-4387 citation-4388 citation-4389 citation-end-4389">Pete Sam<sup class="superscript" data-turn-source-index="62"><!----></sup></span><span class="citation-4387 citation-4388">pras had metal {weights}</span><span class="citation-4387 citation-4388 citation-end-4388"> put into the frames of his rackets.</span></p>
</li>
<li>
<p><span class="citation-4387 citation-4388 citation-end-4388"><sup class="superscript" data-turn-source-index="63"><!----></sup></span><span class="citation-4387 citation-end-4387"><sup class="superscript" data-turn-source-index="64"><!----></sup></span><span class="citation-4385 citation-4386">Gonçalo Oliveira changed the {grips}</span><span class="citation-4385 citation-end-4385"> on his racket handles.<sup class="superscript" data-turn-source-index="66"><!----></sup></span></p>
</li>
</ul>
<p><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</td>
</tr>
</tbody>
</table>
<p data-path-to-node="11"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">8. paint — {Mike and Bob Bryan made changes to the types of paint used on their racket frames.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"They explain how they have adjusted not only racket length, but even experimented with <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"108\">different kinds of paint</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Anh em nhà Bryan không chỉ chỉnh độ dài vợt mà còn thử nghiệm với các loại sơn (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"92\">paint</strong>) khác nhau trên khung vợt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">9. topspin — {Players were not allowed to use the spaghetti-strung racket because of the amount of topspin it created.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"It created a string bed that generated so much <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"68\">topspin</strong> that it was quickly <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"96\">banned</strong> by the International Tennis Federation.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Not allowed to use\" tương ứng với \"banned\" (bị cấm). Lý do là vì loại dây này tạo ra quá nhiều độ xoáy (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"117\">topspin</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">10. training — {Changes to rackets can be regarded as being as important as players’ diets or the training they do.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">\"Today it is... an aspect of the game that is <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"66\">equal in significance to nutrition or training</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc sửa đổi vợt ngày nay được coi là quan trọng ngang bằng với chế độ dinh dưỡng (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"95\">nutrition/diets</strong>) và việc tập luyện (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"131\">training</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">11. intestines (hoặc gut) — {All rackets used to have natural strings made from the intestines/gut of animals.}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">\"At one time, all tennis rackets were strung with <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"70\">natural gut</strong> made from the outer layer of sheep or cow <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"124\">intestines</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước đây, dây vợt tự nhiên được làm từ ruột (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"58\">intestines</strong> hoặc <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"74\">gut</strong>) của động vật (như bò, cừu).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">12. weights — {Pete Sampras had metal weights put into the frames of his rackets.}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">\"...the addition of four to five <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"53\">lead weights</strong> onto his rackets...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Pete Sampras đã thêm các quả tạ chì (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"49\">lead weights</strong>) - một loại kim loại (metal) - vào khung vợt để tăng sức mạnh giao bóng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">13. grips — {Gonçalo Oliveira changed the grips on his racket handles.}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 10):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"21\">\"The professional Portuguese player Gonçalo Oliveira replaced the original <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"96\">grips</strong> of his rackets with something thinner...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Oliveira đã thay đổi phần tay quấn (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"48\">grips</strong>) ở cán vợt vì cảm thấy loại cũ không thoải mái khi cầm.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('ff929d03-4645-40d1-80a2-fe842a8e6fd2', '6204f6ae-328d-4a14-bc38-cfde012e66e7', 'radio', 'Questions 27-30', NULL, '<p data-start="87" data-end="131"><span style="font-family: arial, helvetica, sans-serif;">Choose the correct letter, A, B, C or D.</span></p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A. defining some commonly used terms."}, {"content": "B. questioning a widely held assumption."}, {"content": "C. mentioning a challenge faced by everyone."}, {"content": "D. specifying a situation which makes us most anxious."}], "question": "In the first paragraph, the writer introduces the topic of the text by"}, {"correct": 0, "options": [{"content": "A. The regular changes of stress levels in their working lives make them ideal study subjects."}, {"content": "B. The strategies they use to handle stress are of particular interest to researchers."}, {"content": "C. The stressful nature of their job is typical of many public service professions."}, {"content": "D. Their personalities make them especially well-suited to working under stress."}], "question": "What point does the writer make about firefighters in the second paragraph?"}, {"correct": 3, "options": [{"content": "A. explaining their findings"}, {"content": "B. justifying their approach"}, {"content": "C. setting out their objectives"}, {"content": "D. describing their methodology"}], "question": "What is the writer doing in the fourth paragraph?"}, {"correct": 2, "options": [{"content": "A. enables people to respond more quickly to stressful situations."}, {"content": "B. results in increased ability to control our levels of anxiety."}, {"content": "C. produces heightened sensitivity to indications of external threats."}, {"content": "D. is activated when there is a need to communicate a sense of danger."}], "question": "In the seventh paragraph, the writer describes a mechanism in the brain which"}]', NULL, NULL, NULL, NULL, 0);
INSERT INTO public.questions VALUES ('a6a7eb8d-7a88-4216-995b-84762cfc3a17', 'c598392a-9e35-4e43-b3c1-f182f5b7b1e6', 'checkbox', 'Questions 19–20', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>things do applicants need in order to get a job at the camp?</p>
', 'multiple_choice_many', 'null', '[{"option": "experience of working with children", "correct": false}, {"option": "an ability to make decisions on their own", "correct": false}, {"option": "a friendly personality", "correct": true}, {"option": "relevant qualiﬁcations", "correct": false}, {"option": "to be over a certain age", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('a91b525c-ad27-4504-b22e-8eed7fcdfeef', '59634fca-f09f-4f67-a08d-ef2b7fc38048', 'radio', 'Questions 21-26', NULL, '<p>Choose the correct answers</p>
<p><span style="font-size: 12pt;"><strong>Research Project.</strong></span></p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "He thought the information would be useful for town planning"}, {"content": "He has a special interest in the use of public services"}, {"content": "He read about a similar study which had been done earlier"}], "question": "How did John choose the topic of his research project?"}, {"correct": 1, "options": [{"content": "The use of public services has altered very littl"}, {"content": "A group of people has changed its habits"}, {"content": "The most frequently used facility is the library"}], "question": "During his research, John is expecting to find tha"}, {"correct": 0, "options": [{"content": "They may be lacking in details"}, {"content": "They may not be readily available"}, {"content": "They may be difficult to analyse"}], "question": "What is the problem with using official records?"}, {"correct": 2, "options": [{"content": "He needs to do a course in questionnaire design first"}, {"content": "He should use his method instead of looking at public records"}, {"content": " He will find the practice he gets useful the following year"}], "question": "What does the tutor think about John using a questionnaire to get information?"}, {"correct": 2, "options": [{"content": "Occupation"}, {"content": "Income group"}, {"content": "Qualifications"}], "question": "Which new variable does John agree to add to his investigation?"}, {"correct": 1, "options": [{"content": "The same number as in the previous study"}, {"content": "A greater number than he needs for analysis"}, {"content": "The number recommended in the project guidelines"}], "question": "How many questionnaires will John distribute?"}]', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>SECTION 3</strong></p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Hello John, come in and sit down. You’re here to discuss your research project, are you?</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Yes, I’ve more or less decided what to do, but I’d like your opinion.</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Fine. You’ve chosen a topic?</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Yes, I want to look at how people use public services in their local area—things like parks and swimming pools.</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Right, well, the kind of information you’ll get is very useful for town planning, of course. Do you have a special interest in public services?</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Not really. It’s just that <strong>(21) I found a report in the college library about an investigation that was done 10 years ago and I thought it would be interesting to do a parallel one (C: read about a similar study)</strong>.</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Hmm, 10 years is a relatively short space of time. What do you expect to find? Do you think things will be more or less the same as before?</p>\n<p class=\"MsoNormal\"><strong>John:</strong> I think there will be some differences. For example, I think the number of people going to the library will have decreased… and <strong>(22) I’d guess that older people are using the sports centre more often than they used to (B: A group of people has changed its habits)</strong>.</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Fine, so those are your hypotheses. Now what sort of data are you going to use?</p>\n<p class=\"MsoNormal\"><strong>John:</strong> I was thinking of using official records from the management or the local council and analysing them. They should be easy to obtain. I don’t think that sort of information would be confidential.</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Yes, you’re probably right. <strong>(23) There might not be as much information as you’d like (A: lacking in details)</strong>, but it would certainly be the easiest kind of data to work with. But have you considered using a questionnaire as well? It’s OK to get data from more than one source.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Absolutely. It’s a bonus.</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> You’ve already done the module on questionnaire design, haven’t you? And <strong>(24) it’ll be good to get experience because next year you’ll have to do something similar for your final dissertation on a bigger scale (C: find the practice he gets useful the following year)</strong>.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> OK.</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> And what are the variables you’ll be looking at? Are you going to look at people’s level of education—whether they have a degree, for example?</p>\n<p class=\"MsoNormal\"><strong>John:</strong> I hadn’t planned to. Do you think I should?</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Well, you might see some interesting patterns.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> <strong>(25) Okay, and that’ll tie in nicely with my plans (C: Qualifications)</strong> to analyze the kind of work people do. Hmm, what about the size of your sample? Have you got any thoughts on the number of questionnaires you might send out? The previous study surveyed 120 people.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> I don’t think I can really analyze more than 50 working by myself. So <strong>(26) I should probably distribute about 80 questionnaires altogether to allow for wastage (B: A greater number than he needs for analysis)</strong>. Do you think that’s enough?</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Definitely. I know that your project guidelines recommend a minimum of 100, but that’s an ideal number and you’re working by yourself.</p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\" />\n</div>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> And think of ways you can encourage people to actually complete the questionnaire. For example, to make sure that your questions make sense, <strong>(27/28) you should try them out beforehand (E: Trialing the questionnaire on friends)</strong>.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Okay, that’s no problem, my friends will help.</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Good. Sometimes you get unpredictable responses and you have to rephrase a question. And I know that you usually get a better return if you deliver questionnaires in person, but there will be too many.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> But <strong>(27/28) I could enclose a stamped envelope for the return post (D: Providing return envelopes)</strong>. It’s a bit expensive, but I think it would be worth it.</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Yes, good. Some people say that another way of increasing returns is to make the questionnaires anonymous, but usually people put their names on anyway, so I don’t think that would make much difference. Okay, and can you give me a bit more advice about the questionnaire? Would it be a good idea to have <strong>(29/30) a short paragraph at the top explaining what I’m doing and why (C: introduction to explain survey’s purpose)</strong>?</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Definitely. And don’t forget you’ll need to <strong>(29/30) get a bit of information about your subjects—what age group they’re in (B: elicit personal information)</strong>, and perhaps how long they’ve lived in the area. So you’ll need questions for that.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Ah yes, I suppose that will mean it takes a bit longer to complete. But should I give them my phone number in case there’s anything they’re not sure about?</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> I wouldn’t if I were you, no.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> OK, and do I have to use open-ended questions as well as closed questions?</p>\n<p class=\"MsoNormal\"><strong>Tutor:</strong> Well, it depends. In this case, I’d stick to closed questions. The results will be much more manageable like that.</p>\n<p class=\"MsoNormal\">\n"}]', 0);
INSERT INTO public.questions VALUES ('12f75ddf-f6e0-4520-be9e-51636cfd810f', '59634fca-f09f-4f67-a08d-ef2b7fc38048', 'checkbox', 'Questions 27-28', NULL, '<p>Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong></p>
<p>Which <strong>TWO </strong>strategies will John use to encourage people to fill out his questionnaire?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. Using simple language", "correct": false}, {"option": "B. Delivering the questionnaires in person", "correct": false}, {"option": "C. Making the questionnaires anonymous", "correct": false}, {"option": "D. Providing return envelopes", "correct": true}, {"option": "E. Trialing the questionnaire on friends", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('f8ac96e8-1ce4-4fd6-a5e8-9b20503bbfe3', 'a2fc85b3-b816-486d-bafb-f4627ad93312', 'fillup', 'Questions 7–13', '<p>Complete the summary below.</p>
<p>Choose <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</p>
<p>Dr Olsen group believe that the sudden increase in the size of dinosaurs may have been due to something known as {ecological release}. A current example of this can be found on Komodo Island in Indonesia, where some of the lizards are commonly called {dragons} because of their size. Apparently, they have grown this big because they do not have any {competitors}. The asteroid strike that may have cleared the way for dinosaurs to become the dominant group probably occurred 202 million years ago.</p>
<p>According to the writer, there are three possible reasons why we have not found a large hole in the Earth’s crust dating back 202 million years. First, it may have been {overlooked} by scientists, because craters are easily covered up. Or, it could have {vanished}; for example, if the hole had been in the ocean, it would no longer exist because of the {tectonic processes} that produce continental drift. Thirdly, the hole could still exist but have been {misdated}</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<h3 data-path-to-node=\"2\">Câu 7</h3>\n<ul data-path-to-node=\"3\">\n<li><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"3,0,0\" data-index-in-node=\"8\">ecological release</strong></li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"3,1,0\" data-index-in-node=\"11\">“Dr Olsen and his colleagues suggest that the explanation for may be a phenomenon called <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"100\">ecological release</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản nêu rõ giả thuyết của nhóm nghiên cứu Olsen về việc tại sao các loài khủng long lại tăng nhanh về số lượng và kích thước. Họ gọi tên hiện tượng này là “ecological release” (giải phóng sinh thái).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"4\">Câu 8</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">dragons</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,1,0\" data-index-in-node=\"11\">“The most spectacular example is on the Indonesian island of Komodo, where local lizards have grown so large that they are often referred to as <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"155\">dragons</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Để minh họa cho hiện tượng trên, tác giả dẫn chứng về loài thằn lằn tại đảo Komodo. Do kích thước khổng lồ, chúng thường được mọi người gọi là “dragons” (rồng).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">Câu 9</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">competitors</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,1,0\" data-index-in-node=\"11\">“This is seen today when reptiles… reach islands where they face no <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"81\">competitors</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Lý do khiến các loài bò sát (như rồng Komodo hay khủng long kỷ Jura) có thể phát triển mạnh mẽ là vì tại môi trường đó, chúng không phải đối mặt với bất kỳ <strong data-path-to-node=\"7,2,0\" data-index-in-node=\"168\">đối thủ cạnh tranh</strong> nào.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">Câu 10</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">overlooked</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,1,0\" data-index-in-node=\"11\">“Old craters are eroded and buried, and not always easy to find. It may, of course, have been <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"105\">overlooked</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi lý giải tại sao chưa tìm thấy hố thiên thạch 202 triệu năm tuổi, giả thuyết đầu tiên là do nó đã bị <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"116\">bỏ sót/không được chú ý tới</strong> vì các miệng hố cũ thường bị xói mòn và vùi lấp.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">Câu 11</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">vanished</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,1,0\" data-index-in-node=\"11\">“Alternatively, it may have <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"39\">vanished</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Khả năng thứ hai được đưa ra là miệng hố này có thể đã <strong data-path-to-node=\"11,2,0\" data-index-in-node=\"67\">biến mất hoàn toàn</strong>. Điều này xảy ra nếu địa điểm va chạm nằm ở đại dương.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">Câu 12</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">tectonic processes</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,1,0\" data-index-in-node=\"11\">“…the ocean floor is constantly recycled by the <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"61\">tectonic processes</strong> that bring about continental drift.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Lý do miệng hố ở đại dương biến mất là do đáy biển liên tục bị tái tạo bởi các <strong data-path-to-node=\"13,2,0\" data-index-in-node=\"91\">quá trình kiến tạo</strong> mảng địa chất (quá trình gây ra sự trôi dạt lục địa).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"14\">Câu 13</h3>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">misdated</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,1,0\" data-index-in-node=\"11\">“There is a third possibility, however. This is that the crater is known, but has been <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"98\">misdated</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Khả năng cuối cùng là con người thực chất đã tìm thấy miệng hố đó rồi (ví dụ hố Manicouagan ở Quebec), nhưng nó bị <strong data-path-to-node=\"15,2,0\" data-index-in-node=\"127\">xác định sai niên đại</strong> nên các nhà khoa học chưa khớp nó vào mốc thời gian 202 triệu năm trước.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('2c145bfe-d2e7-4db1-af26-72bc4b391dea', '59634fca-f09f-4f67-a08d-ef2b7fc38048', 'checkbox', 'Questions 29-30', NULL, '<p>Choose <strong>TWO </strong>letters, A-E</p>
<p>Which <strong>TWO </strong>pieces of advice does the tutor give John about his questionnaire?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. There should be a mixture of question types", "correct": false}, {"option": "B. Some questions should elicit personal information", "correct": true}, {"option": "C. There should be an introduction to explain the survey’s purpose", "correct": true}, {"option": "D. A telephone number should be provided for queries", "correct": false}, {"option": "E. The questions should only take a few minutes to answer", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('6a3ed0ac-50f5-4536-830b-b834c288f674', '8756a7ff-0501-40fa-96a3-66b7c2fd933e', 'matching', 'Questions 11–16', '', '<p>Choose <strong data-path-to-node="5" data-index-in-node="7">SIX</strong> answers from the box and write the correct letter, <strong data-path-to-node="5" data-index-in-node="62">A–H</strong>, next to Questions 11–16.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p>Superheroes {C   is aimed at children with a disability}</p>\n<p> </p>\n<p>Just do it {D   involves a drama activity}</p>\n<p> </p>\n<p>Count on me {F   is aimed at a specific age group}</p>\n<p> </p>\n<p>Speak up {G   explores an unhappy feeling}</p>\n<p> </p>\n<p>Jump for joy {B   will be led by a prize-winning author}</p>\n<p> </p>\n<p>Sticks and stones {E   focuses on new relationships}</p>", "answerOptions": [{"optionText": "A   involves painting and drawing"}, {"optionText": "B   will be led by a prize-winning author"}, {"optionText": "C   is aimed at children with a disability"}, {"optionText": "D   involves a drama activity"}, {"optionText": "E   focuses on new relationships"}, {"optionText": "F   is aimed at a specific age group"}, {"optionText": "G   explores an unhappy feeling"}, {"optionText": "H   raises awareness of a particular culture"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('dfbca7ee-04b7-40ea-8fb6-32b3b977e6ab', 'bd7e4e44-1351-4772-9ce8-f2b6d73ef0cc', 'matrix', 'Questions 21–23', NULL, '<p>Choose the correct packaging development, A–F, for each company.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "KFC", "correctCategoryLetter": "E"}, {"itemText": "Loliware", "correctCategoryLetter": "D"}, {"itemText": "Tomorrow Machine", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "a container that gets bigger under certain conditions", "categoryLetter": "A"}, {"categoryText": "packaging that vanishes in hot water", "categoryLetter": "B"}, {"categoryText": "a material that prevents the waste of sticky condiments", "categoryLetter": "C"}, {"categoryText": "packaging made from a vegetable product", "categoryLetter": "D"}, {"categoryText": "a sweet container for hot drinks", "categoryLetter": "E"}, {"categoryText": "round, flavourless containers that can be consumed", "categoryLetter": "F"}]}', '[{"content": "<p><strong data-path-to-node=\"1\" data-index-in-node=\"0\">21. KFC: E (a sweet container for hot drinks)</strong></p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 2–4.</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The fried chicken chain <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"36\">KFC</strong>, for example, is experimenting with an <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"79\">edible coffee-cup</strong>. Made from a <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"110\">hard cookie lined with heat-resistant white chocolate</strong>…”</li>\n<li><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> KFC đang thử nghiệm loại cốc đựng cà phê (hot drinks) có thể ăn được. Cấu tạo của chiếc cốc này từ bánh quy và sô-cô-la trắng, vốn là những nguyên liệu ngọt (sweet). Do đó, đây là một vật chứa đồ uống nóng có vị ngọt.</li>\n</ul>\n<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">22. Loliware: D (packaging made from a vegetable product)</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 9–10.</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “And last year, the company [<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"40\">Loliware</strong>] introduced edible cupcake wrappers made from <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"95\">potato starch</strong>.”</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công ty Loliware đã giới thiệu loại màng bọc bánh cupcake ăn được làm từ tinh bột khoai tây (<strong data-path-to-node=\"4,2,0\" data-index-in-node=\"105\">potato starch</strong>). Khoai tây là một loại sản phẩm thực vật (vegetable product), khớp hoàn toàn với mô tả ở lựa chọn D.</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">23. Tomorrow Machine: A (a container that gets bigger under certain conditions)</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng cuối.</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"12\">Tomorrow Machine</strong> is also working on a <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"50\">compressed tiny package that expands into a full-size bowl</strong> when hot water is added.”</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công ty Tomorrow Machine đang nghiên cứu loại bao bì siêu nén (tiny package) có khả năng nở ra (expands/gets bigger) thành một chiếc bát kích cỡ bình thường khi gặp điều kiện nhất định là có nước nóng (hot water) đổ vào.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('f4356174-aee6-40a4-8995-717e493046ad', 'fcc1bf58-c30c-4ff6-8657-beb3e4887c03', 'matrix', 'Questions 14–18', NULL, '<p>The text has five paragraphs, <strong>A–E</strong>. Which paragraph contains the following information?</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "a description of a company that provides financial assistance for employees to continue their learning", "correctCategoryLetter": "B"}, {"itemText": "a mention of worldwide trends in the changing attitudes of businesses and customers", "correctCategoryLetter": "E"}, {"itemText": "details about years of continuous service by employees at one company", "correctCategoryLetter": "C"}, {"itemText": "a reference to the reason why many people-centered workers first start their own businesses", "correctCategoryLetter": "A"}, {"itemText": "a comment about how certain groups are still fighting for respect in the business world", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<h2 data-start=\"81\" data-end=\"93\"><strong data-start=\"84\" data-end=\"93\">14. B</strong></h2>\n<p data-start=\"95\" data-end=\"132\"><strong data-start=\"95\" data-end=\"106\">Vị trí:</strong> Đoạn B, phần giữa đoạn.</p>\n<p data-start=\"134\" data-end=\"285\"><strong data-start=\"134\" data-end=\"148\">Dẫn chứng:</strong><br data-start=\"148\" data-end=\"151\" />“He encourages people to work their way up in the company, and pays, at least partially, for educational opportunities and textbooks.”</p>\n<p data-start=\"287\" data-end=\"502\"><strong data-start=\"287\" data-end=\"302\">Giải thích:</strong><br data-start=\"302\" data-end=\"305\" />Công ty Plastic Solutions (Stephen Harper) hỗ trợ tài chính một phần cho nhân viên tiếp tục học tập và mua giáo trình. Đây chính là mô tả về công ty hỗ trợ tài chính cho việc học tập của nhân viên.</p>\n<hr data-start=\"504\" data-end=\"507\" />\n<h2 data-start=\"509\" data-end=\"521\"><strong data-start=\"512\" data-end=\"521\">15. E</strong></h2>\n<p data-start=\"523\" data-end=\"566\"><strong data-start=\"523\" data-end=\"534\">Vị trí:</strong> Đoạn E, câu đầu và giữa đoạn.</p>\n<p data-start=\"568\" data-end=\"747\"><strong data-start=\"568\" data-end=\"582\">Dẫn chứng:</strong><br data-start=\"582\" data-end=\"585\" />“Family-friendly entrepreneurs are becoming more commonplace internationally…”<br data-start=\"663\" data-end=\"666\" />“…parents are important consumers and investors who can change buying practices.”</p>\n<p data-start=\"749\" data-end=\"933\"><strong data-start=\"749\" data-end=\"764\">Giải thích:</strong><br data-start=\"764\" data-end=\"767\" />Đoạn E đề cập xu hướng toàn cầu (internationally) và sự thay đổi thái độ của doanh nghiệp và người tiêu dùng (customers/investors). Đây là xu hướng mang tính quốc tế.</p>\n<hr data-start=\"935\" data-end=\"938\" />\n<h2 data-start=\"940\" data-end=\"952\"><strong data-start=\"943\" data-end=\"952\">16. C</strong></h2>\n<p data-start=\"954\" data-end=\"985\"><strong data-start=\"954\" data-end=\"965\">Vị trí:</strong> Đoạn C, câu cuối.</p>\n<p data-start=\"987\" data-end=\"1108\"><strong data-start=\"987\" data-end=\"1001\">Dẫn chứng:</strong><br data-start=\"1001\" data-end=\"1004\" />“…the company will celebrate six 5-year anniversaries, and one 25-year anniversary among its employees.”</p>\n<p data-start=\"1110\" data-end=\"1259\"><strong data-start=\"1110\" data-end=\"1125\">Giải thích:</strong><br data-start=\"1125\" data-end=\"1128\" />Đoạn này nêu rõ số năm làm việc liên tục của nhân viên (5 năm, 25 năm), tức là thông tin về thời gian phục vụ liên tục tại công ty.</p>\n<hr data-start=\"1261\" data-end=\"1264\" />\n<h2 data-start=\"1266\" data-end=\"1278\"><strong data-start=\"1269\" data-end=\"1278\">17. A</strong></h2>\n<p data-start=\"1280\" data-end=\"1310\"><strong data-start=\"1280\" data-end=\"1291\">Vị trí:</strong> Đoạn A, câu 2–3.</p>\n<p data-start=\"1312\" data-end=\"1440\"><strong data-start=\"1312\" data-end=\"1326\">Dẫn chứng:</strong><br data-start=\"1326\" data-end=\"1329\" />“Many of these go into business themselves as a result of negative experiences they have had in the workplace.”</p>\n<p data-start=\"1442\" data-end=\"1592\"><strong data-start=\"1442\" data-end=\"1457\">Giải thích:</strong><br data-start=\"1457\" data-end=\"1460\" />Nhiều doanh nhân lấy con người làm trung tâm bắt đầu kinh doanh vì trải nghiệm tiêu cực trước đó. Đây chính là lý do họ khởi nghiệp.</p>\n<hr data-start=\"1594\" data-end=\"1597\" />\n<h2 data-start=\"1599\" data-end=\"1611\"><strong data-start=\"1602\" data-end=\"1611\">18. D</strong></h2>\n<p data-start=\"1613\" data-end=\"1648\"><strong data-start=\"1613\" data-end=\"1624\">Vị trí:</strong> Đoạn D, câu gần cuối.</p>\n<p data-start=\"1650\" data-end=\"1766\"><strong data-start=\"1650\" data-end=\"1664\">Dẫn chứng:</strong><br data-start=\"1664\" data-end=\"1667\" />“Working mothers still need to be taken more seriously, and so do mothers who are business owners.”</p>\n<p data-start=\"1768\" data-end=\"1968\"><strong data-start=\"1768\" data-end=\"1783\">Giải thích:</strong><br data-start=\"1783\" data-end=\"1786\" />Hazel Gibbs nói rằng các bà mẹ đi làm và các nữ doanh nhân vẫn cần được coi trọng hơn. Điều này cho thấy một số nhóm vẫn đang đấu tranh để được tôn trọng trong môi trường kinh doanh.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('e168b4a7-7694-44a2-98f8-2bec56001cf9', 'd770d077-ae92-43bb-8e5b-9931487ac043', 'matching', 'Questions 21–26', NULL, '<p>What reason do teachers give for using each of the following picture books with children?</p>
<p>Choose <strong>SIX </strong>correct answers, <strong>A-I,</strong> next to questions <strong>21-26</strong>.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Picture books</strong></p>\n<p> </p>\n<p>I Spy Friends {I It features well-known characters.}</p>\n<p> </p>\n<p>Goodnight Little Rabbit {A The pictures show changing times of day.}</p>\n<p> </p>\n<p>The Boat Party {E The pictures were done by a famous illustrator.}</p>\n<p> </p>\n<p>Puppy and Friends {F There is a surprise at the end of the story.}</p>\n<p> </p>\n<p>Hats and Socks {C It has an uncommon plot structure.}</p>\n<p> </p>\n<p>A Family Adventure {D The text can easily be turned into song.}</p>", "answerOptions": [{"optionText": "A The pictures show changing times of day."}, {"optionText": "B The words are fun to say out loud."}, {"optionText": "C It has an uncommon plot structure."}, {"optionText": "D The text can easily be turned into song."}, {"optionText": "E The pictures were done by a famous illustrator."}, {"optionText": "F There is a surprise at the end of the story."}, {"optionText": "G The pictures are simple line drawings."}, {"optionText": "H It was published very recently."}, {"optionText": "I It features well-known characters."}], "matchingItems": null}', 'null', '[{"content": "<h3 data-path-to-node=\"3\">PART 3: PICTURE BOOKS PRESENTATION</h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Student 1:</strong> Hi, are you ready to discuss our presentation?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Student 2:</strong> Yeah sure. So what are we going to say about teachers reading picture books with young children?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Student 1:</strong> Hmm, I think we should start with the reasons why teachers use picture books. The journal article we read mentioned several picture books and why they’re popular with teachers.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Student 2:</strong> Right, like <em data-path-to-node=\"7\" data-index-in-node=\"23\">I Spy Friends</em>. It’s a lovely story.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Student 1:</strong> Yeah, the children like to find the familiar faces from the fairy tales they know so well, and they’re all doing predictable things. The article said children find this familiarity very comforting. <span style=\"text-decoration: underline;\"><strong><span style=\"background-color: #ffe786;\">(21) I (It is popular with boys/familiarity).</span></strong></span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Student 2:</strong> Yes, now how about <em data-path-to-node=\"9\" data-index-in-node=\"30\">Goodnight Little Rabbit</em>, which has those delightful pictures? I love the way the colours get darker as the book progresses, indicating how evening turns into night.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Student 1:</strong> Me too. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>The article said that’s why teachers like it—very cute and a good example of visual subtext. Hard to believe that it came out over 60 years ago; it’s still relevant. (22) A (It is too long)</strong></span></p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Student 2:</strong> I really liked what the article said about <em data-path-to-node=\"11\" data-index-in-node=\"54\">The Boat Party</em>. There’s a lot of repetition, which I think would be great for vocabulary development.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Student 1:</strong> That’s true, but apparently it’s the images that make it popular with children. <strong><span style=\"text-decoration: underline; background-color: #ffe786;\">The artist is really well known and children often ask for her books. (23) E (It has won a prize).</span></strong></p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Student 2:</strong> Oh, that’s good to know. And shall we also include <em data-path-to-node=\"13\" data-index-in-node=\"62\">Puppy and Friends</em>?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Student 1:</strong> Yes, it sounds like an innocent title, but the article warns that there’s a bit of a fright—you know, the one on the last page when the puppy suddenly encounters the scary cat. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>Teachers like to use this to help children explore their emotions. (24) F (The characters are very likable).</strong></span></p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Student 2:</strong> Sounds good. <em data-path-to-node=\"15\" data-index-in-node=\"24\">Hats and Socks</em> is a good one. It doesn’t really have a beginning and an end, does it? Which is unusual.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Student 1:</strong> That’s why teachers like this one though, because it’s so different. It’s good for children to hear a story that doesn’t follow the usual pattern. And the pages are so full of life and colour. <strong data-path-to-node=\"16\" data-index-in-node=\"204\">(25) C</strong> (It is a good example of its type).</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Student 2:</strong> A good choice. Hmm, okay, and for our last one, how about <em data-path-to-node=\"17\" data-index-in-node=\"69\">A Family Adventure</em>? This one uses a lot of the same language throughout, which I think can help with letter and word recognition.<span style=\"text-decoration: underline; background-color: #ffe786;\"><strong> Teachers say it has a really poetic feel to it; they often sing it to a simple tune. (26) D (The story is quite simple).</strong></span></p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Student 1:</strong> Yes, and it’s full of beautiful watercolours too.</p>\n<hr data-path-to-node=\"19\" />\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Student 2:</strong> In the next part of our presentation, shall we look at some of the other research? I really liked Smith’s article about the history of picture books.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Student 1:</strong> Picture books haven’t been around for that long, of course, and as we know from our reading lists, there’s a lot of research on them already. Smith makes some interesting points.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Student 2:</strong> Yes, one thing that shocked me was that some people don’t consider picture books as proper writing because they don’t have enough words in them.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Student 1:</strong> Yes, that was unexpected for me as well. I think they should be just as respected as other works of fiction. <span style=\"background-color: #ffe786;\"><strong><span style=\"text-decoration: underline;\">(27/28) B (The argument that they are not literature).</span></strong></span></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Student 2:</strong> Smith also mentioned that books from other countries are very popular here, even though they don’t show our daily life.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Student 1:</strong> I think that’s interesting, but it’s the same for adult fiction too—people want variety. What I didn’t realize is how fixed the number of pages is.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Student 2:</strong> <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>Me neither. I wasn’t expecting that. They’re so strictly limited to 32 pages. It’s important, so let’s include it. (27/28) A (Their standard length).</strong></span></p>\n<hr data-path-to-node=\"27\" />\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Student 1:</strong> Alright, now let’s think about other aspects of picture books we want to include in our presentation. How about the characters?</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Student 2:</strong> Okay, well, a lot of them feature animals or families, often in very traditional roles. But do you think we need to talk about that?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Student 1:</strong> For me, the main thing is that they are mostly printed as board books. The cardboard material makes it easy for young children to turn their pages.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Student 2:</strong> <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>I agree, and it’s essential for children to hold books and learn how they open at the front and that the text goes in a certain direction. (29/30) A (The material they are made from).</strong></span></p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Student 1:</strong> Good point. Why don’t we also discuss how culture is important in picture books, like the importance of respecting the elderly?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Student 2:</strong> <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>Yes, it’s probably different all over the world. (29/30) D (Cultural elements in them).</strong></span></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('a7ef976f-4dac-4372-ad3e-ad6422a26ffa', 'f1de6ed3-16ff-4f81-abc9-3da52eeb533d', 'radio', 'Questions 1–6', NULL, '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple-choice', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Early Maori healers learned their skills through studying written texts."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The first Europeans in New Zealand were surprised by how long the Maori lived."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": " Diseases of the gods were believed to be more serious than physical diseases."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The leaves of the pepper tree were used to treat toothache."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Western religion was one reason why traditional Maori medicine became less popular."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Modern day Maori healers often reach the same conclusion about the type of treatment which is best."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">1. Early Maori healers learned their skills through studying written texts.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng cuối và đoạn 8, dòng 2: “…schools of higher learning which had trained healers… training is highly variable, usually <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"145\">informal</strong>… knowledge and ability that has been <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"193\">passed down from their ancestors</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Hệ thống giáo dục của người Maori cổ đại là truyền miệng và thông qua các “ngôi trường học thuật cao” (houses of higher learning), không phải qua văn bản viết (<em data-path-to-node=\"7,2,0\" data-index-in-node=\"172\">written texts</em>). Thực tế, văn hóa Maori truyền thống là văn hóa truyền miệng trước khi người Châu Âu đến.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">2. The first Europeans in New Zealand were surprised by how long the Maori lived.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 1, dòng 3-5: “When Europeans first visited New Zealand, the average age of death for Maori adults was around 30. However… the people were fit and healthy…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nêu tuổi thọ trung bình của người Maori lúc đó là khoảng 30 tuổi và họ rất khỏe mạnh. Tuy nhiên, bài <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"124\">không đề cập</strong> đến việc người Châu Âu có “ngạc nhiên” (<em data-path-to-node=\"9,2,0\" data-index-in-node=\"177\">surprised</em>) về tuổi thọ này hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">3. Diseases of the gods were believed to be more serious than physical diseases.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3: “In Maori culture, illnesses were divided into diseases of the gods (mate atua) and physical diseases (mate tangata).”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ phân loại bệnh tật thành hai nhóm dựa trên nguồn gốc (tâm linh hay thể chất) chứ <strong data-path-to-node=\"11,2,0\" data-index-in-node=\"105\">không so sánh</strong> xem loại nào “nghiêm trọng hơn” (<em data-path-to-node=\"11,2,0\" data-index-in-node=\"152\">more serious</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">4. The leaves of the pepper tree were used to treat toothache.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, dòng 5-6: “People who had toothache were instructed to <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"74\">chew the leaves of this same tree</strong> [pepper tree], and this was found to be of considerable benefit.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông tin trong bài khớp hoàn toàn với câu hỏi: lá cây tiêu được dùng để trị đau răng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">5. Western religion was one reason why traditional Maori medicine became less popular.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 6-8: “…many Maori accepted this explanation [from Western missionaries] and <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"102\">turned to Christianity</strong>… the tradition of the Maori healer declined.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà truyền giáo phương Tây cho rằng bệnh tật lây lan là do người Maori không tin vào Kitô giáo. Khi các thầy thuốc bản địa không chữa được bệnh mới, người dân chuyển sang tôn giáo mới, dẫn đến sự suy giảm của y học truyền thống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">6. Modern day Maori healers often reach the same conclusion about the type of treatment which is best.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 8, dòng 6-7: “As a result, their modern day work has <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"69\">no standard system of diagnosis or widespread agreement about treatments</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “no widespread agreement” (không có sự thống nhất rộng rãi) trái ngược hoàn toàn với “reach the same conclusion” (đi đến cùng một kết luận). Các thầy thuốc hiện đại thử nghiệm và kết hợp nhiều phương pháp khác nhau nên không có tiêu chuẩn chung.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('ab887f9d-e29e-4056-8419-6ee3700bd77f', 'fcc1bf58-c30c-4ff6-8657-beb3e4887c03', 'matrix', 'Questions 19–21', NULL, '<p>Choose the correct business person, <strong>A</strong>–<strong>E</strong>, for each statement.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "Employees should be kept informed about business developments and performance", "correctCategoryLetter": "B"}, {"itemText": "Work output increases when employees have a good balance between company and family responsibilities", "correctCategoryLetter": "D"}, {"itemText": "It is critical to business success that all company members recognise that they matter", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "Jennifer West", "categoryLetter": "A"}, {"categoryText": "Stephen Harper", "categoryLetter": "B"}, {"categoryText": "Margaret Mills", "categoryLetter": "C"}, {"categoryText": "Victor Davies", "categoryLetter": "D"}, {"categoryText": "Hazel Gibbs", "categoryLetter": "E"}]}', '[{"content": "<h2 data-start=\"1999\" data-end=\"2028\"><strong data-start=\"2002\" data-end=\"2028\">19. B (Stephen Harper)</strong></h2>\n<p data-start=\"2030\" data-end=\"2066\"><strong data-start=\"2030\" data-end=\"2041\">Vị trí:</strong> Đoạn B, phần đầu đoạn.</p>\n<p data-start=\"2068\" data-end=\"2251\"><strong data-start=\"2068\" data-end=\"2082\">Dẫn chứng:</strong><br data-start=\"2082\" data-end=\"2085\" />“…every two weeks… they also get an update about the company, including who their new customers are, what successes they’ve had, and what challenges they are facing.”</p>\n<p data-start=\"2253\" data-end=\"2374\"><strong data-start=\"2253\" data-end=\"2268\">Giải thích:</strong><br data-start=\"2268\" data-end=\"2271\" />Harper đảm bảo nhân viên được cập nhật thường xuyên về tình hình công ty → phù hợp với yêu cầu câu hỏi.</p>\n<hr data-start=\"2376\" data-end=\"2379\" />\n<h2 data-start=\"2381\" data-end=\"2409\"><strong data-start=\"2384\" data-end=\"2409\">20. D (Victor Davies)</strong></h2>\n<p data-start=\"2411\" data-end=\"2465\"><strong data-start=\"2411\" data-end=\"2422\">Vị trí:</strong> Đoạn C, câu trích dẫn của Victor Davies.</p>\n<p data-start=\"2467\" data-end=\"2607\"><strong data-start=\"2467\" data-end=\"2481\">Dẫn chứng:</strong><br data-start=\"2481\" data-end=\"2484\" />“…maintain equilibrium between work and home, a policy which ultimately results in a more productive and stable workforce.”</p>\n<p data-start=\"2609\" data-end=\"2720\"><strong data-start=\"2609\" data-end=\"2624\">Giải thích:</strong><br data-start=\"2624\" data-end=\"2627\" />Ông khẳng định cân bằng công việc – gia đình giúp tăng năng suất → đúng với nội dung câu hỏi.</p>\n<hr data-start=\"2722\" data-end=\"2725\" />\n<h2 data-start=\"2727\" data-end=\"2753\"><strong data-start=\"2730\" data-end=\"2753\">21. E (Hazel Gibbs)</strong></h2>\n<p data-start=\"2755\" data-end=\"2792\"><strong data-start=\"2755\" data-end=\"2766\">Vị trí:</strong> Đoạn D, phần giữa đoạn.</p>\n<p data-start=\"2794\" data-end=\"2905\"><strong data-start=\"2794\" data-end=\"2808\">Dẫn chứng:</strong><br data-start=\"2808\" data-end=\"2811\" />“…she works hard to ensure that everyone, from managers to workers, realizes that they count.”</p>\n<p data-start=\"2907\" data-end=\"3033\"><strong data-start=\"2907\" data-end=\"2922\">Giải thích:</strong><br data-start=\"2922\" data-end=\"2925\" />Gibbs nhấn mạnh tất cả nhân viên đều quan trọng → điều này rất cần thiết cho sự thành công của doanh nghiệp.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('fa333c49-8627-4eea-b144-9a04c35e42bb', 'f1de6ed3-16ff-4f81-abc9-3da52eeb533d', 'fillup', 'Questions 7–13', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write<strong> ONE WORD ONLY</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><span style="font-size: 12pt;"><strong>A short history of Maori healing</strong></span></p>
<p><strong>Pre-European arrival</strong></p>
<p>– Maori were using plant based remedies, as well as treatment including massage.</p>
<p>– Diseases sent from the gods were thought to be caused by disobeying a spiritual {rule}.</p>
<p>– Sickness could be attributed to eating food from a sacred {river} or burning sacred wood</p>
<p><strong>After European arrival</strong></p>
<p><strong>1800s</strong></p>
<p>– The inability of Maori healers to cure new diseases meant the Maori people lost <span class="fill-history-correct">{confidence}</span> in them.</p>
<p>– Eventually the {schools} for Maori healing began shutting down.</p>
<p><strong>1970s</strong></p>
<p>– Published {statistics} showed that Maori were not as healthy as Europeans.</p>
<p><strong>2000s</strong></p>
<p>– Maori healers can be seen working with Western doctors in {clinics} in cities.</p>
<p>– Many patients appreciate the fact that the Maoris {language} in used by healers.</p>
</div>
</div>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">7. rule</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3, dòng 2-3: “Diseases sent by the gods were often attributed to attacks by evil spirits, because the person had broken a religious <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"148\">rule</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bệnh do thần linh gửi đến được cho là hậu quả của việc vi phạm một quy tắc (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"88\">rule</strong>) tôn giáo hoặc tâm linh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">8. river</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3, dòng 4-5: “…if someone took food from a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"61\">river</strong> where someone had died… it was believed that the gods could punish them…”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc lấy thức ăn từ một con sông (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"46\">river</strong>) linh thiêng (nơi có người chết) được coi là hành động thiếu tôn trọng dẫn đến bệnh tật.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">9. confidence</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 3-4: “…this failure still strongly affected Maori <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"76\">confidence</strong> in their healers.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi các thầy thuốc bản địa không thể chữa được những căn bệnh mới từ Châu Âu, người Maori đã mất niềm tin (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"119\">confidence</strong>) vào họ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">10. schools</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 8-9: “Over time the <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"44\">schools</strong> of higher learning which had trained healers started to close…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Theo thời gian, những ngôi trường (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"47\">schools</strong>) đào tạo thầy thuốc bắt đầu bị đóng cửa, dẫn đến sự suy thoái của y học truyền thống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">11. statistics</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, dòng 3-4: “…<strong data-path-to-node=\"15,0,0\" data-index-in-node=\"33\">statistics</strong> from the 1970s came out revealing that Maori health continued to be poorer than that of other New Zealanders.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những số liệu thống kê (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"36\">statistics</strong>) được công bố vào những năm 1970 cho thấy tình trạng sức khỏe của người Maori vẫn kém hơn so với những người New Zealand khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">12. clinics</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 8, dòng 4-5: “Many modern healers work in urban <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"64\">clinics</strong>, some alongside mainstream health professionals.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hiện nay, nhiều thầy thuốc Maori làm việc tại các phòng khám (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"74\">clinics</strong>) ở thành phố, đôi khi kết hợp cùng với các bác sĩ Tây y.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">13. language</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 8, dòng cuối: “The Maori <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"41\">language</strong> is also seen as important by many of those receiving treatment.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những bệnh nhân hiện nay đánh giá cao việc ngôn ngữ (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"65\">language</strong>) Maori được các thầy thuốc sử dụng trong quá trình điều trị.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('e6d21059-8855-46b1-9cf4-bac5552789fd', 'd770d077-ae92-43bb-8e5b-9931487ac043', 'checkbox', 'Questions 27–28', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>points from Smith’s article about picture books did both speakers find surprising?</p>
', 'multiple_choice_many', 'null', '[{"option": "their standard length how recent the genre is", "correct": true}, {"option": "the argument that they are not literature", "correct": true}, {"option": "the lack of research about this age group", "correct": false}, {"option": "the popularity of books from overseas", "correct": false}, {"option": "the variety of versions", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('43bed505-ab7f-4782-a5c4-f7465d40c8c4', 'd770d077-ae92-43bb-8e5b-9931487ac043', 'checkbox', 'Questions 29–30', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>aspects of picture books do the speakers agree to talk about in their presentation?</p>
', 'multiple_choice_many', 'null', '[{"option": "the material they are made from", "correct": true}, {"option": "common characters in them", "correct": false}, {"option": "the variety of roles in them", "correct": false}, {"option": "cultural elements in them", "correct": true}, {"option": "the future of the genre", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('eb170a70-93ea-4999-83e3-eb1927815fa3', '44c4ef30-2cec-47f7-8de1-1d1eaf1297d0', 'matching', 'Questions 33–37', NULL, '<p>Complete the summery using the list of words, <strong>A-G,</strong> below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p class=\"ql-align-center\" style=\"text-align: center;\"><strong>Packaging design in the pharmaceutical industry</strong></p>\n<p><strong>Over-the-counter drugs</strong></p>\n<p>First, a proposal is written by the {E marketing team}. Then several designs are produced by the {C external design team} . Finally, selected designs are shown to {A consumers}.</p>\n<p><strong>Prescription-only drugs</strong></p>\n<p>The {D in-house design team} create the design. The design is then passed to {B design engineers}.</p>", "answerOptions": [{"optionText": "A consumers"}, {"optionText": "B design engineers"}, {"optionText": "C external design team"}, {"optionText": "D in-house design team"}, {"optionText": "E marketing team"}, {"optionText": "F pharmaceutical industry"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">33. E (marketing team)</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 5.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;The <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"16\">marketing team</strong> prepares the initial brief&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong bài, &#8220;initial brief&#8221; (bản tóm tắt yêu cầu ban đầu) tương ứng với &#8220;proposal&#8221; (đề xuất) trong câu hỏi. Đội ngũ marketing là bộ phận đưa ra yêu cầu này đầu tiên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">34. C (external design team)</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 3-4.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;these [over-the-counter medicines] are usually commissioned from an <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"83\">external design team</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Khác với thuốc kê đơn, thuốc không kê đơn cần sự bắt mắt nên thường được giao cho các đơn vị thiết kế bên ngoài thực hiện.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">35. A (consumers)</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 6-7.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Two or three of these [designs] are then tested on a <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"65\">consumer group</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi có các bản thiết kế, chúng sẽ được đem đi thử nghiệm trên các nhóm người tiêu dùng (consumers) để đánh giá hiệu quả.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">36. D (in-house design team)</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 8.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;In contrast, most designs for prescription-only products are created <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"81\">in-house</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đối với các sản phẩm thuốc kê đơn, quy trình thiết kế thường được thực hiện bởi đội ngũ thiết kế nội bộ (in-house design team) của chính công ty dược đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">37. B (design engineers)</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 9-10.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;applying the house design and then handing it over to <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"69\">design engineers</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi đội nội bộ hoàn tất thiết kế, họ sẽ chuyển giao (hand over) bản thiết kế đó cho các kỹ sư thiết kế (design engineers) để đưa vào sản xuất mà thường không qua bước thử nghiệm trên người dùng.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('5577ebcd-b414-45da-a84b-1ae3ba7aae9a', 'fcc1bf58-c30c-4ff6-8657-beb3e4887c03', 'fillup', 'Questions 22–26', '<p>Complete the summary. Write <strong>ONE WORD ONLY</strong> from the text for each answer.</p>
<p style="text-align: center;"><strong>Family-friendly practices at Plastic Solutions and the Margaret Mills Corporation</strong></p>
<p>At Plastic Solutions, a bi-weekly update is issued to workers at the same time as their pay. This includes a section dealing with problems such as {gossip} in communal areas of the workplace. The CEO also arranges a regular {seminar} for selected employees for workplace skills which are in great demand. Finally, employees’ families are invited to company open days, when they are allowed to try out the {machines}.</p>
<p>The Margaret Mills Corporation allows employees a degree of flexibility with their children, who can be brought to the office once {school} has finished. Mills likes to reward employees for company performance with a party or even a {trip} for families. There is considerable evidence that these practices are having the desired effect.<br /> </p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2 data-start=\"3064\" data-end=\"3081\"><strong data-start=\"3067\" data-end=\"3081\">22. gossip</strong></h2>\n<p data-start=\"3083\" data-end=\"3104\"><strong data-start=\"3083\" data-end=\"3094\">Vị trí:</strong> Đoạn B.</p>\n<p data-start=\"3106\" data-end=\"3159\"><strong data-start=\"3106\" data-end=\"3120\">Dẫn chứng:</strong><br data-start=\"3120\" data-end=\"3123\" />“This addresses issues like gossip…”</p>\n<p data-start=\"3161\" data-end=\"3234\"><strong data-start=\"3161\" data-end=\"3176\">Giải thích:</strong><br data-start=\"3176\" data-end=\"3179\" />Phần coaching đề cập đến vấn đề gossip ở khu vực chung.</p>\n<hr data-start=\"3236\" data-end=\"3239\" />\n<h2 data-start=\"3241\" data-end=\"3259\"><strong data-start=\"3244\" data-end=\"3259\">23. seminar</strong></h2>\n<p data-start=\"3261\" data-end=\"3282\"><strong data-start=\"3261\" data-end=\"3272\">Vị trí:</strong> Đoạn B.</p>\n<p data-start=\"3284\" data-end=\"3356\"><strong data-start=\"3284\" data-end=\"3298\">Dẫn chứng:</strong><br data-start=\"3298\" data-end=\"3301\" />“…monthly invitation-only Business Pragmatics seminar…”</p>\n<p data-start=\"3358\" data-end=\"3421\"><strong data-start=\"3358\" data-end=\"3373\">Giải thích:</strong><br data-start=\"3373\" data-end=\"3376\" />CEO tổ chức seminar hàng tháng cho nhân viên.</p>\n<hr data-start=\"3423\" data-end=\"3426\" />\n<h2 data-start=\"3428\" data-end=\"3447\"><strong data-start=\"3431\" data-end=\"3447\">24. machines</strong></h2>\n<p data-start=\"3449\" data-end=\"3470\"><strong data-start=\"3449\" data-end=\"3460\">Vị trí:</strong> Đoạn B.</p>\n<p data-start=\"3472\" data-end=\"3540\"><strong data-start=\"3472\" data-end=\"3486\">Dẫn chứng:</strong><br data-start=\"3486\" data-end=\"3489\" />“…kids can experiment with the company’s machines…”</p>\n<p data-start=\"3542\" data-end=\"3632\"><strong data-start=\"3542\" data-end=\"3557\">Giải thích:</strong><br data-start=\"3557\" data-end=\"3560\" />Gia đình nhân viên có thể thử máy móc của công ty trong ngày Open House.</p>\n<hr data-start=\"3634\" data-end=\"3637\" />\n<h2 data-start=\"3639\" data-end=\"3656\"><strong data-start=\"3642\" data-end=\"3656\">25. school</strong></h2>\n<p data-start=\"3658\" data-end=\"3679\"><strong data-start=\"3658\" data-end=\"3669\">Vị trí:</strong> Đoạn C.</p>\n<p data-start=\"3681\" data-end=\"3753\"><strong data-start=\"3681\" data-end=\"3695\">Dẫn chứng:</strong><br data-start=\"3695\" data-end=\"3698\" />“…have their children dropped off when school is over…”</p>\n<p data-start=\"3755\" data-end=\"3832\"><strong data-start=\"3755\" data-end=\"3770\">Giải thích:</strong><br data-start=\"3770\" data-end=\"3773\" />Trẻ em có thể được đưa đến công ty sau khi school kết thúc.</p>\n<hr data-start=\"3834\" data-end=\"3837\" />\n<h2 data-start=\"3839\" data-end=\"3854\"><strong data-start=\"3842\" data-end=\"3854\">26. trip</strong></h2>\n<p data-start=\"3856\" data-end=\"3877\"><strong data-start=\"3856\" data-end=\"3867\">Vị trí:</strong> Đoạn C.</p>\n<p data-start=\"3879\" data-end=\"3977\"><strong data-start=\"3879\" data-end=\"3893\">Dẫn chứng:</strong><br data-start=\"3893\" data-end=\"3896\" />“…the company took all employees and their families on a 2-day trip to Montreal…”</p>\n<p data-start=\"3979\" data-end=\"4052\"><strong data-start=\"3979\" data-end=\"3994\">Giải thích:</strong><br data-start=\"3994\" data-end=\"3997\" />Công ty thưởng bằng chuyến trip cho gia đình nhân viên.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('8611651a-a732-4025-bb67-d01c664e8da7', '547c171f-e381-4add-85b1-47cc2bee568a', 'fillup', 'Questions 7-13', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body" style="text-align: left;">
<p>Complete the notes below</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> from the passage for each answer.</p>
</div>
<p class="s-component-content s-font-body" style="text-align: center;"><strong>Katherine Mansfield’s adult years</strong>      <strong> </strong></p>
<div class="s-component-content s-font-body">
<p><strong>{1906}</strong></p>
<ul>
<li>
<p>Moved from England back to New Zealand.</p>
</li>
<li>
<p>First paid writing work was in a publication based in <strong> {Australia}</strong></p>
</li>
<li>
<p>Her <strong> {Family} </strong>and the New Zealand way of life made her feel dissatisfied.</p>
</li>
</ul>
<p>1908: Returned to London.</p>
<p>1911-1919:</p>
<ul>
<li>
<p>Met John Middleton Murry in 1911. </p>
</li>
<li><strong> {Bankruptcy} </strong>perverted Mansfield and Murry from staying together in Paris</li>
<li>
<p>Spent time with distinguished <strong> {Writers} </strong></p>
</li>
<li>
<p>From 1916, tuberculosis restricted the time she spent in London.</p>
</li>
</ul>
<p>1920:</p>
<ul>
<li>
<p>Her <strong>{Reputation}</strong> was consolidated when <em>Bliss and Other Stories</em> was published.Wrote several stories at “Villa Isola Bella.”1923-1924:</p>
</li>
<li>
<p>Mansfield’s <strong> {Husband}</strong> published more of her works after her death.</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">7. 1906</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 1-2.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “After finishing her schooling in England, she returned to her New Zealand home in <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"94\">1906</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản ghi rõ mốc thời gian bà rời Anh để quay về New Zealand là năm 1906.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">8. Australia</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “She had several works published in <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"47\">Australia</strong> in a magazine called Native Companion which was her first paid writing work…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công việc viết lách được trả lương đầu tiên của bà là cho một tạp chí nằm ở nước Úc (Australia).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">9. family</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 6.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Mansfield rapidly grew discontented with the provincial New Zealand lifestyle, and with her <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"104\">family</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “discontented with” đồng nghĩa với “dissatisfied” (không hài lòng/thất vọng). Hai thứ khiến bà không hài lòng là lối sống ở New Zealand và gia đình (family) của mình.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">10. bankruptcy</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 5-6.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Their attempt to set up as writers in Paris was cut short by Murry’s <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"81\">bankruptcy</strong>, which resulted from the failure of this and other journals.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc kinh doanh các tạp chí văn học thất bại đã dẫn đến sự phá sản (bankruptcy) của Murry, gây khó khăn cho cuộc sống của hai người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">11. writers</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 2.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “She and Murry developed close contact with other well-known <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"72\">writers</strong> of the time such as DH Lawrence…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Distinguished” (kiệt xuất/lừng danh) đồng nghĩa với “well-known”. Bà đã dành thời gian và giữ liên lạc mật thiết với những nhà văn (writers) nổi tiếng khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">12. reputation</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it was the publication of Bliss and Other Stories in 1920 that was to solidify Mansfield’s <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"106\">reputation</strong> as a writer.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Solidify” đồng nghĩa với “consolidated” (củng cố/làm vững chắc). Việc xuất bản tập truyện “Bliss and Other Stories” đã khẳng định vị thế và danh tiếng (reputation) của bà.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">13. husband</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn cuối, dòng 2-3.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “After her death her <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"32\">husband</strong>, Murry, took on the task of editing and publishing her works.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi bà qua đời, chính người chồng (husband) của bà là Murry đã tiếp tục biên tập và cho xuất bản các tác phẩm còn lại.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('15ee227b-7490-4362-9079-58df51a9d56a', '8756a7ff-0501-40fa-96a3-66b7c2fd933e', 'checkbox', 'Questions 17 and 18', '', '<p data-path-to-node="3">Choose <strong data-path-to-node="3" data-index-in-node="7">TWO</strong> letters, <strong data-path-to-node="3" data-index-in-node="20">A–E</strong>.</p>
<p data-path-to-node="4">Which <strong data-path-to-node="4" data-index-in-node="6">TWO</strong> reasons does the speaker give for recommending Alive and Kicking?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A It will appeal to both boys and girls."}, {"correct": false, "option_text": "B The author is well known."}, {"correct": false, "option_text": "C It has colourful illustrations."}, {"correct": false, "option_text": "D It is funny."}, {"correct": true, "option_text": "E It deals with an important topic."}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('065a6a05-f36e-4199-a989-4d2d0581497c', 'bd7e4e44-1351-4772-9ce8-f2b6d73ef0cc', 'fillup', 'Questions 24–26', '<p>Complete the sentences below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>In Japan, {paper} has been used as edible packaging for years.</p>
<p>Liquiglide reduces food waste, especially in bottles containing various {sauces}.</p>
<p>Tomorrow Machine is planning to use solid {sugar} as a container for oil.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<div class=\"flex flex-col text-sm pb-25\">\n<article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" dir=\"auto\" tabindex=\"-1\" data-turn-id=\"request-69861932-a1f4-839e-be3d-cf1ccf1fc500-45\" data-testid=\"conversation-turn-86\" data-scroll-anchor=\"true\" data-turn=\"assistant\">\n<div class=\"text-base my-auto mx-auto pb-10 [--thread-content-margin:--spacing(4)] @w-sm/main:[--thread-content-margin:--spacing(6)] @w-lg/main:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)\">\n<div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" tabindex=\"-1\">\n<div class=\"flex max-w-full flex-col grow\">\n<div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" dir=\"auto\" data-message-author-role=\"assistant\" data-message-id=\"13ad8cc0-d0f9-461b-8a9f-a95951e2c907\" data-message-model-slug=\"gpt-5-2\">\n<div class=\"flex w-full flex-col gap-1 empty:hidden first:pt-[1px]\">\n<div class=\"markdown prose dark:prose-invert w-full wrap-break-word light markdown-new-styling\">\n<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">24 In Japan, {paper} has been used as edible packaging for years.</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Cuối đoạn 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Even with these new advances, one decade-old edible invention continues to see great success – the <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"111\">clear paper</strong> used to wrap <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"136\">Japanese</strong> Botan Rice Candy.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đề cập đến một phát minh đã có từ hàng thập kỷ và vẫn đang thành công tại Nhật Bản, đó là loại <strong data-path-to-node=\"2,2,0\" data-index-in-node=\"115\">giấy (paper)</strong> trong suốt dùng để gói kẹo gạo (Botan Rice Candy) mà người dùng có thể ăn luôn được.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">25 Liquiglide reduces food waste, especially in bottles containing various {sauces}.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 1-3.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Another development has been nonstick packaging, which can eliminate the 3 to 15 percent of <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"104\">sauces</strong> left inside traditional bottles, like those last trails of ketchup and mayonnaise…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công nghệ Liquiglide tạo ra bề mặt siêu trơn giúp các loại <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"71\">nước sốt (sauces)</strong> như tương cà hay sốt mayonnaise không bị dính lại trong chai. Điều này giúp giảm thiểu đáng kể lượng thực phẩm bị lãng phí.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">26 Tomorrow Machine is planning to use solid {sugar} as a container for oil.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 4-5.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Tomorrow Machine, a Swedish design firm, has plans for three disappearing packages: an <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"99\">oil bottle</strong> made from <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"120\">hardened sugar</strong> that cracks open like an egg…”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công ty Tomorrow Machine đang lên kế hoạch cho các loại bao bì tự biến mất, trong đó có chai đựng dầu làm từ <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"121\">đường (sugar)</strong> đã được làm cứng (solid/hardened). Loại chai này có thể đập vỡ ra giống như vỏ trứng sau khi dùng xong.</p>\n</li>\n</ul>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</article>\n</div>\n"}]', 2);
INSERT INTO public.questions VALUES ('8c9430fd-93f6-4bd0-845a-4feef5996243', '5539b991-6bff-446d-b5a5-d8b6e57d59ac', 'matching', 'Questions 21–25', NULL, '<p>Choose the correct letter from A-G.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Analysis methods </strong></p>\n<p> </p>\n<p>PEST {C it does not fit our company}</p>\n<p> </p>\n<p>Drill Down {D it will take too long}</p>\n<p> </p>\n<p>PMI {E it is easy to use}</p>\n<p> </p>\n<p>Pareto {A it will save a lot of business time and effort}</p>\n<p> </p>\n<p>SWOT {G it is suitable to almost all sized companies}</p>\n<p> </p>", "answerOptions": [{"optionText": "A it will save a lot of business time and effort"}, {"optionText": "B it is visualized"}, {"optionText": "C it does not fit our company"}, {"optionText": "D it will take too long"}, {"optionText": "E it is easy to use"}, {"optionText": "F it is difficult to apply"}, {"optionText": "G it is suitable to almost all sized companies"}], "matchingItems": [{"questionPart": "PEST", "correctAnswer": "C it does not fit our company", "sectionContent": null}, {"questionPart": "Drill Down", "correctAnswer": "D it will take too long", "sectionContent": null}, {"questionPart": "PMI", "correctAnswer": "E it is easy to use", "sectionContent": null}, {"questionPart": "Pareto", "correctAnswer": "A it will save a lot of business time and effort", "sectionContent": null}, {"questionPart": "SWOT", "correctAnswer": "G it is suitable to almost all sized companies", "sectionContent": null}]}', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>PART 3</strong></p>\n<p class=\"MsoNormal\"><strong>Professor:</strong> Hi Francis, Sam. So, how did you go with applying the different theoretical business tools for the report I asked you to write?</p>\n<p class=\"MsoNormal\"><strong>Francis:</strong> It was interesting and made us really focus on which tool was best to use when analysing a business.</p>\n<p class=\"MsoNormal\"><strong>Professor:</strong> Good. So tell me what you found out.</p>\n<p class=\"MsoNormal\"><strong>Sam:</strong> <span style=\"text-decoration: underline; background-color: #ffe786;\">We liked the theory behind <strong>PEST</strong> analysis—that’s Political, Economic, Social and Technological—although we’re <strong>(21) not sure if it was very applicable to our case… I felt it focused too much on the big picture and was unsuitable for our company (C)</strong>.</span></p>\n<p class=\"MsoNormal\"><strong>Professor:</strong> I agree. On the other hand?</p>\n<p class=\"MsoNormal\"><strong>Francis:</strong><span style=\"text-decoration: underline; background-color: #ffe786;\"> I enjoyed using the <strong>Drill Down</strong> method. It was painstaking to do and <strong>(22) we seemed to be working on it for ages (D: take too long)</strong>, but the results were worth waiting for.</span></p>\n<p class=\"MsoNormal\"><strong>Professor:</strong> Yes, I liked the way it eventually broke down complex problems.</p>\n<p class=\"MsoNormal\"><strong>Sam:</strong> <span style=\"background-color: #ffe786;\"><span style=\"background-color: #ffffff;\">I much prefer doing the <span style=\"background-color: #ffe786;\"><strong>PMI</strong> </span>analysis. It was so straightforward to break down into its three components: Plus, Minus and Interesting implications</span>.</span><span style=\"text-decoration: underline; background-color: #ffe786;\"> You just needed to brainstorm these components and then write them up—fast and effective. <strong>(23) Anyone can use it (E: easy to use)</strong>.</span></p>\n<p class=\"MsoNormal\"><strong>Francis:</strong> I agree. So, was there any tool that you thought was superior to the others? In my opinion, the one tool that is critical to business, especially for larger companies, is <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong>Pareto</strong></span></span> analysis. If they apply Pareto analysis, they would see that by focusing on the critical 20% of their problems, they could generate 80% of the benefits. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(24) This would allow them to work faster and it also reduces their workload (A: save time and effort)</strong>.</span></p>\n<p class=\"MsoNormal\"><strong>Sam:</strong> I agree with Francis about Pareto, but my favourite was the <span style=\"background-color: #ffe786;\"><strong>SWOT</strong> </span>analysis—you know, looking at the company’s Strengths, Weaknesses, Opportunities and Threats. <strong><span style=\"text-decoration: underline; background-color: #ffe786;\">It can be used in so many different situations; (25) it works in large and small companies and even down to departmental level (G: suitable to almost all sized companies).</span></strong></p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\" />\n</div>\n<p class=\"MsoNormal\"><strong>Professor:</strong> Okay, I’ve read your draft report, but can you tell me a bit more about that company you focused on?</p>\n<p class=\"MsoNormal\"><strong>Francis:</strong> Well, the company we used in our study was a manufacturing company. We initially looked at their strengths. <span style=\"background-color: #ffe786;\"><strong><span style=\"text-decoration: underline;\">The management are committed and the company has a good reputation, but (26) the company has quite a lot of staff who have previously worked for distribution companies… that was something we didn’t expect to find and is probably going to help them the most (B: experienced employees).</span></strong></span></p>\n<p class=\"MsoNormal\"><strong>Professor:</strong> I was quite impressed by some of the opportunities you detailed. I did think you missed something quite pertinent to their future growth, however.</p>\n<p class=\"MsoNormal\"><strong>Sam:</strong> What was that?</p>\n<p class=\"MsoNormal\"><strong>Professor:</strong> <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong>(27) You didn’t consider the potential for establishing an offshore division (B: set up an overseas office)</strong>.</span></span> If the company had a way of actually distributing the product there, this could be a tremendous opportunity.</p>\n<p class=\"MsoNormal\"><strong>Francis:</strong> That’s a good point. So what did you think about the threats we identified?</p>\n<p class=\"MsoNormal\"><strong>Professor:</strong> I thought you did a good job. <span style=\"background-color: #ffe786;\"><strong><span style=\"text-decoration: underline;\">I was really pleased to see that you considered how the (28) government’s planned environmental policy could really affect the viability of this venture… with this law being introduced next year (C: new legislation).</span></strong></span></p>\n<p class=\"MsoNormal\"><strong>Sam:</strong> So Sam, what did you learn from this assignment?</p>\n<p class=\"MsoNormal\"><strong>Sam:</strong> Heaps, I guess.<span style=\"background-color: #ffe786;\"><strong><span style=\"text-decoration: underline;\"> It was great to study the different tools in books, but (29) applying them in the real world was much harder than I thought (C: gap between reality and theory).</span></strong></span> It was a great learning experience.</p>\n<p class=\"MsoNormal\"><strong>Professor:</strong> I’m basically happy with your report. You’ve got the format correct and sufficient details.<strong><span style=\"text-decoration: underline; background-color: #ffe786;\"> Just remember to (30) state whether or not you think the company should go ahead with the new venture (A: give a final determination). </span></strong>But you’ve done a good job so far.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('f6ce6ad5-8df5-46f0-acc5-2c8dc4051165', '8f9eec03-5894-4b7d-9b5a-ae64fd8c45a5', 'matrix', 'Questions 24–26', '', '<p>Choose the correct researcher, <strong>A</strong>–<strong>E</strong>, for each statement.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "It is likely that research into plant communication will one day help to improve our food supply", "correctCategoryLetter": "C"}, {"itemText": "Plant communication could occur as a consequence of internal mechanisms intended to help a single plant", "correctCategoryLetter": "A"}, {"itemText": "Attitudes towards plant communication have changed greatly in recent decades.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Richard Karban", "categoryLetter": "A"}, {"categoryText": "Ariel Novoplansky", "categoryLetter": "B"}, {"categoryText": "David Johnson", "categoryLetter": "C"}, {"categoryText": "Monica Gagliano", "categoryLetter": "D"}, {"categoryText": "Carel ten Cate", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">24. It is likely that research… will one day help to improve our food supply — {C} David Johnson</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “‘Applying our limited knowledge… to <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"50\">agriculture</strong> is a big jump,’ says <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"83\">Johnson</strong>, ‘but it is definitely on the horizon.’” (Đoạn 6)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">25. Plant communication could occur as a consequence of internal mechanisms… — {A} Richard Karban</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"22,0,0\" data-index-in-node=\"12\">Karban agrees</strong>, saying, ‘The interplant signaling we see may be a result of plants <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"94\">co-opting that process</strong> [within-plant signaling].’” (Đoạn 3)</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">26. Attitudes towards plant communication have changed greatly in recent decades — {B} Ariel Novoplansky</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “‘During my PhD [in the late 1980s], all this stuff was <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"67\">considered very weird</strong>,’ recalls <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"99\">Ariel Novoplansky</strong>. ‘Today, there is <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"135\">no doubt</strong>…’” (Đoạn 6)</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('7d94ca81-2f5a-449e-906c-306713e3b873', '3ecf8872-d7c3-42c4-9c47-39ce45a84315', 'fillup', 'Questions 1-10', '<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>The London Relocation Services</strong></span></p>
<p><strong>Customer’s name: </strong>Anna Woods</p>
<p><strong>Customer’s personal details</strong></p>
<p>– Current address 118 {Fordyce} Park, Ballysillan</p>
<p>– Postcode: BT149BJ</p>
<p>– Phone No: {07840051963} (Mobile)</p>
<p><strong>Other information</strong></p>
<p>– Anna is hoping to find work as a {nurse}</p>
<p>– She needs to find a {primary} school for her son</p>
<p><strong>Requirements for the new property</strong></p>
<p>Location</p>
<p>– Her preferred location is in the {south} of the city.</p>
<p>– Her husband would like to be new a {station}</p>
<p>– Her son would prefer to be close to a {park}</p>
<p>Property details:</p>
<p>– She would like to live in a {house}</p>
<p>– She would prefers {three | 3} bedrooms</p>
<p>– A small {office} is also desirable</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a telephone conversation between a woman who is moving to London and an employee of a relocation service. First you have some time to look at questions one to seven. Now listen carefully and answer questions one to seven.</p>\n<p data-path-to-node=\"4\"><strong>Daniel:</strong> London Relocation Services, Daniel speaking. How may I help you?</p>\n<p data-path-to-node=\"5\"><strong>Anna:</strong> Good morning. My family and I are moving to London later this year and I wonder if you can help.</p>\n<p data-path-to-node=\"6\"><strong>Daniel:</strong> Sure. First of all, I’ll need to get some personal details. May I take your full name please?</p>\n<p data-path-to-node=\"7\"><strong>Anna:</strong> It’s Anna Woods.</p>\n<p data-path-to-node=\"8\"><strong>Daniel:</strong> Thanks. Where are you moving from?</p>\n<p data-path-to-node=\"9\"><strong>Anna:</strong> Northern Ireland, just outside Belfast, actually.</p>\n<p data-path-to-node=\"10\"><strong>Daniel:</strong> Right. And what’s your current address?</p>\n<p data-path-to-node=\"11\"><strong>Anna:</strong> It’s 118 <strong>(1) Fordyce</strong> Park. I’ll spell that for you. It’s F-O-R-D-Y-C-E and that’s in Ballysillan.</p>\n<p data-path-to-node=\"12\"><strong>Daniel:</strong> And what’s the postcode?</p>\n<p data-path-to-node=\"13\"><strong>Anna:</strong> It’s <strong>(2) BT14 9BJ</strong>.</p>\n<p data-path-to-node=\"14\"><strong>Daniel:</strong> Alright. And could I take a contact phone number?</p>\n<p data-path-to-node=\"15\"><strong>Anna:</strong> I’ll give you my mobile number as you can get me on that anytime. It’s <strong>(3) 07840051963</strong>.</p>\n<p data-path-to-node=\"16\"><strong>Daniel:</strong> Great. Got that. Now we always like to get a bit more information about the families that we’re moving. It helps with the search. Are you moving for work?</p>\n<p data-path-to-node=\"17\"><strong>Anna:</strong> Yes, my husband’s just got a new job in London.</p>\n<p data-path-to-node=\"18\"><strong>Daniel:</strong> And what about you? Do you work?</p>\n<p data-path-to-node=\"19\"><strong>Anna:</strong> Well, I’ve been working as a teaching assistant recently. But I’m actually a qualified <strong>(4) nurse</strong>, and I’d like to get back into that if possible.</p>\n<p data-path-to-node=\"20\"><strong>Daniel:</strong> Right. And do you have any children?</p>\n<p data-path-to-node=\"21\"><strong>Anna:</strong> Yes, a son. So we need to find a school for him.</p>\n<p data-path-to-node=\"22\"><strong>Daniel:</strong> Is it a secondary school you’ll be looking for?</p>\n<p data-path-to-node=\"23\"><strong>Anna:</strong> No, he’s still in <strong>(5) primary</strong> school. He’s not quite at the secondary level yet.</p>\n<p data-path-to-node=\"24\"><strong>Daniel:</strong> Fine. So let’s go on to talk about your requirements for the property. Do you have a preferred location? Is your husband’s job in the center?</p>\n<p data-path-to-node=\"25\"><strong>Anna:</strong> No, it’s in East London, but we’d rather live somewhere quieter.</p>\n<p data-path-to-node=\"26\"><strong>Daniel:</strong> Sure. There are some lovely areas in the <strong>(6) South</strong>.</p>\n<p data-path-to-node=\"27\"><strong>Anna:</strong> OK, that sounds great. Now my husband doesn’t want to spend too long commuting to work every day.</p>\n<p data-path-to-node=\"28\"><strong>Daniel:</strong> So I imagine that ideally he’d like to be not too far from a <strong>(7) station</strong> then.</p>\n<p data-path-to-node=\"29\"><strong>Anna:</strong> Yes, he drives now, but I guess that’s not going to be possible and he’s not keen on buses.</p>\n<hr data-path-to-node=\"30\" />\n<p data-path-to-node=\"31\"><strong>Narrator:</strong> Before you hear the rest of the conversation, you have some time to look at questions eight to ten. Now listen and answer questions eight to ten.</p>\n<p data-path-to-node=\"32\"><strong>Daniel:</strong> Ohh what about you or your son? Do you have any preferences? Does your son do any sport for example?</p>\n<p data-path-to-node=\"33\"><strong>Anna:</strong> He’s quite active, so I’m sure he’d love a <strong>(8) park</strong> nearby to run around in. He doesn’t do swimming or anything like that.</p>\n<p data-path-to-node=\"34\"><strong>Daniel:</strong> Great. So what sort of property do you have in mind?</p>\n<p data-path-to-node=\"35\"><strong>Anna:</strong> We have friends who live in an amazing flat over there. But as we’ve always lived in a house, I think we’ll stick with that. We find it hard to adapt to a flat.</p>\n<p data-path-to-node=\"36\"><strong>Daniel:</strong> OK. And size wise, how many bedrooms would you like?</p>\n<p data-path-to-node=\"37\"><strong>Anna:</strong> Well, that’s just myself, my husband, and our son.</p>\n<p data-path-to-node=\"38\"><strong>Daniel:</strong> So you definitely need a two bedroom property, but how about having a guest room? <strong> </strong>I might be able to find <strong>(9)</strong> a <strong>three </strong>bedroom property for you.</p>\n<p data-path-to-node=\"39\"><strong>Anna:</strong> Yes, that would be ideal. We’re sure to have family visiting often.</p>\n<p data-path-to-node=\"40\"><strong>Daniel:</strong> All right, I’ve made a note of that now, are there any other requirements for your new property?</p>\n<p data-path-to-node=\"41\"><strong>Anna:</strong> Well, it’s not essential. But it would be handy to have a small <strong>(10) office</strong> for when my husband works from home. It doesn’t need to be a big one. I guess it all comes down to budget.</p>\n<p data-path-to-node=\"42\"><strong>Daniel:</strong> Yes. OK. Anna. Well, I’ve certainly got enough to be getting on with, and I will.</p>\n<p data-path-to-node=\"43\"><strong>Narrator:</strong> That is the end of Part One. You now have one minute to check your answers to Part One.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('a1e2c397-b60d-4ac1-9261-52e7535541fe', '39846273-f646-4c3c-8dc5-94351c2590f3', 'radio', ' Questions 27–30', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "They need to try harder to be different from one another."}, {"content": "They share a similar understanding of consumer psychology."}, {"content": "They depend too much on the latest technology."}, {"content": "They should do more to analyse how consumers think."}], "question": "What does the writer suggest about supermarkets in the first paragraph?"}, {"correct": 3, "options": [{"content": "to give customers time to decide what they want to buy."}, {"content": "to present customers with a range of interesting bargains."}, {"content": "to ensure customers feel under no pressure to buy anything."}, {"content": "to help customers slowly prepare themselves to go shopping."}], "question": "The writer says the function of the ‘chill zone’ in supermarkets is"}, {"correct": 0, "options": [{"content": "ensures the customers will feel good about the first products they buy."}, {"content": "reduces the risk of customers damaging these products later on."}, {"content": "encourages customers to buy more of these products than they intended."}, {"content": "makes customers consider healthier options in other sections they visit."}], "question": "According to the writer, placing fruit and vegetables near the front of the store"}, {"correct": 2, "options": [{"content": "They spend more time in stores than they realise."}, {"content": "They believe stores make life unnecessarily difficult for them."}, {"content": "They are aware of some of the techniques used by stores."}, {"content": "They are confused by frequent changes in the layout of stores."}], "question": "What point does the writer make about shoppers in the third paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27: What does the writer suggest about supermarkets in the first paragraph?</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"8\">They share a similar understanding of consumer psychology.</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1, dòng 3–5.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It is more that they are all <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"41\">well-versed in the science of persuading people to buy things</strong> – a science that… is beginning to understand what motivates consumers…”</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả bác bỏ ý kiến cho rằng các siêu thị thiếu sáng tạo khi trông giống hệt nhau. Lý do thực sự là họ đều am hiểu “khoa học thuyết phục” (tâm lý học khách hàng) để thúc đẩy việc mua sắm.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28: The writer says the function of the ‘chill zone’ in supermarkets is</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"8\">to help customers slowly prepare themselves to go shopping.</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 1–4.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It takes a while for the mind to get into a shopping mode. People need to make a <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"93\">gentle start and take stock of the surroundings</strong>. This is why some supermarkets have a so-called ‘chill zone’…”</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Tâm trí con người cần thời gian để chuyển sang “chế độ mua sắm”. Khu vực “chill zone” (đọc báo, xem DVD) giúp khách hàng bắt đầu một cách nhẹ nhàng trước khi thực sự đi vào các gian hàng chính.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29 According to the writer, placing fruit and vegetables near the front of the store</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"8\">ensures the customers will feel good about the first products they buy.</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 8–10.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…selecting wholesome fresh food is an <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"52\">uplifting way to start shopping</strong>, and it makes people <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"105\">feel less guilty</strong> about reaching for the less nutritious stuff later on.”</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc chọn thực phẩm tươi sạch ngay đầu buổi mua sắm tạo cảm giác phấn chấn (uplifting) và giúp khách hàng bớt thấy tội lỗi khi mua những đồ ăn kém lành mạnh sau đó.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30: What point does the writer make about shoppers in the third paragraph?</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"8\">They are aware of some of the techniques used by stores.</strong></span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 4–5.</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “But supermarkets <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"29\">know shoppers know this</strong>, so they use other tricks…”</span></p>\n<p><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Người mua hàng đã “nắm thóp” (worked out) được rằng các mặt hàng thiết yếu như sữa thường bị để ở cuối cửa hàng. Cụm từ “supermarkets know shoppers know this” khẳng định khách hàng có nhận thức về các kỹ thuật sắp đặt này.</span></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('ffe29dbc-4ab0-4808-bdc4-289aff939778', '08480964-6bd7-40c5-b5e0-227232a389bb', 'matrix', 'Questions 27-32', '', '<p>Which paragraph contains the following information?<br>Write the correct letter, <strong>A</strong>-<strong>F</strong>, in boxes 27-32 on your answer sheet.</p>
<p><strong>NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": " an explanation of why watching sport may be emotionally satisfying", "correctCategoryLetter": "F"}, {"itemText": "an explanation of why beginners find sporting tasks difficult", "correctCategoryLetter": "B"}, {"itemText": "a factor that needs to combine with mirroring to attain sporting excellence", "correctCategoryLetter": "E"}, {"itemText": "a comparison of human and animal mirror neurons", "correctCategoryLetter": "C"}, {"itemText": "the first discovery of brain activity related to mirror neurons", "correctCategoryLetter": "D"}, {"itemText": "a claim linking observation to improvement in performance", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. an explanation of why watching sport may be emotionally satisfying — {F}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This feeling also derives from mirror neurons. …they also allow us to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"84\">share in its feelings</strong>. This is because they are <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"132\">directly connected to the amygdala</strong>, one of the main brain regions involved in emotion.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F giải thích mối liên hệ giữa tế bào thần kinh gương và hạch hạnh nhân (amygdala), giúp người xem chia sẻ cảm xúc chiến thắng với vận động viên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. an explanation of why beginners find sporting tasks difficult — {B}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This is because most <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"33\">novices swing with their consciousness</strong>, using an area of brain next to the premotor cortex.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Người mới bắt đầu (novices) gặp khó khăn vì họ dùng ý thức để điều khiển hành động, thay vì dùng các phản xạ đã được “lập trình” trong vỏ não tiền vận động như các chuyên gia.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. a factor that needs to combine with mirroring to attain sporting excellence — {E}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The best athletes are those with a premotor cortex capable of imagining the movements… together with the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"119\">physical properties to make those movements real</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để đạt đến đỉnh cao, khả năng mô phỏng trong não bộ (mirroring) phải kết hợp với các <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"97\">tố chất thể chất</strong> thực tế.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. a comparison of human and animal mirror neurons — {C}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"12\">Humans have an even more elaborate mirror neuron system</strong> [than monkeys].”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C so sánh hệ thống tế bào thần kinh gương của người và khỉ, nhấn mạnh rằng ở người nó phức tạp và tinh vi hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. the first discovery of brain activity related to mirror neurons — {D}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This phenomenon of neural mirror was <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"49\">first discovered in 1954</strong>, when two French physiologists… found that the brains of humans vibrate with two distinct wavelengths…”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn D nhắc về mốc thời gian 1954 và phát hiện về sóng alpha/mu, tiền thân của các nghiên cứu về tế bào thần kinh gương sau này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">32. a claim linking observation to improvement in performance — {E}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It turns out that <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"30\">watching a great golfer makes us better golfers</strong>, and watching a great sprinter actually makes us run faster.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E khẳng định việc quan sát (watching/observation) giúp cải thiện kỹ năng thực tế của người xem.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('03893f30-0889-4fd8-b059-169f4c5da4f4', '5539b991-6bff-446d-b5a5-d8b6e57d59ac', 'radio', 'Questions 26–30', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "reputation"}, {"content": "experienced employees"}, {"content": "management"}], "question": "What does Frances consider as the best strength of the company?"}, {"correct": 1, "options": [{"content": "seek for cheaper suppliers"}, {"content": "set up an overseas office"}, {"content": "compete with major competitors"}], "question": "What factor did Sam overlooked for the future growth of the company?"}, {"correct": 2, "options": [{"content": "increasing competition"}, {"content": "outdated technology"}, {"content": "new legislation"}], "question": "Which of the following can be the threat to a company?"}, {"correct": 2, "options": [{"content": "using better tools"}, {"content": "cost of a success business"}, {"content": "gap between reality and theory"}], "question": "What has Sam learned from the research?"}, {"correct": 0, "options": [{"content": "give a final determination"}, {"content": "reorganize a clear structure"}, {"content": "add more detailed information"}], "question": "What is the professor’s suggestion for the report?"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('e0b602ec-14da-4d3b-91d2-30a93fa0ed88', '92d8da2a-515b-489e-8c21-b2b5bb0d952a', 'matrix', 'Questions 14-18', NULL, '<p>Which section contains the following information?</p>
<p>Choose the correct letter,<strong> A-G</strong></p>', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "a species that indicates to its young to move to a place where they are less visible", "correctCategoryLetter": "C"}, {"itemText": "an instance where sound is used to help an animal escape", "correctCategoryLetter": "G"}, {"itemText": "reature that can use camouflage to match a range of different backgrounds", "correctCategoryLetter": "D"}, {"itemText": "a claim that the majority of animals disguise themselves in some way", "correctCategoryLetter": "A"}, {"itemText": "examples of animals that use camouflage to look like plants", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">14. A species that indicates to its young to move to a place where they are less visible.</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: C</strong></li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"16\">C</strong>, dòng cuối: “…when the chicks land they are usually highly conspicuous, and their <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"102\">parents try to signal to them to move to a safe location</strong>.”</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “signal to them to move” tương ứng với “indicates to its young to move”. Loài chim Tawny Frogmouth (Cú muỗi mỏ quặp) cha mẹ sẽ ra hiệu cho con non di chuyển đến chỗ an toàn (ít bị lộ hơn).</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. An instance where sound is used to help an animal escape.</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: G</strong></li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"16\">G</strong>, dòng 4-5: “…in the case of the chameleon gecko the tail bones actually rub against one another, so <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"120\">it squeaks</strong>.”</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Loài tắc kè Chameleon gecko khi rụng đuôi, chiếc đuôi đó sẽ phát ra tiếng kêu “squeaks” (chít chít) để thu hút sự chú ý của kẻ thù, giúp nó trốn thoát.</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. A creature that can use camouflage to match a range of different backgrounds.</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: D</strong></li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"16\">D</strong>, dòng 1-3: “…some animals, such as the <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"59\">cuttlefish</strong>, have evolved an <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"87\">adaptable disguise</strong>… change its colour, Pattern and texture to match its surroundings…”</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Mực nang (cuttlefish) có khả năng thay đổi màu sắc và vân da ngay lập tức để phù hợp với nhiều môi trường khác nhau (<strong data-path-to-node=\"8,2,0\" data-index-in-node=\"129\">adaptable disguise</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. A claim that the majority of animals disguise themselves in some way.</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án: A</strong></li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"16\">A</strong>, dòng đầu tiên: “<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"35\">Most species use camouflage to some extent</strong>.”</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “Most species” đồng nghĩa với “the majority of animals”. Tất cả các loài đều ngụy trang ở một mức độ nào đó để sinh tồn.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. Examples of animals that use camouflage to look like plants.</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: B</strong></li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"16\">B</strong>, dòng 2-4: “…<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"33\">stick and leaf insects</strong> have evolved complex camouflage… Many have the texture of sticks or dry leaves, while others imitate living foliage…”</li>\n<li><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các loài côn trùng lá và côn trùng que bắt chước hình dạng của cành cây hoặc lá khô để ẩn mình.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('932b20e4-48d6-4fd7-ad96-fdbde7b90e75', '8864f5c7-792f-4620-96a3-d67362c2b7c9', 'fillup', ' Questions 31–40', '<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p style="text-align: left;"><strong>GAMIFICATION</strong></p>
<p><strong>What is it?</strong></p>
<p>– The use of gaming techniques in non-game situations</p>
<p>– In business, it is frequently used for {marketing}</p>
<p>– Uses people’s desire to win a reward</p>
<p>– Not a new idea, e.g. incentive schemes were first used by {airlines}</p>
<p><strong>Uses</strong></p>
<p>– To get online {feedback} quickly</p>
<p>– To persuade people to change their {behavior | behaviour}</p>
<p>– For training purposes, e.g. simulators used by {pilots} and town planners</p>
<p><strong>Successful examples</strong></p>
<p>– Official campaigns</p>
<p>– Australian government: to encourage people to {exercise} more</p>
<p>– overseas local authority: to reward drivers for not speeding</p>
<p><strong>Health</strong></p>
<p>– a staircase at a station that worked like a {piano}</p>
<p>– a game that helps recovery when old people hurt their {hand} in a fall</p>
<p><strong>Things to consider</strong></p>
<p>– It’s important for gamification to be {fun}</p>
<p>– Need to think about the laws regarding {privacy}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>SECTION 4</strong></p>\n<p class=\"MsoNormal\"><strong>Lecturer:</strong> Today we are going to look at how the phenomenon known as gamification has really exploded in recent years. So what exactly is gamification? It has been defined as the use of games thinking and mechanics in non-game situations, such as for business. Up to now, its most common function has been <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(31) marketing</strong>.</span> It is extremely popular with big companies, but as we&#8217;ll see, it also has many other uses.</p>\n<p class=\"MsoNormal\">Gamification techniques work on our natural desire for competition. One way they do this is by providing a reward—for example, badges or points, or providing a type of virtual currency. But don&#8217;t be fooled into thinking the concept is a novel one. Just think of the frequent flyer incentive schemes that were initiated by <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(32) airlines</strong></span> to try and retain customers. In fact, it&#8217;s been around for years; however, it has become more prolific with advances in technology.</p>\n<p class=\"MsoNormal\">So how is gamification being used? Well, it is seen as an excellent way of obtaining almost instantaneous <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(33) feedback</strong></span> through common social media sites. However, there are other areas where it is increasingly being used. In particular, as a means of trying to convince people through fun activities to alter their <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(34) behaviour</strong></span> <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\">(hoặc <strong>behavior</strong>). </span></span>Another use is in education or training in the workplace, especially when it is just not feasible to train people on the real thing. Good examples of this are the aircraft simulators used by <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(35) pilots</strong></span> or the urban simulators used by town planners.</p>\n<p class=\"MsoNormal\">So let&#8217;s look at a few examples of the successful implementation of gamification. One perhaps surprising use of gamification has been in official campaigns by governments and authorities, who have quickly seen its potential. In Australia, the government developed a smartphone app called &#8220;MyFitBuddy&#8221;, whose aim was to help people get off the sofa and <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(36) exercise</strong> </span>more. The app provided plenty of motivational content to ensure people got the encouragement they needed to increase their levels of activity.</p>\n<p class=\"MsoNormal\">Overseas, in one city, instead of just punishing the drivers caught driving too fast, a local authority conducted a trial where they rewarded good drivers with free entries into a draw. The trial was so successful that it resulted in a 22% reduction in speeding.</p>\n<p class=\"MsoNormal\">Gamification is also playing its part in helping people make healthy choices. In an attempt to get commuters to walk instead of using the escalators in an underground station, the staircase next to it was transformed into a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(37) piano</strong></span>. It had a touchpad underneath which played notes as people stepped on it. When it was in use, almost everyone opted to use the stairs instead of the escalator.</p>\n<p class=\"MsoNormal\">Another example is a medical research company in Australia. They realized the potential of gamification to help the elderly recover much more quickly from accidents. When the elderly fall, the most common injury is not to the arm or the leg, but to the<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong>(38) hand</strong>.</span></span> So they took an already popular computer game which involved people smashing fruit and adapted it so patients could practice their fine motor skills in a fun way.</p>\n<p class=\"MsoNormal\">Now there are a number of things to consider when using gamification. First of all, there is no way it can work unless it is <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(39) fun</strong>.</span> In fact, without that element, it could have the complete opposite effect on the consumer. In addition, as companies are often obtaining a lot more personal information and data on their customers this way, they should always be mindful of their legal obligations in terms of legislation relating to <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(40) privacy</strong>.</span></p>\n<p class=\"MsoNormal\">So now, it&#8217;s over to you to think of other examples of gamification that you might have come across&#8230;</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('f1cad28a-5757-4c19-b31d-4e3c96683d55', '11729290-561e-491a-86c6-9f961c1f0330', 'matching', 'Questions 21–26', NULL, '<p>What do the students say about each of the following websites?</p>
<p>Choose SIX correct answers, A-H, next to questions 21-26.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Websites</strong></p>\n<p> </p>\n<p>National Geographic {C. Contains a useful tool for users}</p>\n<p> </p>\n<p>United Nations {A. Information is not freely accessible}</p>\n<p> </p>\n<p>Energy Information Administration {G some information is missing}</p>\n<p> </p>\n<p>British Petroleum {B. Too detailed for their purposes}</p>\n<p> </p>\n<p>Central Intelligence Agency {E. Up-to-date information}</p>\n<p> </p>\n<p>World Bank {H useful historical information}</p>", "answerOptions": [{"optionText": "A. Information is not freely accessible"}, {"optionText": "B. Too detailed for their purposes"}, {"optionText": "C. Contains a useful tool for users"}, {"optionText": "D. Convenient format"}, {"optionText": "E. Up-to-date information"}, {"optionText": "F difficult to navigate"}, {"optionText": "G some information is missing"}, {"optionText": "H useful historical information"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear two students called Charlie and Delia discussing a joint assignment for their human Geography course. First you have some time to look at questions 21 to 26 on page five. Now listen carefully and answer questions 21 to 26.</p>\n<p><strong>Charlie:</strong> Hi Delia, shall we get down to planning our assignment? We haven’t got long now before the deadline.</p>\n<p><strong>Delia:</strong> I know, and it’s quite open ended, isn’t it? Just research and analyse data about energy consumption in a given region.</p>\n<p><strong>Charlie:</strong> Yes, and all we’ve done so far is check out a few likely websites. Shall we exchange ideas about those first? Hmm, good idea. Let me look at my notes.</p>\n<p><strong>Charlie:</strong> Okay. I had a preliminary look at one or two websites. There was National Geographic. The thing there that struck me was a facility for creating tailor made maps. We might like to use that when it comes to presenting our findings. <strong>(21) (C)</strong>.</p>\n<p><strong>Delia:</strong> Right, that would make some types of data instantly clear. My guess also I checked out the United Nations website. That one had masses of useful stuff.</p>\n<p><strong>Charlie:</strong> Only I couldn’t get at it. <strong>(22) I know, it was for subscribers only (A)</strong>.</p>\n<p><strong>Delia:</strong> Right, and we don’t want to get into that sort of thing. After all, it’s not a major piece of work we’re doing.</p>\n<p><strong>Charlie:</strong> Yes, I agree. I looked at the website of an agency called the Energy Information Administration. There were some population statistics there that we could use, but <strong>(23) there didn’t seem to be any figures for energy use (G)</strong>. So that site would only be suitable to a limited extent for our purposes.</p>\n<p><strong>Delia:</strong> I thought the British Petroleum website might be a good place to get information about energy use.</p>\n<p><strong>Charlie:</strong> Oh, good thinking. There was lots of data actually. Uh, the only thing is <strong>(24) it went into more depth than was necessary for our assignment (B)</strong>, and we’d have to collate a lot of the figures to arrive at an overview. So I didn’t think it was quite what we were looking for.</p>\n<p><strong>Delia:</strong> I also looked on the Central Intelligence Agency website.</p>\n<p><strong>Charlie:</strong> Hmm, I never had thought of that. Something worth noting: <strong>(25) it seemed to be the only place I looked at that had data for this current year (E)</strong>.</p>\n<p><strong>Delia:</strong> Oh, right. I’m not sure about the websites I looked at. I didn’t look carefully enough, I guess. And I also found stuff on the World Bank site, and that had <strong>(26) figures going back quite a long way (H)</strong>. Okay.</p>\n<hr />\n<p><strong>Narrator:</strong> Before you hear the rest of the discussion, you have some time to look at questions 27 to 30 on page six. Now listen and answer questions 27 to thirty.</p>\n<p><strong>Charlie:</strong> Fine. We know roughly what we’re doing, but have you got any more definite thoughts about what our subject matter should be?</p>\n<p><strong>Delia:</strong> I think one thing we’ve got to be careful about is biting off more than we can chew. <strong>(27/28) </strong></p>\n<p><strong>Charlie: Yes (B)</strong>, especially as it doesn’t count towards our final assessment anyway.</p>\n<p><strong>Delia:</strong> So shall we just limit it to data about population size and energy consumption?</p>\n<p><strong>Charlie</strong>: How about if we add in one other factor: carbon emissions? I think it would be interesting to see what the interaction between those three factors is like.</p>\n<p><strong>Delia:</strong> Okay, but in that case, we originally planned to stick to countries in North and South America, but what if we narrowed it down further?</p>\n<p><strong>Charlie: </strong>I’d be happy with that. How about let’s say 20 countries in all—<strong>the top 10 consumers of energy in the region and also the bottom ten (D)</strong>? <strong>(27/28)</strong></p>\n<p><strong>Delia:</strong> Hmm, sounds good. And we can calculate per capita consumption and per capita emissions to allow valid comparisons.</p>\n<p><strong>Charlie: </strong>Actually, it would be interesting to look at a breakdown of the types of energy each of those countries uses. You know, how much coal, how much wind power, how much nuclear power, and so on.</p>\n<p><strong>Delia: </strong>But we did just agree to restrict our data.</p>\n<p><strong>Charlie:</strong> I know. And then what about the way we present our data? Our tutor said that’s one of the things she’ll be looking at in particular, especially our graphics. Don’t you think a bar chart would be more effective than a set of tables with figures?</p>\n<p><strong>Delia:</strong> It might, but I’ve got another idea. I’m keen to display our data on a map instead.  We can easily find a software program to do that</p>\n<p><strong>Charlie:</strong> Brilliant, thanks.</p>\n<p><strong>Delia: </strong>One last thing, Charlie, and then we better go away and get started. Who’s going to do what?</p>\n<p><strong>Charlie</strong>: Your math is better than mine, so <strong> [29B] </strong> <span style=\"background-color: #fecc02;\">I’ll volunteer to </span><span style=\"background-color: #fecc02;\">search out all of the raw data we need</span><strong> </strong>if you’re prepared to do the necessary number crunching.</p>\n<p><strong>Delia:</strong> Okay, but can you get them to me as soon as possible?</p>\n<p><strong>Charlie: </strong>I’ll do it tonight.</p>\n<p><strong>Delia:</strong> Okay. And I tell you what, since the graphics were my idea, I’ll take those on, <strong>[30E]</strong> <span style=\"background-color: #fecc02;\"> but do you mind doing the text? You’ve got a better way with words than I have. </span></p>\n<p><span style=\"background-color: #ffffff;\"><strong>Charlie:</strong> </span><span style=\"background-color: #fecc02;\">That’s okay with me, as long as you’ll agree to look over everything and give it the finishing touches before we hand it in.</span> <span style=\"background-color: #fecc02;\"><span style=\"background-color: #ffffff;\">I</span><span style=\"background-color: #ffffff;\">t’s a deal.</span></span> Shall we meet at the same time tomorrow or do…</p>\n<p><strong>Narrator:</strong> That is the end of Section 3. You now have half a minute to check your answers. Now turn to Section 4 on page 7.</p>\n<hr />\n<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">DỊCH TIẾNG VIỆT SECTION 3</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Người dẫn chương trình:</strong> Bạn sẽ nghe hai sinh viên tên là Charlie và Delia thảo luận về một bài tập nhóm cho khóa học Địa lý nhân văn của họ. Đầu tiên, bạn có một chút thời gian để xem các câu hỏi từ 21 đến 26 trên trang năm. Bây giờ, hãy nghe kỹ và trả lời các câu hỏi từ 21 đến 26.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Charlie:</strong> Chào Delia, chúng ta bắt đầu lập kế hoạch cho bài tập nhóm chứ? Không còn nhiều thời gian nữa là đến hạn chót rồi.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Delia:</strong> Tớ biết, và đề bài khá là mở, đúng không? Chỉ là nghiên cứu và phân tích dữ liệu về mức tiêu thụ năng lượng trong một khu vực nhất định.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Charlie:</strong> Đúng vậy, và tất cả những gì chúng ta đã làm cho đến nay là kiểm tra một vài trang web có khả năng. Chúng ta có nên trao đổi ý tưởng về những trang web đó trước không? Hừm, ý kiến hay đấy. Để tớ xem lại ghi chú của mình.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Charlie:</strong> Được rồi. Tớ đã xem sơ qua một hoặc hai trang web. Có trang National Geographic. <strong data-path-to-node=\"7\" data-index-in-node=\"90\">Điều làm tớ ấn tượng ở đó là tính năng tạo các bản đồ thiết kế riêng. Chúng ta có thể muốn sử dụng tính năng đó khi trình bày các kết quả nghiên cứu của mình. (21) (C).</strong></p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Delia:</strong> Đúng vậy, điều đó sẽ giúp một số loại dữ liệu trở nên rõ ràng ngay lập tức. Tớ cũng đã kiểm tra trang web của Liên Hợp Quốc. Trang đó có rất nhiều tài liệu hữu ích.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Charlie:</strong> <strong data-path-to-node=\"9\" data-index-in-node=\"9\">Chỉ có điều tớ không thể truy cập được. (22) Tớ biết, nó chỉ dành cho những người đăng ký (thuê bao) thôi (A).</strong></p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Delia:</strong> Đúng rồi, và chúng ta không muốn vướng vào những việc kiểu đó. Dù sao thì đây cũng không phải là một bài làm quá lớn.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Charlie:</strong> Ừ, tớ đồng ý. Tớ đã xem trang web của một cơ quan tên là Cơ quan Quản lý Thông tin Năng lượng. Có một số thống kê về dân số ở đó mà chúng ta có thể sử dụng, nhưng <strong data-path-to-node=\"11\" data-index-in-node=\"172\">(23) có vẻ như không có bất kỳ số liệu nào về việc sử dụng năng lượng cả (G).</strong> Vì vậy, trang web đó sẽ chỉ phù hợp ở một mức độ hạn chế cho mục đích của chúng ta thôi.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Delia:</strong> Tớ nghĩ trang web của British Petroleum có thể là một nơi tốt để lấy thông tin về việc sử dụng năng lượng.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Charlie:</strong> Ồ, nghĩ hay đấy. Thực ra có rất nhiều dữ liệu. Ừm, vấn đề duy nhất là <strong data-path-to-node=\"13\" data-index-in-node=\"79\">(24) nó đi sâu hơn mức cần thiết cho bài tập của chúng ta (B)</strong>, và chúng ta sẽ phải đối chiếu và tổng hợp rất nhiều con số để có được một cái nhìn tổng thể. Vì thế tớ không nghĩ đó chính xác là những gì chúng ta đang tìm kiếm.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Delia:</strong> Tớ cũng đã xem trên trang web của Cơ quan Tình báo Trung ương (CIA).</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Charlie:</strong> Hừm, tớ chưa bao giờ nghĩ đến trang đó. Có một điều đáng lưu ý: <strong data-path-to-node=\"15\" data-index-in-node=\"73\">(25) nó dường như là nơi duy nhất tớ xem qua có dữ liệu cho năm hiện tại này (E).</strong></p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Delia:</strong> Ồ, đúng rồi. Tớ không chắc về các trang web mà tớ đã xem. Tớ đoán là tớ đã không xem kỹ lắm. Và tớ cũng tìm thấy một số thứ trên trang của Ngân hàng Thế giới, và ở đó có <strong data-path-to-node=\"16\" data-index-in-node=\"177\">(26) các số liệu từ rất lâu về trước (H).</strong> Được rồi.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Người dẫn chương trình:</strong> Trước khi bạn nghe phần còn lại của cuộc thảo luận, bạn có một chút thời gian để xem các câu hỏi từ 27 đến 30 trên trang sáu. Bây giờ hãy nghe và trả lời các câu hỏi từ 27 đến 30.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Charlie:</strong> Được rồi. Chúng ta đã biết sơ bộ những gì mình đang làm, nhưng cậu có ý tưởng cụ thể nào hơn về chủ đề chính của chúng ta không?</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Delia:</strong> Tớ nghĩ có một điều chúng ta phải cẩn thận là đừng ôm đồm quá sức mình.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Charlie:</strong> Đúng vậy, đặc biệt là khi dù sao bài này cũng không tính vào điểm đánh giá cuối kỳ của chúng ta. <strong data-path-to-node=\"20\" data-index-in-node=\"106\">Vậy chúng ta chỉ giới hạn ở dữ liệu về quy mô dân số và mức tiêu thụ năng lượng thôi nhé? (27/28 – B)</strong></p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Delia:</strong> Hay là mình thêm một yếu tố nữa: khí thải carbon? Tớ nghĩ sẽ rất thú vị khi xem sự tương tác giữa ba yếu tố đó như thế nào.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Charlie:</strong> Được thôi, nhưng trong trường hợp đó, ban đầu chúng ta định chỉ chọn các quốc gia ở Bắc và Nam Mỹ, nhưng nếu chúng ta thu hẹp phạm vi hơn nữa thì sao?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Charlie/Delia (đoạn thảo luận):</strong> Tớ đồng ý với việc đó. <strong data-path-to-node=\"23\" data-index-in-node=\"55\">Hay là mình chọn tổng cộng 20 quốc gia đi – 10 nước tiêu thụ năng lượng nhiều nhất vùng và 10 nước tiêu thụ ít nhất (27/28 – D)?</strong></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Delia:</strong> Hừm, nghe hay đấy. Và chúng ta có thể tính toán mức tiêu thụ bình quân đầu người và lượng khí thải bình quân đầu người để có sự so sánh chính xác.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Charlie:</strong> Thực ra, sẽ rất thú vị nếu xem bảng phân tích các loại năng lượng mà mỗi quốc gia đó sử dụng. Cậu biết đấy, bao nhiêu than đá, bao nhiêu năng lượng gió, bao nhiêu năng lượng hạt nhân, vân vân.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Delia:</strong> Nhưng chúng ta vừa mới đồng ý là sẽ hạn chế dữ liệu mà.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Charlie:</strong> Tớ biết. Và còn cách chúng ta trình bày dữ liệu thì sao? Giáo viên hướng dẫn nói đó là một trong những phần cô ấy sẽ xem xét kỹ, đặc biệt là phần đồ họa của chúng ta. Cậu có nghĩ biểu đồ cột sẽ hiệu quả hơn một tập hợp các bảng số liệu không?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Delia:</strong> Có thể, nhưng tớ có ý khác. Tớ muốn hiển thị dữ liệu của chúng ta trên bản đồ hơn. Chúng ta có thể dễ dàng tìm thấy một phần mềm để làm việc đó.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Charlie:</strong> Tuyệt vời, cảm ơn nhé.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Delia:</strong> Một việc cuối cùng thôi Charlie, rồi chúng ta nên bắt đầu làm luôn. Ai sẽ làm việc gì đây?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Charlie:</strong> Toán của cậu giỏi hơn tớ, nên <strong data-path-to-node=\"31\" data-index-in-node=\"39\">[29-B] tớ sẽ tình nguyện tìm kiếm tất cả dữ liệu thô chúng ta cần</strong> nếu cậu sẵn sàng thực hiện việc tính toán số liệu cần thiết.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Delia:</strong> Được thôi, nhưng cậu có thể gửi chúng cho tớ càng sớm càng tốt không?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Charlie:</strong> Tớ sẽ làm ngay tối nay.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Delia:</strong> Được rồi. Và tớ bảo này, vì đồ họa là ý tưởng của tớ nên tớ sẽ đảm nhận phần đó, <strong data-path-to-node=\"34\" data-index-in-node=\"88\">nhưng cậu có phiền nếu viết phần văn bản không? [30-E]</strong> Cậu có khả năng diễn đạt ngôn từ tốt hơn tớ.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Charlie:</strong> <strong data-path-to-node=\"35\" data-index-in-node=\"9\">Tớ đồng ý thôi [30-E]</strong>, miễn là cậu đồng ý xem lại mọi thứ và hoàn thiện những bước cuối cùng trước khi chúng ta nộp bài. Chốt vậy nhé. Ngày mai chúng ta gặp nhau cùng giờ này nhé, hay là cậu…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('16c049fb-7c1a-43d0-b1ec-6aee6e5bc7e3', '3db83e53-a345-4780-b470-0f6519bc6860', 'radio', 'Questions 7–13', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": " TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "A group of professional researchers are in charge of the Brooklyn project."}, {"correct": 1, "options": [{"content": " TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "The Brooklyn project team carries out their assessment of stores without the owner’s knowledge."}, {"correct": 2, "options": [{"content": " TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "The Brooklyn project has experienced technical difficulties setting up the website."}, {"correct": 1, "options": [{"content": " TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "The city government has taken a considerable interest in the Brooklyn project website."}, {"correct": 0, "options": [{"content": " TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "Michele Ver Ploeg believes the Brooklyn project website should contain additional information."}, {"correct": 2, "options": [{"content": " TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "The rate of internet use in Brooklyn is unlikely to increase in the near future."}, {"correct": 0, "options": [{"content": " TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "Jeffrey Heehs would like more people to assist with the Brooklyn project research."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>7. A group of professional researchers are in charge of the Brooklyn project.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> “The Brooklyn project differs in that it’s run by a local core of five <strong>volunteers</strong> who have worked on the project for the past year, rather than trained, academic <strong>researchers</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong>Giải thích:</strong> Dự án do một nhóm tình nguyện viên địa phương thực hiện, chứ không phải các nhà nghiên cứu chuyên nghiệp được đào tạo.</p>\n</li>\n</ul>\n<p>8. The Brooklyn project team carries out its assessment of stores without the owner’s knowledge.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> “…simply go to individual stores with pre-printed surveys in hand, and once the <strong>storekeeper’s permission has been obtained</strong>, check off boxes on their list…”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong>Giải thích:</strong> Họ phải xin phép chủ cửa hàng trước khi đánh giá.</p>\n</li>\n</ul>\n<p>9. The Brooklyn project has experienced technical difficulties setting up the website.</p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> Văn bản mô tả công nghệ được sử dụng (mapping software, GPS-related smart phones, Google Maps, Open Street Map), nhưng không đề cập đến việc họ gặp khó khăn kỹ thuật (technical difficulties) khi thiết lập trang web.</p>\n</li>\n</ul>\n<p>10. The city government has taken a considerable interest in the Brooklyn project website.</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> “Their website <strong>hasn’t caught them much local or official attention yet</strong>, however.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Trang web chưa thu hút được nhiều sự chú ý từ chính quyền thành phố (official attention).</p>\n</li>\n</ul>\n<p>11. Michele Ver Ploeg believes the Brooklyn project website should contain additional information.</p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> “To make the map more helpful to both residents and policy makers, she would like to see <strong>price data for healthy products, too</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong>Giải thích:</strong> Michele Ver Ploeg muốn trang web có thêm dữ liệu về giá (additional information).</p>\n</li>\n</ul>\n<p>12. The rate of internet use in Brooklyn is unlikely to increase in the near future.</p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong>Dẫn chứng:</strong> Văn bản chỉ nêu ra số liệu hiện tại: một phần đáng kể cư dân Brooklyn không có internet và 8% dùng dial-up. <strong>Không có thông tin</strong> về xu hướng tăng hay giảm sử dụng internet trong tương lai gần.</p>\n</li>\n</ul>\n<p>13. Jeffrey Heehs would like more people to assist with the Brooklyn project research.</p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong>Dẫn chứng:</strong> “He also hopes warmer days in the spring will draw out <strong>fresh volunteers to spread awareness and to finish surveying</strong>, as they have about two-thirds of Brooklyn left to cover.”</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong>Giải thích:</strong> Jeffrey Heehs (người lãnh đạo dự án) hy vọng có thêm tình nguyện viên mới để hoàn thành khảo sát (assist with the research).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('e3d26042-0cb2-4d8e-87db-f7399cf281fc', '11729290-561e-491a-86c6-9f961c1f0330', 'checkbox', 'Questions 27–28', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>decisions do the students reach about the subject matter of their assignment?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. They will keep the assessment criteria in mind.", "correct": false}, {"option": "B. They will limit the scale of their investigation.", "correct": true}, {"option": "C. They will select countries from all over the world.", "correct": false}, {"option": "D. They will collect data about two groups of countries.", "correct": true}, {"option": "E. They will find figures for wind and nuclear power.", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('75ea984f-275f-4f51-9ea6-07b27ac2161c', '11729290-561e-491a-86c6-9f961c1f0330', 'checkbox', 'Questions 29–30', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>tasks will Charley be responsible for?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. reviewing the final draft", "correct": false}, {"option": "B. collecting basic figures", "correct": true}, {"option": "C. producing the graphics", "correct": false}, {"option": "D. processing the raw data", "correct": false}, {"option": "E. drafting the written sections", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('569fed5d-35d2-4b0b-bfd1-c40aec346226', 'fa1804ba-3de1-4dc1-9e8a-d40b824030ca', 'radio', 'Questions 21–25', NULL, '<p>Choose the correct answer.</p>
<p><span style="font-size: 12pt;"><strong>Group Project</strong></span></p>', 'multiple-choice', '[{"correct": 2, "options": [{"content": "A finished planting the experiment."}, {"content": "B taken an extended break."}, {"content": "C spent a lot of time in the laboratory."}], "question": "Jen states that Irene has recently"}, {"correct": 0, "options": [{"content": "A He is grateful for her contribution."}, {"content": "B He thinks she is stylish."}, {"content": "C He resents her avoiding lab work."}], "question": "What is Bill''s attitude toward Kim?"}, {"correct": 1, "options": [{"content": "A would be easier for boys good at maths."}, {"content": "B would fail without Kim and Irene''s input."}, {"content": "C is almost done because Kim has finished the data analysis."}], "question": "Jen believes that their project"}, {"correct": 1, "options": [{"content": "A she is always late with her work."}, {"content": "B she fails to keep in touch enough."}, {"content": "C she thinks the project is an easy grade."}], "question": "Bill and Jen are irritated with Linda because"}, {"correct": 1, "options": [{"content": "A is popular with everyone on the team."}, {"content": "B always reads all of her assignments."}, {"content": "C enjoys talking to Professor Cooper."}], "question": "Jen was asked to join the team because she"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: GROUP PROJECT</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Bill:</strong> What’s up, Jen? How are you?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Jen:</strong> Oh hey, Bill.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Bill:</strong> Where’s everybody else?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Jen:</strong> I don’t know, you’re the first to get here.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Bill:</strong> Well, I hope they don’t take too long. I have a class at noon.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Jen:</strong> Why don’t we at least discuss what we’ve completed and what’s left to do?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Bill:</strong> Sounds like a plan. Have you heard anything from Irene?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Jen:</strong> Yeah, Irene told me the experiment is just about done. <span style=\"text-decoration: underline;\"><span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"60\">(21) She’s been practically living in the lab the past week.</strong></span></span></p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Bill:</strong> Wow, we owe her a favor, don’t we?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Jen:</strong> You can say that again.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Bill:</strong> Has Kim been helping her? I thought that lab work was not her style.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Jen:</strong> Well, not so much in the lab, but she has started compiling the data for the analysis.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Bill:</strong> <strong data-path-to-node=\"15\" data-index-in-node=\"6\"><span style=\"text-decoration: underline; background-color: #f3db7b;\">(22) Kim is terrific</span>.</strong> I hate doing stats. I’ve always been bad at math.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Jen:</strong> I always thought there wasn’t anything to that &#8220;boys are good at math&#8221; theory, haha.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Bill:</strong> Yes, and I’m proof!</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Jen:</strong> Anyway, Kim hasn’t actually run the stats for the project yet since she still has to wait for the rest of the experiment data, but she’s ready to get started when we get the experiment done. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"18\" data-index-in-node=\"196\">(23) Seriously, without Irene and Kim, we’d be in trouble.</strong></span></p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Bill:</strong> Yeah, you’re right about that. So what about Linda? What’s she been up to?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Jen:</strong> Who knows? All she ever talks about is her fiancé. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"20\" data-index-in-node=\"56\">(24) I haven’t seen or heard from her all week.</strong></span></p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Bill:</strong> Well, I hope she turns up soon. We’ll need everyone if we’re going to get this done on time.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Jen:</strong> Yeah, and she knows that Professor Cooper is a hard grader of projects. I’m worried that Professor Cooper is not going to give us a passing grade anyway. We haven’t talked about the introduction yet. Have you finished reading those articles Professor Cooper gave us?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Jen:</strong> Bill, she gave us those two weeks ago!</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Bill:</strong> Hey, I’ve been busy and I haven’t&#8230;</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Jen:</strong> Come on, Bill!</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Bill:</strong> Oh Jen, you know we all depend on you for that. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"26\" data-index-in-node=\"54\">(25) You’re the only person I know that reads every assignment from beginning to end.</strong></span> You and Professor Cooper often have private discussions about readings in the middle of class.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Bill:</strong> I’m not complaining! That’s why all the rest of us asked you to be on our team.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Jen:</strong> Oh, so that’s why!</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Bill:</strong> Yeah.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Jen:</strong> So it wasn’t because I’m popular, huh?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Bill:</strong> Hey, you’re the best. No one’s gonna argue that.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Bill:</strong> Hey, I’m thirsty. You want something to drink?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Jen:</strong> No, I’m good.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Bill:</strong> Okay, I’ll be right back.</p>\n<hr data-path-to-node=\"35\">\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">ASSIGNING RESPONSIBILITIES</strong></p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Jen:</strong> They&#8217;re still not here?</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Bill:</strong> Nope, and I&#8217;ve got a class I gotta get to.</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Jen:</strong> Well, let&#8217;s divide up responsibilities, like who&#8217;s responsible for each section. It only makes sense that <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"39\" data-index-in-node=\"111\">(26) Irene writes up all the materials and methods</strong></span>, since she spent the most time with that.</p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Bill:</strong> Oh, that&#8217;s easy.</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Jen:</strong> Hey, didn’t you just say we owe her one?</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Bill:</strong> Yeah, yeah, you’re right. Irene can do the methodology section.</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Jen:</strong> Do you wanna do the results?</p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Bill:</strong> Not at all. I thought Kim would do that.</p>\n<p data-path-to-node=\"45\"><strong data-path-to-node=\"45\" data-index-in-node=\"0\">Jen:</strong> Just because she is good at stats, doesn&#8217;t mean she’ll be good at writing it up. And besides, you are the one good at copy editing.</p>\n<p data-path-to-node=\"46\"><strong data-path-to-node=\"46\" data-index-in-node=\"0\">Bill:</strong> Well, all the same, I think it’ll be easiest if <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"46\" data-index-in-node=\"54\">(27) she (Kim) does the results section.</strong></span> I’ll edit the whole report.</p>\n<p data-path-to-node=\"47\"><strong data-path-to-node=\"47\" data-index-in-node=\"0\">Jen:</strong> Come on, that’s asking a lot of you.</p>\n<p data-path-to-node=\"48\"><strong data-path-to-node=\"48\" data-index-in-node=\"0\">Bill:</strong> Well, what part are you gonna do, Jen?</p>\n<p data-path-to-node=\"49\"><strong data-path-to-node=\"49\" data-index-in-node=\"0\">Jen:</strong> Isn&#8217;t that obvious? Since I’m the one who does all the reading,</p>\n<p data-path-to-node=\"50\"><strong data-path-to-node=\"50\" data-index-in-node=\"0\">Bill:</strong> I’m sure<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"50\" data-index-in-node=\"15\">(28) you’ll (Jen) give us the best literature review.</strong> </span></span>We’re all counting on you for that.</p>\n<p data-path-to-node=\"51\"><strong data-path-to-node=\"51\" data-index-in-node=\"0\">Jen:</strong> I guess that leaves the discussion section and the bibliography.</p>\n<p data-path-to-node=\"52\"><strong data-path-to-node=\"52\" data-index-in-node=\"0\">Bill:</strong> Yeah, can you make suggestions on these?</p>\n<p data-path-to-node=\"53\"><strong data-path-to-node=\"53\" data-index-in-node=\"0\">Jen:</strong> Okay, but seriously, wouldn&#8217;t it make more sense if<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"53\" data-index-in-node=\"57\">(29) you (Bill) do the list of references?</strong></span></span></p>\n<p data-path-to-node=\"54\"><strong data-path-to-node=\"54\" data-index-in-node=\"0\">Jen:</strong> There are enough commas, capital letters, and parentheses to keep you happy in there, haha.</p>\n<p data-path-to-node=\"55\"><strong data-path-to-node=\"55\" data-index-in-node=\"0\">Bill:</strong> Yeah, you got a point. It sure does make sense that I do the bibliography&#8230;</p>\n<p data-path-to-node=\"56\"><strong data-path-to-node=\"56\" data-index-in-node=\"0\">Jen:</strong> I guess<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"56\" data-index-in-node=\"13\">(30) Linda could handle the discussion section</strong>,</span></span> even if she hasn’t been around much.</p>\n<p data-path-to-node=\"57\"><strong data-path-to-node=\"57\" data-index-in-node=\"0\">Bill:</strong> Yeah, but isn’t that like the most important section?</p>\n<p data-path-to-node=\"58\"><strong data-path-to-node=\"58\" data-index-in-node=\"0\">Jen:</strong> Well, what else is she going to do?</p>\n<p data-path-to-node=\"59\"><strong data-path-to-node=\"59\" data-index-in-node=\"0\">Bill:</strong> The whole paper? It’ll serve her right.</p>\n<p data-path-to-node=\"60\"><strong data-path-to-node=\"60\" data-index-in-node=\"0\">Jen:</strong> Then we’d all fail!</p>\n<p data-path-to-node=\"61\"><strong data-path-to-node=\"61\" data-index-in-node=\"0\">Bill:</strong> Okay, but I think we all should start messaging her to make sure she gets busy. The discussion section can be long.</p>\n<p data-path-to-node=\"62\"><strong data-path-to-node=\"62\" data-index-in-node=\"0\">Jen:</strong> What about the abstract?</p>\n<p data-path-to-node=\"63\"><strong data-path-to-node=\"63\" data-index-in-node=\"0\">Bill:</strong> You really don’t want me to do the abstract, do you?</p>\n<p data-path-to-node=\"64\"><strong data-path-to-node=\"64\" data-index-in-node=\"0\">Jen:</strong> That’s not the point. I just think that the abstract should be for whoever finishes first,</p>\n<p data-path-to-node=\"65\"><strong data-path-to-node=\"65\" data-index-in-node=\"0\">Bill:</strong> right.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('93d4c6c0-9ce1-434c-a7c4-dc357360e223', 'fe110040-9bd9-4b3e-a043-a7975f07dd37', 'matching', 'Questions 14–18', NULL, '<p>Choose the correct heading for each paragraph from the list of headings below</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i Historical reasons why interrupted sleep became uncommon"}, {"optionText": "ii Brain structures involved in sleep patterns"}, {"optionText": "iii Potential health issues related to sleep"}, {"optionText": "iv Famous cases in literature of sleep"}, {"optionText": "v An analysis of old documents to discover deep patterns"}, {"optionText": "vi Biological and environmental factors preventing people from falling asleep again"}, {"optionText": "vii Scientific evidence that divided sleep is a natural phenomenon"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>14. Paragraph A</strong></p>\n<ul>\n<li><strong>Đáp án: vii. Scientific evidence that divided sleep is a natural phenomenon</strong></li>\n<li><strong>Giải thích:</strong> Đoạn A mô tả thí nghiệm khoa học của Thomas Wehr, chứng minh rằng mô hình ngủ chia làm hai giai đoạn (divided sleep) là mô hình tự nhiên (natural) của con người khi không bị ánh sáng nhân tạo chi phối.</li>\n</ul>\n<p><strong>15. Paragraph B</strong></p>\n<ul>\n<li><strong>Đáp án: v. An analysis of old documents to discover deep patterns</strong></li>\n<li><strong>Giải thích:</strong> Đoạn B nói về nghiên cứu của nhà sử học Roger Ekirch, người đã phân tích hơn 500 tài liệu lịch sử (diaries, court recorders, medical books…) để khám phá ra mô hình ngủ phân đoạn.</li>\n</ul>\n<p><strong>16. Paragraph C</strong></p>\n<ul>\n<li><strong>Đáp án: i. Historical reasons why interrupted sleep became uncommon</strong></li>\n<li><strong>Giải thích:</strong> Đoạn C giải thích sự biến mất của giấc ngủ chia đoạn, gắn liền với <strong>cải tiến ánh sáng đường phố</strong> (street and home lighting) và sự trỗi dậy của <strong>văn hóa quán cà phê</strong> (coffee houses), khiến việc thức khuya trở nên phổ biến.</li>\n</ul>\n<p><strong>17. Paragraph D</strong></p>\n<ul>\n<li><strong>Đáp án: vi. Biological and environmental factors preventing people from falling asleep again</strong></li>\n<li><strong>Giải thích:</strong> Đoạn D thảo luận về nguyên nhân của chứng mất ngủ giữa đêm (<strong>sleep maintenance insomnia</strong>) là do sự <strong>ưa thích tự nhiên</strong> của cơ thể đối với giấc ngủ chia đoạn (biological factor) và <strong>tiếp xúc kéo dài với ánh sáng nhân tạo</strong> (environmental factor).</li>\n</ul>\n<p><strong>18. Paragraph E</strong></p>\n<ul>\n<li><strong>Đáp án: iii. Potential health issues related to sleep</strong></li>\n<li><strong>Giải thích:</strong> Đoạn E tập trung vào tác động tâm lý của việc lo lắng về giấc ngủ (có thể làm tăng stress) và dẫn lời Russell Foster nói rằng <strong>hơn 30% vấn đề y tế</strong> (<strong>medical problems/health issues</strong>) có liên quan trực tiếp hoặc gián tiếp đến giấc ngủ.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('b4f3dbe8-7775-4d30-a822-24c7c9c0239a', 'fe110040-9bd9-4b3e-a043-a7975f07dd37', 'matrix', 'Questions 19–23', NULL, '<p>Look at the following statements and the list of researchers below.</p>
<p>Match each statement with the correct researcher, A-E</p>
<p><em><strong>NB </strong>you may use any letter more than once.</em></p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "In certain historical periods, the threat of criminal danger led to segmented sleep\t", "correctCategoryLetter": "C"}, {"itemText": "Physicians should learn more about treating people with sleeping difficulties.\t", "correctCategoryLetter": "E"}, {"itemText": "Historically, when people experienced interrupted sleep, they used the waking period at night for different activities\t", "correctCategoryLetter": "B"}, {"itemText": "Technological changes in Europe made people more likely to sleep throughout the night.\t", "correctCategoryLetter": "B"}, {"itemText": "The belief that humans should have a long continuous sleep can be psychologically harmful\t", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "Thomas Wehr  ", "categoryLetter": "A"}, {"categoryText": "Roger Ekirch", "categoryLetter": "B"}, {"categoryText": "Craig Koslofsky", "categoryLetter": "C"}, {"categoryText": "Gregg Jacobs", "categoryLetter": "D"}, {"categoryText": "Russell Foster", "categoryLetter": "E"}]}', '[{"content": "<p><strong>19. In certain historical periods, the threat of criminal danger led to segmented sleep.</strong></p>\n<ul>\n<li><strong>Đáp án: C</strong> (Craig Koslofsky)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) Craig Koslofsky giải thích rằng <strong>“Associations with night before the 17th century were not good”</strong> và đường phố bị tội phạm chiếm đóng (<strong>“populated by thieves or worse”</strong>).</li>\n</ul>\n<p><strong>20. Physicians should learn more about treating people with sleeping difficulties.</strong></p>\n<ul>\n<li><strong>Đáp án: E</strong> (Russell Foster)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) Russell Foster nói rằng <strong>“sleep has been ignored in medical training, and there are very few countries where sleep is studied,”</strong> và cảm thấy điều này cần phải thay đổi (<strong>“He feels this needs to change”</strong>).</li>\n</ul>\n<p><strong>21. Historically, when people experienced interrupted sleep, they used the waking period at night for different activities.</strong></p>\n<ul>\n<li><strong>Đáp án: B</strong> (Roger Ekirch)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) Ekirch mô tả hoạt động giữa hai giấc ngủ: <strong>“read or wrote”</strong>, <strong>“think about and attempt to analyse their dreams”</strong>.</li>\n</ul>\n<p><strong>22. Technological changes in Europe made people more likely to sleep throughout the night.</strong></p>\n<ul>\n<li><strong>Đáp án: B</strong> (Roger Ekirch)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) Ekirch <strong>“attributes the initial shift to improvements in street and home lighting”</strong>. Ánh sáng (technological change) đã khiến thời gian nghỉ ngơi giảm xuống.</li>\n</ul>\n<p><strong>23. The belief that humans should have a long continuous sleep can be psychologically harmful.</strong></p>\n<ul>\n<li><strong>Đáp án: D</strong> (Gregg Jacobs)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) Gregg Jacobs nói rằng <strong>“If it makes people who wake up in the night anxious, as this anxiety can itself discourage sleep”</strong>. Niềm tin này gây lo lắng (psychologically harmful).</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('2d24ad4c-9fb0-4dca-9d6d-b1832dabe3b3', '8f3ec8e0-7acb-415d-93f9-9047eeb6fb48', 'fillup', 'Questions 8–13', '<p>Complete the notes below. Choose <strong>ONE WORD AND/OR A NUMBER</strong> from the passage for each answer.</p>
<h3 style="text-align: center;">Sydney Opera House</h3>
<p><strong>Final cost</strong></p>
<p>– 8 $ {102 million}</p>
<p><strong>Construction</strong></p>
<p>– A large platform acting as a base for the building</p>
<p>– Concrete panels used to make ‘shells’, which are covered in tiles</p>
<p>– Over a million tiles from {Sweden}</p>
<p>– {granite} from Australia covering the outside walls</p>
<p><strong>Use</strong></p>
<p>– More than 1,500 performances annually</p>
<p>– {4 | four} performing-arts companies have their home base at the Opera House</p>
<p><strong>Outside</strong></p>
<p>– A large {forecourt} , at the foot of a wide staircase</p>
<p><strong>Alterations</strong></p>
<p>– A colonnade was added in 2006</p>
<p>– Openings made the {harbor | harbour} visible from foyers</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"19\"><strong>8. Final cost <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> $102 million</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án:</strong> <strong>102 million</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “…having cost <strong>$102 million</strong>.”</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong>9. </strong>Over a million tiles from <span class=\"math-inline\" data-math=\"rightarrow\">-&gt;</span> <strong>Sweden</strong> ****</p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong>Đáp án:</strong> <strong>Sweden</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “The ‘shells’ are covered with 1,056,006 white and cream-coloured tiles manufactured in a factory in <strong>Sweden</strong>…”</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong>10. granite from Australia covering the outside walls</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong>Đáp án:</strong> <strong>granite</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “…the building’s exterior is mostly clad with <strong>granite</strong> quarried in Australia.”</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong>11. four performing-arts companies have their home base at the Opera House</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong>Đáp án:</strong> <strong>four</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “It hosts a large number of performing-arts companies, including the <strong>four resident companies</strong>…”</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong>12. A large forecourt, at the foot of a wide staircase</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong>Đáp án:</strong> <strong>forecourt</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 9) “There is a sizeable outdoor <strong>forecourt</strong> from which people ascend to the main entrance.”</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong>13. Openings made the harbor visible from foyers</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong>Đáp án:</strong> <strong>harbor</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 10) “…enabled theatre patrons to see the <strong>harbour</strong> for the first time from the theatre foyers.”</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('94dd6c78-262d-4553-8941-fdbb14fd4171', 'fa1804ba-3de1-4dc1-9e8a-d40b824030ca', 'matching', 'Questions 26–30', NULL, '<p>Which section will each of the following group members write up?</p>
<p>Choose <strong>FIVE </strong>correct letters.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Group members</strong></p>\n<p> </p>\n<p>Irene {F Methodology}</p>\n<p> </p>\n<p>Kim {G Results}</p>\n<p> </p>\n<p>Jen {E Literature review}</p>\n<p> </p>\n<p>Bill {C Bibliography}</p>\n<p> </p>\n<p>Linda {D Discussion}</p>", "answerOptions": [{"optionText": "A Abstract"}, {"optionText": "B Acknowledgements"}, {"optionText": "C Bibliography"}, {"optionText": "D Discussion"}, {"optionText": "E Literature review"}, {"optionText": "F Methodology"}, {"optionText": "G Results"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('fc0e3c51-7635-41cf-a9fa-0c95d81d3a59', '92d8da2a-515b-489e-8c21-b2b5bb0d952a', 'matrix', 'Questions 19-23', NULL, '<p>Look at the following statements (Questions 19-23) and the list of people below.</p>
<p>Match each statement with the correct person, <strong>A-F</strong></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "one species has a camouflage tactic that is not present from birth.", "correctCategoryLetter": "C"}, {"itemText": "Species that live in an ancient environment have become very effective at camouflaging themselves", "correctCategoryLetter": "B"}, {"itemText": "Part of an animals is left behind to distract predators.", "correctCategoryLetter": "F"}, {"itemText": "If it takes too long to find one kind of prey, animals will look for an alternative source food.", "correctCategoryLetter": "A"}, {"itemText": "Camouflage can involve copying a threatening type of animals.", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "Professor Mark Elgar", "categoryLetter": "A"}, {"categoryText": "Palu Zborowski", "categoryLetter": "B"}, {"categoryText": "Professor Gisela Kaplan", "categoryLetter": "C"}, {"categoryText": "Dr Karen Cheney", "categoryLetter": "D"}, {"categoryText": "Henry Bates", "categoryLetter": "E"}, {"categoryText": "Martyn Robinson", "categoryLetter": "F"}]}', '[{"content": "<p><strong data-path-to-node=\"15\" data-index-in-node=\"0\">19. One species has a camouflage tactic that is not present from birth.</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án: C (Professor Gisela Kaplan)</strong></li>\n<li><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"16\">C</strong>: “…says the frogmouth’s skill at camouflaging is <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"69\">learned behaviour</strong>… the ability to choose a backdrop… <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"126\">does not develop for 4-6 months</strong>.”</li>\n<li><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Giáo sư Kaplan cho biết kỹ năng chọn nền ngụy trang của chim Tawny Frogmouth là do học hỏi mà có, chứ không phải có sẵn từ lúc mới sinh.</li>\n</ul>\n<p><strong data-path-to-node=\"17\" data-index-in-node=\"0\">20. Species that live in an ancient environment have become very effective at camouflaging themselves.</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án: B (Paul Zborowski)</strong></li>\n<li><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"16\">B</strong>: “It’s an <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"28\">incredibly old habitat</strong> so the creatures have had a long time to adapt,’ Zborowski explains.”</li>\n<li><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Zborowski cho rằng môi trường sống cổ xưa giúp các sinh vật có nhiều thời gian để tiến hóa kỹ năng ngụy trang hoàn hảo.</li>\n</ul>\n<p><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. Part of an animal is left behind to distract predators.</strong></p>\n<ul data-path-to-node=\"20\">\n<li><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án: F (Martyn Robinson)</strong></li>\n<li><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"16\">G</strong>: “Robinson explains that if attacked, the chameleon gecko will <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"81\">drop off its tail</strong>, which will wriggle around on the ground… and the gecko can sneak away.”</li>\n<li><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Robinson giải thích về cơ chế rụng đuôi của tắc kè để đánh lạc hướng kẻ thù.</li>\n</ul>\n<p><strong data-path-to-node=\"21\" data-index-in-node=\"0\">22. If it takes too long to find one kind of prey, animals will look for an alternative source food.</strong></p>\n<ul data-path-to-node=\"22\">\n<li><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án: A (Professor Mark Elgar)</strong></li>\n<li><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"16\">A</strong>: “Camouflage <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"31\">increases the search time</strong> and, as a consequence, the predator will simply <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"105\">target another species</strong>…”</li>\n<li><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Giáo sư Elgar giải thích rằng ngụy trang làm tăng thời gian tìm kiếm, khiến kẻ săn mồi nản lòng và đi tìm con mồi khác dễ thấy hơn.</li>\n</ul>\n<p><strong data-path-to-node=\"23\" data-index-in-node=\"0\">23. Camouflage can involve copying a threatening type of animal.</strong></p>\n<ul data-path-to-node=\"24\">\n<li><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Đáp án: E (Henry Bates)</strong></li>\n<li><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"16\">E</strong>: “<strong data-path-to-node=\"24,1,0\" data-index-in-node=\"20\">Batesian mimicry</strong> refers to animals that gain protection from predators by <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"94\">imitating a dangerous organism</strong>…”</li>\n<li><strong data-path-to-node=\"24,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Henry Bates là người đưa ra thuyết bắt chước Batesian, trong đó loài hiền lành giả dạng loài nguy hiểm để tự vệ.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('1b5e4fbd-9480-42bb-83f0-49ae9cd31ab0', '08480964-6bd7-40c5-b5e0-227232a389bb', 'radio', 'Questions 33-35', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B</strong>, <strong>C </strong>or <strong>D</strong>.<br>Write your answers in boxes 33-35 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A a level of sporting skill."}, {"option_text": "B a system of words about movement."}, {"option_text": "C a pattern of connected cells."}, {"option_text": "D a type of golf swing."}], "question": "The writer uses the term ‘grammar of movement’ to mean"}, {"correct": 0, "options": [{"option_text": "A without conscious thought."}, {"option_text": "B by planning each phase of movement."}, {"option_text": "C without regular practice."}, {"option_text": "D by thinking about the actions of others."}], "question": "The writer states that expert players perform their actions"}, {"correct": 2, "options": [{"option_text": "A improve personal performance."}, {"option_text": "B feel linked with people of different nationalities."}, {"option_text": "C experience strong positive emotions."}, {"option_text": "D realize what skill consists of."}], "question": "The writer states that the most common motive for watching sport is to"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. The writer uses the term ‘grammar of movement’ to mean — {C} a pattern of connected cells.</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…inside these primate brains there were <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"54\">groups of cells</strong> that ‘store vocabularies of motor actions’. Just as there are <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"132\">grammars of movement</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Ngữ pháp của chuyển động” ở đây được dùng để ẩn dụ cho các mạng lưới tế bào thần kinh kết nối với nhau để lưu trữ các chuỗi hành động.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. The writer states that expert players perform their actions — {A} without conscious thought.</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “For him [the expert], the motor action has become memorized… He hits the ball with the tranquility of his <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"120\">perfected autopilot</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vận động viên chuyên nghiệp thực hiện hành động như một “chế độ lái tự động” (autopilot), tức là không cần suy nghĩ bằng ý thức (conscious thought).</p>\n</li>\n</ul>\n<div class=\"attachment-container search-images\"><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!---->\n<p> </p>\n<div class=\"image-container ng-star-inserted\" data-full-size-image-uri=\"https://encrypted-tbn3.gstatic.com/licensed-image?q=tbn:ANd9GcSXaKx7njOJYl9bwiPVMbZhLbw0aVSeWcTeYgnlZVvDq-pzdJs45UwRyDFEl7J9n5BjEMwacecRmzKiT2qQ1mOGg-J-9YwGzxnyAU6hf_hOvOhrbw0\">\n<div class=\"overlay-container ng-star-inserted\"><!---->\n<p> </p>\n<div class=\"licensed-image-source ng-star-inserted\"> </div>\n<p><!----><!----><!----></p>\n</div>\n<p><!----><!----></p>\n</div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n</div>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">35. The writer states that the most common motive for watching sport is — {C} experience strong positive emotions.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “But how many of us regularly watch sports in order to be a better athlete? <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"87\">Rather, we watch sport for the feeling, the human drama</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Động cơ chính không phải để học tập mà là để trải nghiệm cảm xúc và kịch tính của con người.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('085e4555-a462-4b36-82ec-77c567e45e66', '08480964-6bd7-40c5-b5e0-227232a389bb', 'radio', 'Questions 36-40', '', '<p>Choose<strong> YES </strong>if the statement is agrees with the claims of the writer ,<strong>NO </strong>if the statement contradicts the claims of the writer,<strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Inexpert sports players are too aware of what they are doing."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Monkeys have a more complex mirror neuron system than humans."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Looking at a photograph can activate mirror neurons."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": " Gastaut and Bert were both researchers and sports players."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The mu system is at rest when we are engaged in an activity."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">36. Inexpert sports players are too aware of what they are doing. — {YES}</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…most <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"20\">novices swing with their consciousness</strong>…” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc sử dụng ý thức quá nhiều đồng nghĩa với việc họ quá chú tâm/nhận thức rõ từng cử động mình đang làm, điều này cản trở sự mượt mà.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">37. Monkeys have a more complex mirror neuron system than humans. — {NO}</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"30,0,0\" data-index-in-node=\"12\">Humans have an even more elaborate</strong> mirror neuron system.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định hệ thống của người phức tạp hơn của khỉ, trái ngược hoàn toàn với câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">38. Looking at a photograph can activate mirror neurons. — {NO}</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “If we are staring at a <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"35\">photograph</strong>… our mirror neurons are <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"72\">totally silent</strong>.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tế bào thần kinh gương chỉ hoạt động khi thấy hành động thực tế, không phải ảnh tĩnh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">39. Gastaut and Bert were both researchers and sports players. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…two French physiologists, Gastaut and Bert, found that…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ giới thiệu họ là nhà sinh lý học, <strong data-path-to-node=\"34,1,0\" data-index-in-node=\"58\">không có thông tin</strong> họ có phải là người chơi thể thao hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">40. The mu system is at rest when we are engaged in an activity. — {YES}</strong></p>\n<ul data-path-to-node=\"36\">\n<li>\n<p data-path-to-node=\"36,0,0\"><strong data-path-to-node=\"36,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The mu system… <strong data-path-to-node=\"36,0,0\" data-index-in-node=\"29\">disappears</strong> [is quiet] whenever we do something active…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"36,1,0\"><strong data-path-to-node=\"36,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “disappears/quiet” tương ứng với trạng thái nghỉ (at rest) khi não bộ chuyển sang trạng thái thực hiện hành động.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('58c8da6a-5abd-4c2f-9723-dee6ef4d83c1', 'e505f1da-d83e-4a8e-a007-16d6e4790056', 'checkbox', 'Questions 21–22', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>points did students most frequently make about their musical background before staring a music degree?</p>
', 'multiple_choice_many', 'null', '[{"option": "A They had already composed music.", "correct": false}, {"option": "B They had several music qualifications", "correct": false}, {"option": "C They could play more than one instrument.", "correct": true}, {"option": "D They had performed in public.", "correct": true}, {"option": "E They had had piano lessons.", "correct": false}]', 'null', 'null', '[{"content": "<h3><strong>1. Bối Cảnh Âm Nhạc và Thói Quen Tập Luyện</strong></h3>\n<p>So Gareth, we need to organise the findings from our survey on music students for the final presentation. Yes, Lona, I think we’ve got some very interesting results. Obviously we need to start by saying that we interviewed all the third year students doing a music degree and state the objective of our research project, that is to find out about their attitudes to performing.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Vậy Gareth, chúng ta cần sắp xếp các phát hiện từ cuộc khảo sát sinh viên âm nhạc của chúng ta cho bài thuyết trình cuối cùng. Vâng, Lona, tôi nghĩ chúng ta đã có một số kết quả rất thú vị. Rõ ràng, chúng ta cần bắt đầu bằng cách nói rằng chúng ta đã phỏng vấn tất cả sinh viên năm thứ ba học ngành âm nhạc và nêu mục tiêu của dự án nghiên cứu, đó là tìm hiểu về thái độ của họ đối với việc biểu diễn.</p>\n</blockquote>\n<p>And then we should talk about the students’ musical backgrounds before coming to university. The most important points to make are that although most people have actually composed music during the course, that wasn’t the case when they arrived. And the other thing they had in common was the piano—well they’d had access to a piano at some point, but not all had studied it formally. I thought the most interesting finding was that before coming here, almost everyone was involved in a chamber orchestra or band or singing in a choir, and <strong>(21/22) playing in front of live audiences (D)</strong> but varying enormously in size. Some had only played in tiny venues. I think it’s worth saying that. OK. And as you might expect from people wanting to study music, they all had a degree of proficiency in <strong>(21/22) at least two instruments (C)</strong> but in most cases one of the instruments was dominant. Right.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Và sau đó, chúng ta nên nói về nền tảng âm nhạc của sinh viên trước khi vào đại học. Những điểm quan trọng nhất cần nêu là mặc dù hầu hết mọi người đã thực sự sáng tác nhạc trong khóa học, nhưng điều đó không xảy ra khi họ mới đến. Và điều khác mà họ có điểm chung là đàn piano—họ đã có cơ hội tiếp xúc với đàn piano vào một thời điểm nào đó, nhưng không phải tất cả đều đã học nó một cách chính thức. Tôi nghĩ phát hiện thú vị nhất là trước khi đến đây, hầu hết mọi người đều tham gia vào một dàn nhạc thính phòng, ban nhạc hoặc hát trong dàn hợp xướng, và <strong>(21/22) biểu diễn trước khán giả trực tiếp (D)</strong> nhưng quy mô rất khác nhau. Một số chỉ biểu diễn ở những địa điểm rất nhỏ. Tôi nghĩ điều đó đáng để nói. Được rồi. Và như bạn có thể mong đợi từ những người muốn học âm nhạc, tất cả họ đều có trình độ thành thạo về <strong>(21/22) ít nhất hai nhạc cụ (C)</strong> nhưng trong hầu hết các trường hợp, một trong các nhạc cụ là nổi trội hơn. Đúng.</p>\n</blockquote>\n<p>We need to talk about attitudes to music practice. The most striking thing here is that even students who you’d expect to practice for hours every day until they get it perfect, say it’s being <strong>(23/24) terrified of failing (C)</strong> that really makes them practice. I know, I’m the same. Me too. It’s interesting what was said about practicing alone; some people preferred that because they could focus more on their weak points, but that wasn’t a majority view. What most of them agree on is <strong>(23/24) that there’s nothing more rewarding than mastering something that’s really hard to learn (E)</strong>. That’s right.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Chúng ta cần nói về thái độ đối với việc luyện tập âm nhạc. Điều nổi bật nhất ở đây là ngay cả những sinh viên mà bạn mong đợi sẽ luyện tập hàng giờ mỗi ngày cho đến khi họ đạt đến độ hoàn hảo, lại nói rằng chính việc <strong>(23/24) sợ thất bại (C)</strong> mới thực sự khiến họ luyện tập. Tôi biết, tôi cũng vậy. Tôi cũng thế. Thật thú vị những gì đã được nói về việc luyện tập một mình; một số người thích điều đó hơn vì họ có thể tập trung nhiều hơn vào những điểm yếu của mình, nhưng đó không phải là quan điểm của đa số. Điều mà hầu hết họ đồng ý là <strong>(23/24) không có gì đáng giá hơn việc làm chủ được một thứ gì đó thực sự khó học (E)</strong>. Đúng vậy.</p>\n</blockquote>\n<hr />\n<h3><strong>2. Tiêu chí Lựa chọn Tác phẩm cho Biểu diễn Đánh giá</strong></h3>\n<p>Okay, after that, we should talk a bit about the pieces that students select for assessed performances. There wasn’t quite so much consensus on this, was there? A few people prefer to do pieces which are relatively unknown, while others choose the ones they think will show off their technical ability, but they were in the minority. I think the first thing to say is that a high percentage said they would always try to <strong>(25/26) learn their pieces by heart (C)</strong> because it’s too easy to get lost if you’re trying to read and play when you’re nervous. Okay, and quite a lot of them said it helps to <strong>(25/26) listen to other people playing (A)</strong> your chosen piece—preferably recordings, but even just other students.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Được rồi, sau đó, chúng ta nên nói một chút về các tác phẩm mà sinh viên chọn cho các buổi biểu diễn được đánh giá. Không có quá nhiều sự đồng thuận về điều này, đúng không? Một số người thích chọn các tác phẩm tương đối ít được biết đến, trong khi những người khác chọn những tác phẩm mà họ nghĩ sẽ thể hiện khả năng kỹ thuật của họ, nhưng họ chỉ là thiểu số. Tôi nghĩ điều đầu tiên cần nói là một tỷ lệ cao cho biết họ sẽ luôn cố gắng <strong>(25/26) học thuộc lòng các tác phẩm của mình (C)</strong> vì rất dễ bị lạc nếu bạn cố gắng đọc và chơi khi bạn lo lắng. Được rồi, và khá nhiều người trong số họ nói rằng việc <strong>(25/26) nghe người khác chơi (A)</strong> tác phẩm bạn đã chọn sẽ rất hữu ích—tốt nhất là bản ghi âm, nhưng ngay cả khi chỉ là những sinh viên khác.</p>\n</blockquote>\n<hr />\n<h3><strong>3. Thái độ đối với các Khía cạnh Biểu diễn</strong></h3>\n<p>So finally, we need to look at the findings for students’ attitudes to performing. We should point out that this includes informal and formal public performances as well as assessed ones. Yes, that’s important.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Vậy cuối cùng, chúng ta cần xem xét các phát hiện về thái độ của sinh viên đối với việc biểu diễn. Chúng ta nên chỉ ra rằng điều này bao gồm các buổi biểu diễn công khai không chính thức và chính thức cũng như các buổi biểu diễn được đánh giá. Vâng, điều đó quan trọng.</p>\n</blockquote>\n<p>I expected to find that <strong>(27) performing solo (B)</strong> would make students very nervous, but in fact that isn’t the case. They do find it hugely challenging to start with, but they appreciate the challenge and find it stimulating. Right.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Tôi đã mong đợi rằng <strong>(27) biểu diễn solo (B)</strong> sẽ khiến sinh viên rất lo lắng, nhưng thực tế không phải vậy. Họ thấy nó cực kỳ thử thách lúc đầu, nhưng họ đánh giá cao thử thách đó và thấy nó kích thích. Đúng.</p>\n</blockquote>\n<p>I was surprised by what students said about <strong>(28) deciding which pieces to perform (E)</strong>. I thought they’d all say this was easy. But the most commonly cited answer was that it took them ages to make their minds up. I suppose it’s because there are so many factors involved… and you can’t do that in a hurry. That’s true.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Tôi đã ngạc nhiên về những gì sinh viên nói về <strong>(28) việc quyết định tác phẩm nào để biểu diễn (E)</strong>. Tôi nghĩ tất cả họ sẽ nói rằng điều này rất dễ dàng. Nhưng câu trả lời được trích dẫn phổ biến nhất là họ mất rất nhiều thời gian để quyết định. Tôi đoán là vì có quá nhiều yếu tố liên quan… và bạn không thể làm điều đó một cách vội vàng. Đúng vậy.</p>\n</blockquote>\n<p>Then there’s <strong>(29) performing with musicians from a different genre (G)</strong>, like a classical musician playing with a jazz group. That can really be fun, but most of the music students had never even considered it. Right.</p>\n<blockquote>\n<p><strong>Dịch:</strong> Tiếp theo là <strong>(29) biểu diễn với các nhạc sĩ thuộc thể loại khác (G)</strong>, giống như một nhạc sĩ cổ điển chơi với một nhóm nhạc jazz. Điều đó thực sự có thể rất vui, nhưng hầu hết các sinh viên âm nhạc thậm chí chưa bao giờ xem xét nó. Đúng.</p>\n</blockquote>\n<p>For <strong>(30) performing with musicians who play the same instrument (A)</strong>, almost everyone put the same thing. Yes, they all said it was incredibly helpful and not at all intimidating. Which says a lot for the department’s ethos. Yes, that’s a good point. OK, what I think we should sort out now is…</p>\n<blockquote>\n<p><strong>Dịch:</strong> Đối với <strong>(30) biểu diễn với các nhạc sĩ chơi cùng nhạc cụ (A)</strong>, hầu như tất cả mọi người đều đưa ra cùng một ý kiến. Vâng, tất cả họ đều nói rằng nó cực kỳ hữu ích và hoàn toàn không đáng sợ. Điều đó nói lên nhiều điều về đạo đức của khoa. Vâng, đó là một điểm hay. Được rồi, điều tôi nghĩ chúng ta nên giải quyết bây giờ là…</p>\n</blockquote>\n<p><strong>Narrator:</strong> That is the end of Section 3. You now have half a minute to check your answers. Now turn to Section 4 on page seven.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('f8afddfb-fcdf-4264-83da-1121e5dcade5', 'e505f1da-d83e-4a8e-a007-16d6e4790056', 'checkbox', 'Questions 23–24', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO</strong> points did students most frequently make about music practice?</p>
', 'multiple_choice_many', 'null', '[{"option": "A They prefer to practise alone", "correct": false}, {"option": "B They try to practise every day", "correct": false}, {"option": "C They are motivated to practise by fear", "correct": true}, {"option": "D They feel they don’t do enough practice", "correct": false}, {"option": "E They enjoy the challenge of a difficult piece", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('579f31ca-f0c6-493a-a503-375a12a308d6', '136a6a3b-67a3-465a-a956-984c7b8ec061', 'matrix', 'Questions 14-17', NULL, '<p>Reading Passage 2 has six paragraphs <strong>A-F</strong>. Which paragraph contains the following information?</p>
<p>Choose the correct letter,<strong> A-F</strong>, in boxes 14-17.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "an explanation of research aimed at restoring the health of the heirloom tomato", "correctCategoryLetter": "F"}, {"itemText": "a reference to a false belief about the heirloom tomato", "correctCategoryLetter": "A"}, {"itemText": "a description of the flavour of the heirloom tomato", "correctCategoryLetter": "E"}, {"itemText": "a reference to a single gene that significantly improves the cultivation of tomatoes", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p>14. an explanation of research aimed at restoring the health of the heirloom tomato</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>F</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “In 1999 a tomato breeder… Doug Heath began a favorite project. After 12 years of traditional breeding with the help of molecular markers, <strong>he created a new multi-colored tomato less prone to cracking and also endowed with 12 disease-resistant genes</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Đoạn F mô tả nghiên cứu lai tạo kéo dài 12 năm của Doug Heath nhằm khôi phục các gen kháng bệnh (restoring the health) cho cà chua heirloom, tạo ra giống mới ít bị nứt và có nhiều gen kháng bệnh hơn.</p>\n</li>\n</ul>\n<p>15. a reference to a false belief about the heirloom tomato</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>A</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) “The tomato enthusiast might conclude that, given the immense varieties, heirlooms must base a more diverse and superior set of genes… <strong>However, their seeming diversity is only skin-deep: heirlooms are actually feeble and inbred</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Đoạn A bác bỏ niềm tin phổ biến (false belief) rằng cà chua heirloom có bộ gen đa dạng và vượt trội.</p>\n</li>\n</ul>\n<p>16. a description of the flavour of the heirloom tomato</p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “Any plant that produces only two fruits… is highly likely to produce <strong>juicier, sweeter and more flavorful fruit</strong> than varieties that produce 100, as commercial types do. In addition, heirlooms are sold <strong>ripened on the vine</strong>, a certain way to get tastier results…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Đoạn E mô tả chi tiết hương vị của cà chua heirloom (juicier, sweeter, more flavorful) và yếu tố môi trường ảnh hưởng đến hương vị đó.</p>\n</li>\n</ul>\n<p>17. a reference to a single gene that significantly improves the cultivation of tomatoes</p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “…Tanksley and his colleagues reported that they found <strong>a gene that increases fruit size by 50 percent</strong>. <strong>It was probably the most important event in domestication</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Đoạn D đề cập đến một gen duy nhất làm tăng đáng kể (significantly improves) kích thước quả cà chua lên 50%.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('242deb85-3cca-41e4-aa47-5e3cc3686cd8', 'e505f1da-d83e-4a8e-a007-16d6e4790056', 'checkbox', 'Questions 25–26', NULL, '<p>Choose <strong>TWO</strong> correct answers.</p>
<p>Which <strong>TWO</strong> points were most frequently made by students about the pieces they select for assessed performances?</p>
', 'multiple_choice_many', 'null', '[{"option": "A They like to hear others performing the same pieces.", "correct": true}, {"option": "B They like to choose little-known pieces", "correct": false}, {"option": "C They like to play pieces from memory", "correct": true}, {"option": "D They like their tutor to choose their pieces", "correct": false}, {"option": "E They like to choose technically demanding pieces.", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('e56f2ef3-53f6-4a0c-b0d0-3e5caaded2b0', '14815fc0-190d-428e-8381-a57bf6efce75', 'fillup', 'Questions 1–10', '<p data-start="94" data-end="169">Complete the notes below.</p>
<p data-start="94" data-end="169">Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p data-start="176" data-end="209"><strong>Shipping of personal belongings</strong></p>
<p data-start="211" data-end="223"><strong>Example</strong>:</p>
<p data-start="224" data-end="279">Special boxes for packing are provided free of charge.</p>
<p data-start="286" data-end="317"><strong>The company will transport:</strong></p>
<ul data-start="318" data-end="373">
<li data-start="318" data-end="360">
<p data-start="320" data-end="360">some electrical goods, e.g. a computer</p>
</li>
<li data-start="361" data-end="373">
<p data-start="363" data-end="373">a {bicycle}</p>
</li>
</ul>
<p data-start="380" data-end="415"><strong>The company will not transport:</strong></p>
<ul data-start="416" data-end="553">
<li data-start="416" data-end="464">
<p data-start="418" data-end="464">any single item weighing more than {40} kg</p>
</li>
<li data-start="465" data-end="511">
<p data-start="467" data-end="511">any {liquids} (for security reasons) or foods</p>
</li>
<li data-start="512" data-end="553">
<p data-start="514" data-end="553">anything in containers made of {plastic}</p>
</li>
</ul>
<p data-start="560" data-end="584"><strong>Additional services:</strong></p>
<ul data-start="585" data-end="678">
<li data-start="585" data-end="607">
<p data-start="587" data-end="607">special deliveries</p>
</li>
<li data-start="608" data-end="630">
<p data-start="610" data-end="630">delivery on {Saturdays}</p>
</li>
<li data-start="631" data-end="651">
<p data-start="633" data-end="651">express delivery</p>
</li>
<li data-start="652" data-end="678">
<p data-start="654" data-end="678">organisation of {storage}</p>
</li>
</ul>
<p data-start="685" data-end="706"><strong>Example of price:</strong></p>
<ul data-start="707" data-end="808">
<li data-start="707" data-end="808">
<p data-start="709" data-end="808">for fifteen boxes and one violin sent from the UK to {Sweden},<br data-start="769" data-end="772">the cost would be about £ {575}</p>
</li>
</ul>
<p data-start="815" data-end="835"><strong>Payment options:</strong></p>
<ul data-start="836" data-end="902">
<li data-start="836" data-end="902">
<p data-start="838" data-end="902">on the phone by debit or credit card, or in cash to the {driver}</p>
</li>
</ul>
<p data-start="909" data-end="934"><strong>Documentation needed:</strong></p>
<ul data-start="935" data-end="979">
<li data-start="935" data-end="958">
<p data-start="937" data-end="958">photocopy of {passport}</p>
</li>
<li data-start="959" data-end="979">
<p data-start="961" data-end="979">insurance papers</p>
</li>
</ul>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>SECTION 1: SHIPPING OF PERSONAL BELONGINGS<br />\nStaff: Hello, Move It Shipping.</p>\n<p>Customer: Hi, I’d like a few more details about your services, please.</p>\n<p>Staff: Certainly.</p>\n<p>Customer: I’ve been on your website looking into sending some things abroad when I go away to study next term. I see that you provide special empty (Example) boxes so that I can pack them myself, and you then transport them.</p>\n<p>Staff: That’s right, we provide those free of charge.</p>\n<p>Customer: And can I ask what goods you can transport? Like, do you take electrical goods?</p>\n<p>Staff: Well, it depends. If you’ve got something like a computer, that’s fine. But things like washing machines and fridges are too heavy and bulky for our service.</p>\n<p>Customer: No, I wouldn’t be taking that sort of stuff.</p>\n<p>Staff: You can always check with us if there’s anything you’re not sure about.</p>\n<p>Customer: Including… I was wondering about my <span style=\"background-color: #f1c40f;\"><strong>(1) bicycle</strong></span>. I suppose that would be too bulky?</p>\n<p>Staff: No, that’s fine. Though we wouldn’t be able to take a motorbike, sure.</p>\n<p>Customer: Is there anything else you don’t take?</p>\n<p>Staff: Well, basically the service is restricted to what one man can lift, so <span style=\"background-color: #f1c40f;\"><strong>(2) 40</strong></span> kg is the maximum for each package. We do have a list of particular things we can’t transport on our website, but I’ll tell you the main points. So in order to comply with security regulations, we don’t take any sort of <strong><span style=\"background-color: #f1c40f;\">(3) liquids</span></strong>, and we also don’t accept any type of foods.</p>\n<p>Customer: And if you provide your own containers rather than using ours, we only allow certain types. So can I use cardboard containers?</p>\n<p>Staff: Yes, they’re okay if they’re strong enough. But we won’t carry things that have been packed in <span style=\"background-color: #f1c40f;\"><strong>(4) plastic</strong></span> containers—they crack and break so easily that our policy is simply not to take them.</p>\n<p>Customer: Okay, fine. And once I’ve packed everything, you can collect my things from my home and deliver them to wherever I live abroad, is that right?</p>\n<p>Staff: Yes, and we do have some special services. For example, we can make special arrangements to deliver on <strong><span style=\"background-color: #f1c40f;\">(5) Saturdays</span></strong> if that’s more convenient for you. Or if you’re in a hurry, we have an express delivery option. There’s a surcharge for these services, of course, but it’s very reasonable.</p>\n<p>Customer: OK, I’ll keep that in mind. And what happens if the delivery can’t be made for some reason? Like if I haven’t finalised my accommodation, can you keep my stuff for me for a few days?</p>\n<p>Staff: Yes, we can arrange <span style=\"background-color: #f1c40f;\"><strong>(6) storage</strong></span>, though again, there would be an extra charge for that, sure.</p>\n<p>Customer: And can you give me an idea of your prices?</p>\n<p>Staff: Of course. Roughly how much would you want transported?</p>\n<p>Customer: Say for example I had 15 boxes, and I’ve also got a violin that would need packing with special care, I think.</p>\n<p>Staff: OK, and it would be collection in the UK?</p>\n<p>Customer: Yes, and <span style=\"background-color: #f1c40f;\"><strong>(7) Sweden</strong></span> would be the destination.</p>\n<p>Staff: OK, I’ll do a quick calculation. Let me just get that up on the screen. 15 boxes and one special package… let’s see… it’d be something in the order of £(<span style=\"background-color: #f1c40f;\"><strong>8) 575.</strong></span></p>\n<p>Customer: Right. And how would I pay that?</p>\n<p>Staff: Well, you can pay by debit or credit card over the phone, or if you prefer to pay in cash, you can just give it to the <span style=\"background-color: #f1c40f;\"><strong>(9) driver</strong></span> when he arrives to collect your belongings, and he’ll give you a receipt.</p>\n<p>Customer: Fine.</p>\n<p>Staff: And at the same time, you’ll need to hand over some documentation. So you’ll need a copy of your <span style=\"background-color: #f1c40f;\"><strong>(10) passport.</strong></span></p>\n<p>Customer: A photocopy?</p>\n<p>Staff: That’s right, so make sure you get that done in advance and have it ready with you. Then there are also some papers you’ll need that we’ll send you in advance so that you can get them completed in good time. The most important ones are the insurance documents…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('96d64298-1d02-4a6b-b205-4e25d110a8f0', 'e505f1da-d83e-4a8e-a007-16d6e4790056', 'matching', 'Questions 27–30', '', '<p>Which comment did most students make about each of the following aspects of performance?</p>
<p>Choose <strong>FOUR </strong>correct answers, <strong>A-G</strong>, next to questions <strong>27-30</strong>.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Aspects of performance</strong></p>\n<p> </p>\n<p>Performing solo {B This is difficult but enjoyable.}</p>\n<p> </p>\n<p>Deciding which pieces to perform {E This is time-consuming.}</p>\n<p> </p>\n<p>Performing with musicians from a different genre {G This happens infrequently.}</p>\n<p> </p>\n<p>Performing with musicians who play the same instrument {A This is very beneficial.}</p>", "answerOptions": [{"optionText": "A This is very beneficial."}, {"optionText": "B This is difficult but enjoyable."}, {"optionText": "C This can affect relationships."}, {"optionText": "D This makes them very nervous."}, {"optionText": "E This is time-consuming."}, {"optionText": "F This is easy."}, {"optionText": "G This happens infrequently."}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>\n"}]', 3);
INSERT INTO public.questions VALUES ('88309602-fa32-45fa-a82e-2187ec71ecb8', '136a6a3b-67a3-465a-a956-984c7b8ec061', 'matrix', 'Questions 18-21', NULL, '<p>Look at the following statements (Questions 18-21) and the list of researchers below.</p>
<p>Choose each statement with the correct researcher, <strong>А, В, C </strong>or <strong>D</strong>.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "The transplanting of certain genes into tomatoes can change their shape.", "correctCategoryLetter": "B"}, {"itemText": "The flavour of the heirloom tomato is largely dependent on actual yield and cultivation.", "correctCategoryLetter": "C"}, {"itemText": "A new type of tomato can be produced that is stronger than the original heirloom tomato yet equally sweet and flavoursome.", "correctCategoryLetter": "D"}, {"itemText": "The wide variety of heirloom tomatoes is due to only a small number of genes.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Steven Tanlestey", "categoryLetter": "A"}, {"categoryText": "Esther van der Knaap", "categoryLetter": "B"}, {"categoryText": "Roger Chetelat", "categoryLetter": "C"}, {"categoryText": "Doug Heath", "categoryLetter": "D"}]}', '[{"content": "<p>18. The wide variety of heirloom tomatoes is due to only a small number of genes.</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Nhà nghiên cứu:</strong> <strong>A (Steven Tanksley)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) Tanksley khẳng định: “There’re probably <strong>no more than 10 mutant genes that create the diversity of heirlooms</strong> you see.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Steven Tanksley là nhà di truyền học tại Đại học Cornell, người đã chỉ ra rằng sự đa dạng bề ngoài của cà chua heirloom thực chất chỉ do một số lượng rất nhỏ gen đột biến quyết định.</p>\n</li>\n</ul>\n<p>19. The transplanting of certain genes into tomatoes can change their shape.</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Nhà nghiên cứu:</strong> <strong>B (Esther van der Knap)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) Esther van der Knap đã lấy một gen từ cà chua heirloom và chèn vào một loài hoang dã. Cô <strong>“observed that, as a result, the tiny fruits became shaped like pears.”</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Esther van der Knap đã tiến hành thí nghiệm cấy gen và quan sát thấy sự thay đổi hình dạng của quả cà chua.</p>\n</li>\n</ul>\n<p>20. The flavour of the heirloom tomato is largely dependent on actual yield and cultivation.</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Nhà nghiên cứu:</strong> <strong>C (Roger Chetelat)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) Roger Chetelat giải thích rằng <strong>“heirlooms taste may have less to do with their genes than with the productivity of the plant and the growing environment”</strong>.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Roger Chetelat lập luận rằng hương vị của cà chua heirloom phụ thuộc chủ yếu vào năng suất thực tế và môi trường trồng trọt, chứ không hẳn là do gen.</p>\n</li>\n</ul>\n<p>21. A new type of tomato can be produced that is stronger than the original heirloom tomato yet equally sweet and flavoursome.</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong>Nhà nghiên cứu:</strong> <strong>D (Doug Heath)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) Doug Heath đã tạo ra giống cà chua lai tạo mới có 12 gen kháng bệnh (khỏe hơn/stronger) và <strong>“claims he is also able to maintain a comparable flavor and sugar profile”</strong> (duy trì hương vị và độ ngọt tương đương).</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong>Giải thích:</strong> Doug Heath là nhà lai tạo đã chứng minh có thể khắc phục các lỗi di truyền của heirloom để tạo ra một giống khỏe mạnh hơn mà vẫn giữ được hương vị mong muốn.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('8416ceb1-659e-4e18-9bb3-2aab17cb787e', 'a0bf0e74-2e4b-4e45-b222-7d26a27218e0', 'matching', 'Questions 14-19', NULL, '<p>Reading Passage 2 has six paragraphs, A-F.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i New terminology reflecting changing attitudes to waste disposal"}, {"optionText": "ii Fundamental changes in behaviour in the past and future"}, {"optionText": "iii Ways of rewarding the public for recycling"}, {"optionText": "iv A surprising approach to waste disposal by several countries"}, {"optionText": "v Difficult choices for individuals and businesses"}, {"optionText": "vi Arguments against incineration from a country that uses it"}, {"optionText": "vii A number of justifications for the use of incineration"}], "matchingItems": null}', 'null', '[{"content": "<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">14. Paragraph A: iv (A surprising approach to waste disposal by several countries)</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Norway, however, appears to be burning its way through a sizable chunk of Europe’s municipal waste… Germany, Sweden, Belgium and the Netherlands all burn significant quantities…”</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông thường, đốt rác bị coi là lựa chọn “lười biếng” và độc hại. Tuy nhiên, các quốc gia này lại sử dụng nó để sưởi ấm và tạo năng lượng, một cách tiếp cận gây bất ngờ so với quan điểm truyền thống.</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. Paragraph B: vii (A number of justifications for the use of incineration)</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Filters and scrubbing mechanisms now capture harmful substances… incineration is the only way of preventing the long-term impacts of landfill… practical way to deal swiftly…”</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này đưa ra các lý do bào chữa/ủng hộ việc đốt rác: công nghệ lọc khí mới giúp giảm khí độc và đây là cách nhanh nhất để xử lý lượng rác khổng lồ thay vì chôn lấp.</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. Paragraph C: vi (Arguments against incineration from a country that uses it)</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Lars Haltbrekken, chairman of Friends of the Earth in Norway… ‘The problem in Norway… is that we have built too many waste-burning factories. So we’ve ended up importing waste…’”</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Na Uy là nước sử dụng lò đốt rác, nhưng Lars Haltbrekken (người Na Uy) lại phản đối vì nó làm giảm động lực giảm thiểu và tái chế rác thải.</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. Paragraph D: i (New terminology reflecting changing attitudes to waste disposal)</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “We used to call this the ‘cradle to grave’ life cycle; now, the talk is of ‘cradle to cradle’ and an even more comprehensive concept known as ‘zero waste’.”</li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giới thiệu các thuật ngữ mới như “cradle to cradle” và “zero waste” để phản ánh sự thay đổi trong cách con người nhìn nhận vòng đời sản phẩm.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. Paragraph E: v (Difficult choices for individuals and businesses)</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “You can argue about composting that, or not buying it in the first place… that’s money the retailers don’t get… [Supermarkets] have to pay to dispose of a lot of food… but that cost is less to them than brand damage…”</li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đề cập đến sự mâu thuẫn giữa việc cắt giảm lãng phí thực phẩm và lợi nhuận của nhà bán lẻ (siêu thị thà bỏ đồ thừa còn hơn để kệ trống gây ảnh hưởng thương hiệu).</li>\n</ul>\n<p><strong data-path-to-node=\"13\" data-index-in-node=\"0\">19. Paragraph F: ii (Fundamental changes in behaviour in the past and future)</strong></p>\n<ul data-path-to-node=\"14\">\n<li><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Nobody would have said there would be so much electronic waste. But recycling has grown, too… we need to look at whether it’s business that drives consumers or the other way around.”</li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nhìn lại sự thay đổi về tiêu dùng và tái chế từ những năm 1980 đến nay và định hướng thay đổi hành vi trong tương lai.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('9edd5bc5-48da-4328-a85a-279d7f6f4459', '019c8290-6cfb-4361-b2e2-7cf4de433b99', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text   ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Write ONE WORD ONLY for each answer.</strong></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text   ">
<div class="">
<div class="s-component-content s-font-body">
<p><span style="font-size: 14pt;"><strong>Reasons for and against urban migration</strong></span></p>
<p><strong>Cities today</strong></p>
<ul>
<li>
<p>account for 3% of our planet’s land area</p>
</li>
<li>
<p>produce less {carbon} than non-urban areas</p>
</li>
</ul>
<p><strong>The advantages of more people moving to the city</strong></p>
<ul>
<li>
<p>some {forests} would recover</p>
</li>
<li>
<p>more energy efficient for services like electricity and water</p>
</li>
<li>
<p>{transport} in the city is more environmentally friendly</p>
</li>
<li>
<p>Recycling: energy could be generated from the methane gas from {rubbish}</p>
</li>
<li>
<p>Population: urban women</p>
<ul>
<li>
<p>start a family much later</p>
</li>
<li>
<p>are more likely to gain {promotion} at work</p>
</li>
</ul>
</li>
</ul>
<p><strong>The downsides of living in the city</strong></p>
<ul>
<li>
<p>possible loss of {culture} amongst some migrants</p>
</li>
<li>
<p>the higher {crime} rate among the population</p>
</li>
<li>
<p>the poor quality of the {air}</p>
</li>
<li>
<p>Economic factors: increased {wealth} in a population leads to more energy consumption</p>
</li>
<li>
<p>citizens may find the quantity of daily {traffic} stressful</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: URBAN MIGRATION AND THE ENVIRONMENT</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> </p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Good morning everyone.</strong> Today we’re looking at urban migration—the movement of people migrating from outside cities into cities. I think it’s easy to jump to the conclusion that a rural lifestyle is greener; however, recent studies have suggested otherwise.</p>\n<p data-path-to-node=\"4\">First of all, if we take the land area of the earth, the proportion that cities take up is a mere 3%. And these same cities actually produce 30 to 40% of the <span style=\"background-color: #f3db7b;\"><strong>31 </strong><strong data-path-to-node=\"4\" data-index-in-node=\"158\">{carbon}</strong></span> that is released into the atmosphere—a lower amount than the 60 to 70% from non-urban areas.</p>\n<p data-path-to-node=\"5\">Anyway, let’s imagine that most people decide to migrate to the city. What kind of impact would that have? For a start, this movement of people from the countryside should lift the pressure of intensive agriculture from the land, allowing <span style=\"background-color: #f3db7b;\"><strong>32 </strong><strong data-path-to-node=\"5\" data-index-in-node=\"239\">{forests}</strong></span> to regenerate.</p>\n<p data-path-to-node=\"6\">Another point in favour of urban migration is that it can be far more energy efficient if services are concentrated in the city. For example, this is true for electricity and, as you can imagine, water. Then, once you remember that rural communities are often very spread out, you can see yet another green reason to live in the city: rural citizens rely on the car to make their journeys far more than city dwellers, who have other more environmentally friendly forms of <span style=\"background-color: #f3db7b;\"><strong>33 </strong><strong data-path-to-node=\"6\" data-index-in-node=\"472\">{transport}</strong></span> that they can use, such as buses and trains. The journeys tend to be shorter too.</p>\n<p data-path-to-node=\"7\">Yet another point in favour of urban migration is the kind of recycling schemes that can only take place where the population is concentrated. Take, for instance, Seattle in the USA, where methane gas is being put to good use and is generating energy for the city. It’s produced from the city’s <span style=\"background-color: #f3db7b;\"><strong>34 {rubbish}</strong></span>, which could not be collected so efficiently from rural areas.</p>\n<p data-path-to-node=\"8\">Now, another factor that threatens the environment is the growing world population. It’s estimated that 75 million babies are now born every year and in some countries, the birth rate shows no signs of slowing down. Urban migration may provide an answer here. Now in cities, one of the reasons that women tend to have fewer children is that they get married later and start their families later. And the reason for this is that it’s far easier to find a job, and once you have one, to get a <strong><span style=\"background-color: #f3db7b;\">35 {promotion}</span></strong>. So yes, the focus isn’t on bearing children.</p>\n<p data-path-to-node=\"9\">Well, it would be foolish to pretend that there are no downsides to urban living, when clearly there are. The thing that critics often mention is the idea that migrants may end up losing their <span style=\"background-color: #f3db7b;\"><strong>36 </strong><strong data-path-to-node=\"9\" data-index-in-node=\"193\">{culture}</strong></span>, although some studies have found the opposite is true; rather than give up their traditions, people actually work hard to maintain them.</p>\n<p data-path-to-node=\"10\">More evident is the fact that, compared to the lower rate that is observed in rural areas, we can see that there is more <span style=\"background-color: #f3db7b;\"><strong>37</strong></span><strong data-path-to-node=\"10\" data-index-in-node=\"121\"><span style=\"background-color: #f3db7b;\">{crime</span>}</strong> occurring in cities. There won’t be many of us here today who can say we haven’t been directly or indirectly affected by it. There’s another issue that we have to deal with: so many cities, including our own, now suffer from high levels of pollution, so that the <strong><span style=\"background-color: #f3db7b;\">38 {air}</span></strong> we breathe is far from pure.</p>\n<p data-path-to-node=\"11\">And another factor against the “urban is greener” idea is that urbanization often drives a country’s economy. Put simply, when there is greater <span style=\"background-color: #f3db7b;\"><strong>39 </strong><strong data-path-to-node=\"11\" data-index-in-node=\"144\">{wealth}</strong></span> in society, more energy is consumed. One of the direct effects of a stronger economy—something that many citizens will now experience every day and may well find stressful—is the amount of <span style=\"background-color: #f3db7b;\"><strong>40 </strong></span><strong data-path-to-node=\"11\" data-index-in-node=\"342\"><span style=\"background-color: #f3db7b;\">{traffic</span>}</strong> on the road. Despite the other options we mentioned earlier, this is a problem that is not about to go away…</p>"}]', 0);
INSERT INTO public.questions VALUES ('33fb4e5d-63d2-4daf-ab8a-7d347eb1ae3f', '39846273-f646-4c3c-8dc5-94351c2590f3', 'radio', 'Questions 31–35', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong>  if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Cheaper products are placed on lower shelves to minimise the likelihood that they will be bought."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Head offices should be more flexible about how products are arranged by supermarkets."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "There is widespread agreement on how products should be arranged on shelves."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Security cameras are a serious threat to customers’ privacy"}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Technology is the best tool for determining why shoppers fail to make purchases."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">31. Cheaper products are placed on lower shelves to minimise the likelihood that they will be bought.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 1–3.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…stores encourage customers to buy expensive branded products by arranging them at eye-level, <strong data-path-to-node=\"14,2,0\" data-index-in-node=\"108\">with cheaper ones lower down.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"14,3,0\"><strong data-path-to-node=\"14,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Siêu thị ưu tiên hàng đắt tiền ngang tầm mắt để khách dễ thấy và mua nhất, trong khi hàng rẻ bị đẩy xuống thấp để hạn chế sự chú ý.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. Head offices should be more flexible about how products are arranged by supermarkets.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong> (Lưu ý: Đáp án trong hình của bạn ghi là YES, nhưng thực tế đoạn 5 mô tả sự kiểm soát gắt gao của trụ sở chính).</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 3–5.</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Often head offices specify where everything has to be placed and <strong data-path-to-node=\"16,2,0\" data-index-in-node=\"77\">spot-checks are carried out</strong> to make sure instructions are followed to the letter.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,3,0\"><strong data-path-to-node=\"16,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc cho thấy các trụ sở chính đang áp đặt quy tắc cứng nhắc và kiểm tra đột xuất, không có sự linh hoạt. Câu hỏi mang tính chất kiến nghị dựa trên mâu thuẫn được nêu ở dòng tiếp theo về tranh cãi trong cách xếp hàng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. There is widespread agreement on how products should be arranged on shelves.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 5–7.</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “But shelf-positioning is <strong data-path-to-node=\"18,2,0\" data-index-in-node=\"37\">extremely controversial</strong>. Despite all the academic papers… <strong data-path-to-node=\"18,2,0\" data-index-in-node=\"97\">retailers have their own views.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"18,3,0\"><strong data-path-to-node=\"18,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Trái với “widespread agreement”, việc sắp xếp hàng hóa gây tranh cãi gay gắt và mỗi nhà bán lẻ lại có quan điểm riêng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. Security cameras are a serious threat to customers’ privacy.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 1–4.</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…security cameras in stores may be doing considerably more than watching out for theft. Pictures showing shoppers… can now be analysed.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,3,0\"><strong data-path-to-node=\"20,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ đề cập camera được dùng để phân tích hành vi mua sắm thay vì chỉ chống trộm, nhưng không hề bàn luận liệu điều này có phải là “mối đe dọa nghiêm trọng đến quyền riêng tư” hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. Technology is the best tool for determining why shoppers fail to make purchases.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 4–8.</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…data collected electronically <strong data-path-to-node=\"22,2,0\" data-index-in-node=\"45\">tells them little about why</strong> so many customers leave without making a purchase. <strong data-path-to-node=\"22,2,0\" data-index-in-node=\"124\">Face-to-face interviews reveal</strong> [more]…”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,3,0\"><strong data-path-to-node=\"22,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Công nghệ cao kể rất ít lý do, trong khi cách “low-tech” là phỏng vấn trực tiếp lại hiệu quả hơn trong việc giải thích tại sao khách hàng rời đi tay không.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('e38e36ae-e8af-4060-ac0d-4ee4a62da504', '9de8c968-7092-49be-bf3b-c9a23bb1bdbd', 'radio', 'Questions 1–4', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information  <strong>FALSE </strong>if the statement contradicts the information  <strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE  "}, {"content": "FALSE  "}, {"content": "NOT GIVEN"}], "question": "Research to date has concentrated on the importance of escape speed in surviving an attack by a predator"}, {"correct": 0, "options": [{"content": "TRUE  "}, {"content": "FALSE  "}, {"content": "NOT GIVEN"}], "question": "According to the ''bigger is better'' hypothesis, larger animals have better eyesight"}, {"correct": 1, "options": [{"content": "TRUE  "}, {"content": "FALSE  "}, {"content": "NOT GIVEN"}], "question": "Early-juvenile reef fish share similar characteristics   "}, {"correct": 2, "options": [{"content": "TRUE  "}, {"content": "FALSE  "}, {"content": "NOT GIVEN"}], "question": "Fully developed reef fish have a slower swimming speed than juveniles   "}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1. Research to date has concentrated on the importance of escape speed in surviving an attack by a predator.</p>\n<ul>\n<li><strong class=\"\">Đáp án:</strong> <strong class=\"\">FALSE</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 1) “Body size,</span><span class=\"\"> weight,</span><span class=\"\"> growth rate,</span><span class=\"\"> overall condition,</span><span class=\"\"> sensory development and </span><strong class=\"\">escape speed</strong><span class=\"\"> have all been linked to survival.</span> <strong class=\"\">Of these, body size has received the most attention</strong><span class=\"\"> from researchers…</span><span class=\"\">“</span></li>\n<li><strong class=\"\">Giải thích:</strong><span class=\"\"> Văn bản liệt kê nhiều yếu tố,</span><span class=\"\"> bao gồm tốc độ trốn thoát,</span><span class=\"\"> nhưng khẳng định </span><strong class=\"\">kích thước cơ thể</strong><span class=\"\"> (body size) mới là yếu tố được tập trung nghiên cứu nhiều nhất (“most attention”).</span></li>\n</ul>\n<p>2. According to the ‘bigger is better’ hypothesis, larger animals have better eyesight.</p>\n<ul>\n<li><strong class=\"\">Đáp án:</strong> <strong class=\"\">TRUE</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 1) “This theory predicts that larger body size should increase an individual’s ability to escape from a predator due to the characteristics associated with this,</span><span class=\"\"> such as overall strength and </span><strong class=\"\">visual development</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li><strong class=\"\">Giải thích:</strong><span class=\"\"> “Visual development” (sự phát triển thị giác) đồng nghĩa với việc có thị lực/thị giác tốt hơn (better eyesight).</span></li>\n</ul>\n<p>3. Early-juvenile reef fish share similar characteristics.</p>\n<ul>\n<li><strong class=\"\">Đáp án:</strong> <strong class=\"\">FALSE</strong></li>\n<li><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 2) “…</span><span class=\"\">determine whether a predator’s choice of prey is influenced by factors such as the prey’s size,</span><span class=\"\"> weight and swimming speed,</span><span class=\"\"> as these characteristics </span><strong class=\"\">vary from individual to individual</strong><span class=\"\"> at the beginning of the juvenile stage.</span><span class=\"\">“</span></li>\n<li><strong class=\"\">Giải thích:</strong><span class=\"\"> Các đặc điểm của cá non </span><strong class=\"\">khác nhau</strong><span class=\"\"> giữa các cá thể (“vary from individual to individual”),</span> mâu thuẫn với việc chúng “share similar characteristics” (chia sẻ các đặc điểm tương tự).</li>\n</ul>\n<p>4. Fully developed reef fish have a slower swimming speed than juveniles.</p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> Văn bản chỉ nói về cá ấu trùng và cá non, và đề cập đến việc cá lớn hơn không nhất thiết bơi nhanh hơn cá nhỏ hơn (Đoạn 8).</li>\n<li><strong>Giải thích:</strong> <strong>Không có thông tin</strong> so sánh trực tiếp tốc độ bơi giữa cá trưởng thành hoàn toàn (“fully developed reef fish” / “adult”) và cá non (“juveniles”).</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('2ca997d3-7b6a-497b-9318-5ac63b66643f', '1a17c47a-6a8d-4aef-aa6d-f45bb3014b3f', 'matrix', 'Questions 14–19', '', '<p data-path-to-node="5">Write the correct letter, <strong data-path-to-node="5" data-index-in-node="26">A–G</strong>, in boxes 14–19 on your answer sheet.</p>
<p data-path-to-node="6"><strong data-path-to-node="6" data-index-in-node="0">NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a reference to a denial of involvement in piracy", "correctCategoryLetter": "D"}, {"itemText": "details of how a campaign to eradicate piracy was carried out", "correctCategoryLetter": "G"}, {"itemText": "a mention of the circumstances in which states in the ancient world would make use of pirates", "correctCategoryLetter": "C"}, {"itemText": "a reference to how people today commonly view pirates", "correctCategoryLetter": "A"}, {"itemText": "an explanation of how some people were encouraged not to return to piracy", "correctCategoryLetter": "G"}, {"itemText": "a mention of the need for many sailing vessels to stay relatively close to land", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">14. A reference to a denial of involvement in piracy — {D}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">\"In the letters, the king of Alashiya (modern Cyprus) <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"65\">rejected</strong> Akhenaten’s claims of a connection with the Lukka...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc \"rejected Akhenaten’s claims\" (bác bỏ cáo buộc) chính là một sự phủ nhận việc liên quan (denial of involvement) đến hải tặc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">15. Details of how a campaign to eradicate piracy was carried out — {G}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">\"Pompey <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"19\">divided the entire Mediterranean into 13 districts</strong>, assigning a fleet and commander to each. After cleansing one district... the fleet would join another...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn G mô tả cực kỳ chi tiết cách thức (how) mà chiến dịch xóa sổ hải tặc của Pompey được thực hiện (chia khu vực, đánh cuốn chiếu).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">16. A mention of the circumstances in which states in the ancient world would make use of pirates — {C}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">\"...it was not unknown... for governments to <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"56\">resort to pirates’ services, especially during wartime</strong>, employing their skills and numbers against their opponents.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hoàn cảnh (circumstances) mà các quốc gia sử dụng hải tặc là vào thời điểm chiến tranh (during wartime).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">17. A reference to how people today commonly view pirates — {A}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">\"When one mentions pirates, an <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"42\">image springs to most people’s minds</strong> of a crew of misfits... in command of a tall sailing ship in the <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"144\">Caribbean Sea</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là cách mọi người ngày nay thường hình dung về hải tặc (gắn liền với vùng biển Caribê và tàu cao chân dài).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">18. An explanation of how some people were encouraged not to return to piracy — {G}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"11\">\"...as a long-term solution... many more were <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"57\">offered land in fertile areas</strong> located far from the sea. Instead of a maritime menace, Rome got <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"152\">productive farmers</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để họ không quay lại nghề cũ, La Mã đã cho họ đất đai để làm nông dân, giải quyết gốc rễ vấn đề kinh tế.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">19. A mention of the need for many sailing vessels to stay relatively close to land — {B}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"18,0,0\" data-index-in-node=\"11\">\"...ships could not easily cross long distances over open water. Thus, in the ancient world most were <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"113\">restricted to a few well-known navigable routes that followed the coastline</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Do hạn chế kỹ thuật, tàu bè cổ đại buộc phải đi theo các tuyến đường men theo đường bờ biển (close to land).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('e4b0e770-0df2-4f9a-b5fa-82f506fed322', '27941a33-af01-4744-887e-bbaa3870e9a5', 'fillup', ' Questions 31–40', '<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p style="text-align: left;"><strong>GAMIFICATION</strong></p>
<p><strong>What is it?</strong></p>
<p>– The use of gaming techniques in non-game situations</p>
<p>– In business, it is frequently used for {marketing}</p>
<p>– Uses people’s desire to win a reward</p>
<p>– Not a new idea, e.g. incentive schemes were first used by {airlines}</p>
<p><strong>Uses</strong></p>
<p>– To get online {feedback} quickly</p>
<p>– To persuade people to change their {behavior | behaviour}</p>
<p>– For training purposes, e.g. simulators used by {pilots} and town planners</p>
<p><strong>Successful examples</strong></p>
<p>– Official campaigns</p>
<p>– Australian government: to encourage people to {exercise} more</p>
<p>– overseas local authority: to reward drivers for not speeding</p>
<p><strong>Health</strong></p>
<p>– a staircase at a station that worked like a {piano}</p>
<p>– a game that helps recovery when old people hurt their {hand} in a fall</p>
<p><strong>Things to consider</strong></p>
<p>– It’s important for gamification to be {fun}</p>
<p>– Need to think about the laws regarding {privacy}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>SECTION 4</strong></p>\n<p class=\"MsoNormal\"><strong>Lecturer:</strong> Today we are going to look at how the phenomenon known as gamification has really exploded in recent years. So what exactly is gamification? It has been defined as the use of games thinking and mechanics in non-game situations, such as for business. Up to now, its most common function has been <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(31) marketing</strong>.</span> It is extremely popular with big companies, but as we’ll see, it also has many other uses.</p>\n<p class=\"MsoNormal\">Gamification techniques work on our natural desire for competition. One way they do this is by providing a reward—for example, badges or points, or providing a type of virtual currency. But don’t be fooled into thinking the concept is a novel one. Just think of the frequent flyer incentive schemes that were initiated by <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(32) airlines</strong></span> to try and retain customers. In fact, it’s been around for years; however, it has become more prolific with advances in technology.</p>\n<p class=\"MsoNormal\">So how is gamification being used? Well, it is seen as an excellent way of obtaining almost instantaneous <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(33) feedback</strong></span> through common social media sites. However, there are other areas where it is increasingly being used. In particular, as a means of trying to convince people through fun activities to alter their <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(34) behaviour</strong></span> <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\">(hoặc <strong>behavior</strong>). </span></span>Another use is in education or training in the workplace, especially when it is just not feasible to train people on the real thing. Good examples of this are the aircraft simulators used by <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(35) pilots</strong></span> or the urban simulators used by town planners.</p>\n<p class=\"MsoNormal\">So let’s look at a few examples of the successful implementation of gamification. One perhaps surprising use of gamification has been in official campaigns by governments and authorities, who have quickly seen its potential. In Australia, the government developed a smartphone app called “MyFitBuddy”, whose aim was to help people get off the sofa and <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(36) exercise</strong> </span>more. The app provided plenty of motivational content to ensure people got the encouragement they needed to increase their levels of activity.</p>\n<p class=\"MsoNormal\">Overseas, in one city, instead of just punishing the drivers caught driving too fast, a local authority conducted a trial where they rewarded good drivers with free entries into a draw. The trial was so successful that it resulted in a 22% reduction in speeding.</p>\n<p class=\"MsoNormal\">Gamification is also playing its part in helping people make healthy choices. In an attempt to get commuters to walk instead of using the escalators in an underground station, the staircase next to it was transformed into a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(37) piano</strong></span>. It had a touchpad underneath which played notes as people stepped on it. When it was in use, almost everyone opted to use the stairs instead of the escalator.</p>\n<p class=\"MsoNormal\">Another example is a medical research company in Australia. They realized the potential of gamification to help the elderly recover much more quickly from accidents. When the elderly fall, the most common injury is not to the arm or the leg, but to the<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong>(38) hand</strong>.</span></span> So they took an already popular computer game which involved people smashing fruit and adapted it so patients could practice their fine motor skills in a fun way.</p>\n<p class=\"MsoNormal\">Now there are a number of things to consider when using gamification. First of all, there is no way it can work unless it is <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(39) fun</strong>.</span> In fact, without that element, it could have the complete opposite effect on the consumer. In addition, as companies are often obtaining a lot more personal information and data on their customers this way, they should always be mindful of their legal obligations in terms of legislation relating to <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(40) privacy</strong>.</span></p>\n<p class=\"MsoNormal\">So now, it’s over to you to think of other examples of gamification that you might have come across…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('5d2a6173-21cc-4c8f-aba1-54fe17245f64', 'a0bf0e74-2e4b-4e45-b222-7d26a27218e0', 'matrix', 'Questions 20-23', NULL, '<p>Look at the following people (Questions 20-23) and the list of opinions below.</p>
<p>Match each person with the correct opinion, A-G.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of opinions", "matrixItems": [{"itemText": "Ted Michaels", "correctCategoryLetter": "F"}, {"itemText": "Joergen Fenhann", "correctCategoryLetter": "C"}, {"itemText": "Joan Marc Simon", "correctCategoryLetter": "D"}, {"itemText": "Tim Burns", "correctCategoryLetter": "G"}], "matrixCategories": [{"categoryText": "Incineration does not encourage responsible attitudes to waste disposal.", "categoryLetter": "A"}, {"categoryText": "Recycling can sometimes create serious problems for the future.", "categoryLetter": "B"}, {"categoryText": "Greater consumerism leads to higher levels of waste.", "categoryLetter": "C"}, {"categoryText": "Proper systems are needed for the recycling of environmentally-friendly products.", "categoryLetter": "D"}, {"categoryText": "Landfill is better for the environment than incineration.", "categoryLetter": "E"}, {"categoryText": "Incineration of waste is now relatively harmless to the environment.", "categoryLetter": "F"}, {"categoryText": "Efforts to reduce waste may affect profits for some types of companies.", "categoryLetter": "G"}]}', '[{"content": "<p><strong data-path-to-node=\"17\" data-index-in-node=\"0\">20. Ted Michaels: F (Incineration of waste is now relatively harmless to the environment.)</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the output from these facilities is now <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"55\">minuscule</strong>.”</li>\n<li><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ông tin rằng nhờ công nghệ lọc mới, lượng khí thải từ lò đốt rác hiện nay là cực nhỏ (không đáng kể/không gây hại).</li>\n</ul>\n<p><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. Joergen Fenhann: C (Greater consumerism leads to higher levels of waste.)</strong></p>\n<ul data-path-to-node=\"20\">\n<li><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The more you develop, the more you produce, buy and throw away.”</li>\n<li><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự phát triển và tiêu dùng càng cao thì lượng rác thải ra càng nhiều.</li>\n</ul>\n<p><strong data-path-to-node=\"21\" data-index-in-node=\"0\">22. Joan Marc Simon: D (Proper systems are needed for the recycling of environmentally-friendly products.)</strong></p>\n<ul data-path-to-node=\"22\">\n<li><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…without the right mechanisms in place ‘nothing guarantees that this bottle will end up being properly collected and treated…’”</li>\n<li><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dù thiết kế sản phẩm tốt đến đâu, nếu không có hệ thống/cơ chế thu gom đúng cách thì vẫn không thể tái chế hiệu quả.</li>\n</ul>\n<p><strong data-path-to-node=\"23\" data-index-in-node=\"0\">23. Tim Burns: G (Efforts to reduce waste may affect profits for some types of companies.)</strong></p>\n<ul data-path-to-node=\"24\">\n<li><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…if you do that, then that’s money the retailers don’t get…”</li>\n<li><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc người dân giảm mua sắm để giảm rác thải sẽ trực tiếp làm giảm doanh thu/lợi nhuận của các nhà bán lẻ.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('72199d59-15ad-4bb7-abbc-5a2a990659b7', '9976632d-4b0c-4e82-b2f7-b0cef1d42864', 'radio', 'Questions 1–7', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Nancy Athfield found ancient human remains in Cambodia."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The human remains found in the Cardamom mountains were in good condition."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Athfield has taken time off from her usual job to do research in Cambodia."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Cambodian government asked Athfield to radiocarbon date the Cardamom remains."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Film-makers were researching how Angkor was rebuilt after the 1431 invasion."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Athfield initially doubted the stories of the royal family hiding in the Cardamom mountains."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Athfield''s research disproved the idea that the Cardamom remains were from the royal family."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Câu 1: Nancy Athfield found ancient human remains in Cambodia.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The unexplained remains, <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"37\">discovered by local people</strong> in large ceramic jars and hollowed-out logs…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết nêu rõ hài cốt do người dân địa phương phát hiện, không phải do Nancy Athfield trực tiếp tìm thấy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Câu 2: The human remains found in the Cardamom mountains were in good condition.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The unexplained remains… in large ceramic jars and hollowed-out logs…”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ mô tả nơi chứa hài cốt (chậu gốm, thân cây rỗng) chứ không đề cập đến tình trạng (tốt hay xấu) của chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Câu 3: Athfield has taken time off from her usual job to do research in Cambodia.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> TRUE</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…have increasingly <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"33\">drawn Athfield away from her regular employment</strong> at G.N.S. Science’s Rafter Laboratory… into the world of research in the field.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “drawn away from her regular employment” đồng nghĩa với việc cô ấy tạm rời xa công việc thường nhật để đi nghiên cứu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Câu 4: The Cambodian government asked Athfield to radio carbon date the Cardamom remains.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…when a <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"22\">film-making company</strong> requested that she radiocarbon date bone samples…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Người yêu cầu cô thực hiện việc định tuổi carbon là một công ty làm phim, không phải chính phủ Campuchia.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Câu 5: Film-makers were researching how Angkor was rebuilt after the 1431 invasion.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The film-makers had set out to investigate the idea that these human remains marked the <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"100\">final resting place of people belonging to the last royal household of Angkor</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Mục đích của các nhà làm phim là tìm hiểu xem liệu hài cốt có phải là của hoàng gia Angkor hay không, chứ không phải nghiên cứu việc tái thiết thành phố.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Câu 6: Athfield initially doubted the stories of the royal family hiding in the Cardamom mountains.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…many stories were told of surviving members of the royal family fleeing to seek refuge in the Cardamom Mountains.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến các câu chuyện về hoàng gia, nhưng không nói về cảm xúc hay quan điểm cá nhân (nghi ngờ hay tin tưởng) của Athfield lúc ban đầu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Câu 7: Athfield’s research disproved the idea that the Cardamom remains were from the royal family.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án:</strong> TRUE</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Athfield dated the original Cardamom bone samples to as late as 1620, <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"82\">dashing the possibility of Angkorian royalty</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Kết quả giám định (năm 1620) đã dập tắt (dashing) khả năng đây là người của hoàng gia Angkor (vốn bị lật đổ từ năm 1431).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('63e4a638-2600-4c3c-9673-991e5c7f8be2', '9976632d-4b0c-4e82-b2f7-b0cef1d42864', 'fillup', 'Questions 8–13', '<div class="exams-tab hilightJs">
<div id="hilight_panel_0" class="exams-tab-panel hilightItemJs active">
<div class="exams-block">
<div class="exams-inner HilightInnerJs resizeJs">
<div class="exams-quest resizeIt highlightQuest">
<div class="exams-quest-inner">
<div class="quests fill quests-history">
<div class="quests-inner">
<div class="quests-inner-desc">
<div class="txt">
<p>Complete the flow-chart below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><strong>Nancy Athfield’s career</strong></p>
<p class="ql-align-center" style="text-align: center;">In her mid-teens, Athfield did not expect to attend {university} .</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Wally Brocker taught Athfield how to develop the mind of a scientist.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Athfield’s PhD investigated when a type of {rat} arrived in New Zealand.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Her PhD research found that the subject’s diet accounted for previous inaccurate results.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">She worked as a professional {archaeologist} before going to Cambodia in 2003.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Inadequate {funding} prevented further research in Cambodia.</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">Later, she helped to compile a {database} dating across Cambodia of radiocarbon</p>
<p class="ql-align-center" style="text-align: center;">⬇️</p>
<p class="ql-align-center" style="text-align: center;">The lack of a detailed {map} of Cambodia’s geology has made her team’s research harder.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="exams-gr">
<div class="exams-step prev disable"> </div>
</div>
', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Câu 8: In her mid-teens, Athfield did not expect to attend …</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án:</strong> university</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…before a friend suggested she sit the entrance exam for <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"71\">university</strong>. She did, and to her <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"103\">surprise</strong> she was accepted.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc cô ấy thấy “ngạc nhiên” khi được nhận vào học cho thấy trước đó cô không hề mong đợi (did not expect) sẽ đi học đại học.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Câu 9: Athfield’s PhD investigated when a type of … arrived in New Zealand.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án:</strong> rat</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…suggest rằng a <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"30\">rat</strong> species had arrived in New Zealand as early as 100 AD… Her PhD was based on five years of research exploring this issue…”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đề tài tiến sĩ của cô nghiên cứu về thời điểm một loài chuột (rat) đến New Zealand.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Câu 10: She worked as a professional … before going to Cambodia in 2003.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Đáp án:</strong> archaeologist</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “She then… started working as a fully qualified <strong data-path-to-node=\"26,1,0\" data-index-in-node=\"61\">archaeologist</strong> in the UK… But it was the call from those film-makers in 2003 that…”</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong data-path-to-node=\"26,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước khi nhận cuộc gọi từ các nhà làm phim năm 2003, cô đang làm việc như một nhà khảo cổ học chuyên nghiệp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Câu 11: Inadequate … prevented further research in Cambodia.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án:</strong> funding</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…she and her colleagues were hampered by that universal problem for researchers, a <strong data-path-to-node=\"28,1,0\" data-index-in-node=\"97\">lack of funding</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong data-path-to-node=\"28,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Inadequate” đồng nghĩa với “lack of”. Việc thiếu kinh phí (funding) đã cản trở nghiên cứu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Câu 12: Later, she helped to compile a … dating across Cambodia of radiocarbon.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Đáp án:</strong> database</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…as part of a larger project to create a Cambodia-wide radiocarbon <strong data-path-to-node=\"30,1,0\" data-index-in-node=\"81\">database</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong data-path-to-node=\"30,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cô tham gia vào một dự án lớn hơn để tạo ra một cơ sở dữ liệu (database) về carbon phóng xạ trên toàn Campuchia.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Câu 13 The lack of a detailed … of Cambodia’s geology has made her team’s research harder.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Đáp án:</strong> map</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it has been no easy task because the country doesn’t have an extensive geological <strong data-path-to-node=\"32,1,0\" data-index-in-node=\"97\">map</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"32,2,0\"><strong data-path-to-node=\"32,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc thiếu một bản đồ (map) địa chất chi tiết đã khiến công việc của đội nghiên cứu gặp khó khăn.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('d6d30d32-346a-459f-b486-2a9159e6f704', '167699bc-1181-40cb-9d9a-00010be59b77', 'checkbox', 'Questions 23 and 24', '', '<p>In his assignment, which <strong>TWO </strong>aspects of outdoor play does Ravi want to focus on?</p>
<p>Choose <strong>TWO </strong>letters, A-E.</p>', 'list_selection', 'null', '[{"correct": true, "option_text": "A. How it helps children to evaluate risk"}, {"correct": false, "option_text": "B. How it broadens their horizons"}, {"correct": false, "option_text": "C. How it aids children’s muscular development"}, {"correct": true, "option_text": "D. How it improves children’s digestion"}, {"correct": false, "option_text": "E. How it teaches children about the environment"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('c5a2def1-7c42-4960-9844-e0f6d18de1ef', 'cb5dc672-47e0-48d1-badc-dcfb4cd52a54', 'fillup', 'Question 31–40', '<p><strong>Complete the notes below.</strong></p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Nostalgia</strong></span></p>
<p><strong>What is nostalgia?</strong></p>
<p>Memories from the past that can make us feel like seeing an old {photograph}</p>
<p>Nostalgia is frequently brought on by {smell}</p>
<p><strong>Common Triggers</strong></p>
<p>Looking at an old {diary} already used – we’ll swap</p>
<p>Former {soldiers} often feel nostalgic when they hear marching music.</p>
<p>The ringing of church {bells} may recall weddings or other ceremonies.</p>
<p><strong>Emotional Effects</strong></p>
<p>Nostalgia can help reduce mild {depression}</p>
<p>A piece of homemade {cake} can bring back memories of childhood.</p>
<p>Listening to an old {song} can revive strong emotions.</p>
<p><strong>Modern Uses</strong></p>
<p>Some {charity} campaigns use nostalgic themes to attract donors.</p>
<p>A hospital {therapy} may encourage patients to recall memories from their past.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>“Now listen carefully and answer questions 31 to 40. Today, I’d like to talk about nostalgia, a fascinating emotional experience that connects our present with our past. It’s something almost everyone experiences from time to time—that sudden rush of emotion when we’re reminded of moments, people, or places from earlier in our lives.”</p>\n<blockquote>\n<p><em>“Bây giờ hãy lắng nghe cẩn thận và trả lời các câu hỏi từ 31 đến 40. Hôm nay, tôi muốn nói về hoài niệm, một trải nghiệm cảm xúc hấp dẫn kết nối hiện tại của chúng ta với quá khứ. Đó là điều mà hầu hết mọi người đều trải qua theo thời gian—một cảm xúc dâng trào đột ngột khi chúng ta được nhắc nhở về những khoảnh khắc, con người hoặc địa điểm từ những năm tháng trước đó trong đời.”</em></p>\n</blockquote>\n<p>“Nostalgia can arise when something small makes us recall people or experiences we once cherished. Even a <strong>(Question 31) photograph</strong> can awaken those memories, allowing us to relive a fragment of our earlier lives. Sometimes a single image is enough to stir emotions we didn’t even realize were still there. It might remind us of family gatherings, school days, or travels long gone.”</p>\n<blockquote>\n<p><em>“Hoài niệm có thể nảy sinh khi một điều nhỏ bé khiến chúng ta nhớ lại những người hoặc trải nghiệm mà chúng ta từng trân trọng. Ngay cả một <strong>(Câu hỏi 31) bức ảnh</strong> cũng có thể đánh thức những ký ức đó, cho phép chúng ta sống lại một phần nhỏ của những năm tháng trước đây. Đôi khi một hình ảnh duy nhất là đủ để khuấy động những cảm xúc mà chúng ta thậm chí không nhận ra là chúng vẫn còn đó. Nó có thể nhắc nhở chúng ta về những buổi họp mặt gia đình, những ngày đi học, hoặc những chuyến du lịch đã xa.”</em></p>\n</blockquote>\n<p>“Researchers have found that <strong>(Question 32) smell</strong> can instantly activate memories we thought we’d forgotten. For many people, a familiar perfume can bring back events and feelings from years ago. That’s because the part of our brain that processes smell is closely linked to the region responsible for emotion and memory, which is why certain scents feel so powerful.”</p>\n<blockquote>\n<p><em>“Các nhà nghiên cứu đã phát hiện ra rằng <strong>(Câu hỏi 32) mùi hương</strong> có thể ngay lập tức kích hoạt những ký ức mà chúng ta tưởng rằng đã quên. Đối với nhiều người, một loại nước hoa quen thuộc có thể mang lại những sự kiện và cảm xúc từ nhiều năm trước. Đó là vì phần não xử lý mùi hương của chúng ta có liên hệ mật thiết với vùng chịu trách nhiệm về cảm xúc và trí nhớ, đó là lý do tại sao một số mùi hương lại có sức mạnh đến vậy.”</em></p>\n</blockquote>\n<hr />\n<p>“Now moving on, let’s think about what tends to trigger nostalgia most often. The things we keep from the past can act as powerful emotional cues. For instance, leafing through a <strong>(Question 33) diary</strong> can bring back vivid recollections of people, places, and situations once experienced. These records of daily life allow us to see how we’ve changed, what we valued, and how our priorities have shifted over time.”</p>\n<blockquote>\n<p><em>“Bây giờ, chúng ta hãy xem xét điều gì thường có xu hướng kích hoạt hoài niệm nhất. Những thứ chúng ta giữ lại từ quá khứ có thể hoạt động như những tín hiệu cảm xúc mạnh mẽ. Ví dụ, lật giở một cuốn <strong>(Câu hỏi 33) nhật ký</strong> có thể mang lại những hồi ức sống động về những người, địa điểm và tình huống đã từng trải qua. Những ghi chép về cuộc sống hàng ngày này cho phép chúng ta thấy mình đã thay đổi như thế nào, những gì chúng ta coi trọng và cách các ưu tiên của chúng ta đã thay đổi theo thời gian.”</em></p>\n</blockquote>\n<p>“Certain types of music can act as strong emotional triggers for people who have lived through intense periods of their lives. When former <strong>(Question 34) soldiers</strong> hear marching music, it often recalls their training days and the powerful sense of unity they once felt. The rhythm, repetition, and sound patterns of such music seem to carry emotional memories more effectively than words ever could.”</p>\n<blockquote>\n<p><em>“Một số loại nhạc nhất định có thể hoạt động như những tác nhân kích thích cảm xúc mạnh mẽ đối với những người đã trải qua những giai đoạn căng thẳng trong đời. Khi những <strong>(Câu hỏi 34) người lính</strong> cũ nghe nhạc hành quân, nó thường gợi lại những ngày huấn luyện và cảm giác đoàn kết mạnh mẽ mà họ từng cảm thấy. Nhịp điệu, sự lặp lại và các khuôn mẫu âm thanh của loại nhạc này dường như mang lại những ký ức cảm xúc hiệu quả hơn lời nói.”</em></p>\n</blockquote>\n<p>“Sounds from public spaces often act as emotional reminders of shared traditions. The distant <strong>(Question 35) bells</strong> from a ceremony hall like a church can awaken memories of celebrations or community gatherings. For many, such sounds represent a connection to their culture or to moments that marked key transitions in life.”</p>\n<blockquote>\n<p><em>“Âm thanh từ không gian công cộng thường hoạt động như những lời nhắc nhở cảm xúc về các truyền thống chung. Tiếng <strong>(Câu hỏi 35) chuông</strong> từ xa từ một hội trường nghi lễ như nhà thờ có thể đánh thức ký ức về các lễ kỷ niệm hoặc các cuộc tụ họp cộng đồng. Đối với nhiều người, những âm thanh đó đại diện cho sự kết nối với văn hóa của họ hoặc với những khoảnh khắc đánh dấu sự chuyển đổi quan trọng trong cuộc sống.”</em></p>\n</blockquote>\n<hr />\n<p>“Next, let’s consider how nostalgia affects us emotionally. Nostalgia can work as a natural coping mechanism when people feel emotionally low. By revisiting happy experiences, individuals can temporarily relieve the weight of <strong>(Question 36) depression</strong>. It serves almost like a psychological reset, reminding us that joy and meaning have existed, and still can.”</p>\n<blockquote>\n<p><em>“Tiếp theo, hãy xem xét hoài niệm ảnh hưởng đến chúng ta về mặt cảm xúc như thế nào. Hoài niệm có thể hoạt động như một cơ chế đối phó tự nhiên khi mọi người cảm thấy buồn bã. Bằng cách xem lại những trải nghiệm hạnh phúc, các cá nhân có thể tạm thời giảm bớt gánh nặng của <strong>(Câu hỏi 36) trầm cảm</strong>. Nó gần như đóng vai trò như một sự thiết lập lại về mặt tâm lý, nhắc nhở chúng ta rằng niềm vui và ý nghĩa đã từng tồn tại, và vẫn có thể tồn tại.”</em></p>\n</blockquote>\n<p>“Certain flavors are strongly tied to early experiences and family traditions. The smell or taste of a <strong>(Question 37) cake</strong> made at home can awaken joyful memories from one’s younger years. This connection between taste and memory is often what makes traditional foods so comforting; they take us back to childhood kitchens and the people who cared for us.”</p>\n<blockquote>\n<p><em>“Một số hương vị nhất định gắn liền chặt chẽ với những trải nghiệm thời thơ ấu và truyền thống gia đình. Mùi hoặc vị của một chiếc <strong>(Câu hỏi 37) bánh</strong> làm tại nhà có thể đánh thức những ký ức vui vẻ từ những năm tháng tuổi trẻ. Mối liên hệ giữa vị giác và ký ức này thường là điều khiến thực phẩm truyền thống trở nên an ủi; chúng đưa chúng ta trở về căn bếp tuổi thơ và những người đã chăm sóc chúng ta.”</em></p>\n</blockquote>\n<p>“Sound is one of the most direct pathways to emotional recall. Just a single <strong>(Question 38) song</strong> from the past can awaken vivid memories and recreate the mood of an earlier moment. Sometimes it’s the lyrics, sometimes it’s the melody, and sometimes it’s simply the familiarity that makes it feel like traveling back in time.”</p>\n<blockquote>\n<p><em>“Âm thanh là một trong những con đường trực tiếp nhất để hồi tưởng cảm xúc. Chỉ một <strong>(Câu hỏi 38) bài hát</strong> duy nhất từ quá khứ cũng có thể đánh thức những ký ức sống động và tái tạo tâm trạng của một khoảnh khắc trước đó. Đôi khi đó là lời bài hát, đôi khi đó là giai điệu, và đôi khi đơn giản chỉ là sự quen thuộc khiến ta có cảm giác như đang du hành ngược thời gian.”</em></p>\n</blockquote>\n<hr />\n<p>“Finally, let’s look at how nostalgia is used in modern life. Advertisers understand that people are more likely to donate when they feel emotionally moved. For this reason, many <strong>(Question 39) charity</strong> appeals are designed around nostalgic themes that create a sense of warmth and empathy. By showing images or playing music from the past, these campaigns encourage people to act out of compassion and shared values.”</p>\n<blockquote>\n<p><em>“Cuối cùng, hãy xem hoài niệm được sử dụng như thế nào trong cuộc sống hiện đại. Các nhà quảng cáo hiểu rằng mọi người có nhiều khả năng quyên góp hơn khi họ cảm thấy xúc động về mặt cảm xúc. Vì lý do này, nhiều lời kêu gọi <strong>(Câu hỏi 39) từ thiện</strong> được thiết kế xoay quanh các chủ đề hoài niệm nhằm tạo ra cảm giác ấm áp và đồng cảm. Bằng cách chiếu hình ảnh hoặc phát nhạc từ quá khứ, các chiến dịch này khuyến khích mọi người hành động vì lòng trắc ẩn và các giá trị chung.”</em></p>\n</blockquote>\n<p>“Nostalgia is sometimes used as a gentle form of <strong>(Question 40) therapy</strong> in hospitals and care homes. A trained nurse might prompt patients to recall pleasant experiences as a way to reduce anxiety and loneliness. This kind of memory-based therapy helps patients regain confidence, maintain cognitive activity, and strengthen their emotional well-being.”</p>\n<blockquote>\n<p><em>“Hoài niệm đôi khi được sử dụng như một hình thức <strong>(Câu hỏi 40) trị liệu</strong> nhẹ nhàng trong bệnh viện và viện dưỡng lão. Một y tá được đào tạo có thể gợi ý bệnh nhân nhớ lại những trải nghiệm thú vị như một cách để giảm bớt lo lắng và cô đơn. Loại liệu pháp dựa trên ký ức này giúp bệnh nhân lấy lại sự tự tin, duy trì hoạt động nhận thức và củng cố trạng thái cảm xúc tốt đẹp của họ.”</em></p>\n</blockquote>\n"}]', 0);
INSERT INTO public.questions VALUES ('0668b98b-41e9-4561-a9a7-40049b4dae06', '39846273-f646-4c3c-8dc5-94351c2590f3', 'matching', 'Questions 36–40', NULL, '<p>Complete the summary using the list of words and phrases, <strong>A-I</strong>, below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>New technology could help retailers sell more</strong></p>\n<p>Research is providing insights into what makes people purchase particular products. Most shoppers believe that their choices are the result of {G rational decisions} . Research involving fMRI scanners, however, has revealed that certain {C unconscious factors} influence shoppers’ decisions to a significant extent. In the research, a comparison was made between participants’ stated opinions of a product and data from {A brain scans} , which often indicated a radically different {H emotional reaction} .As most new products are {E failures} , this data could be extremely valuable for marketing departments.</p>", "answerOptions": [{"optionText": "A brain scans"}, {"optionText": "B purpose"}, {"optionText": "C unconscious factors"}, {"optionText": "D questionnaire"}, {"optionText": "E failures"}, {"optionText": "F procedure"}, {"optionText": "G rational decisions"}, {"optionText": "H emotional reaction"}, {"optionText": "I achievements"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">36. Most shoppers believe that their choices are the result of {G rational decisions}.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “People tell market researchers that they make decisions about what to buy based on <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"95\">logic and common sense</strong>…” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Logic và lẽ thường tương ứng với các quyết định có tính toán/hợp lý (rational decisions).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">37. Research involving fMRI scanners, however, has revealed that certain {C unconscious factors} influence shoppers’ decisions to a significant extent.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…there are clearly other factors… such as certain feelings and memories which individuals are <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"110\">not fully aware of</strong>.” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những cảm xúc và ký ức mà chúng ta không nhận thức đầy đủ chính là các yếu tố vô thức (unconscious factors).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">38. …a comparison was made between participants’ stated opinions of a product and data from {A brain scans}…</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…while <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"21\">scanners reveal their brain activity</strong> as they respond.” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dữ liệu thu được từ máy quét fMRI chính là kết quả quét não (brain scans).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">39. …which often indicated a radically different {H emotional reaction}.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Often, <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"19\">major contradictions</strong> are apparent between what they say and what they are thinking.” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự mâu thuẫn giữa lời nói (logic giả tạo) và suy nghĩ thực tế thường liên quan đến phản ứng cảm xúc thật của họ đối với sản phẩm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">40. As most new products are {E failures}, this data could be extremely valuable for marketing departments.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"24,0,0\" data-index-in-node=\"12\">Eight out of ten new consumer products</strong> launched on the market <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"74\">do not succeed</strong>…” (Đoạn 7).</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tỷ lệ 8/10 sản phẩm không thành công đồng nghĩa với việc hầu hết là sự thất bại (failures).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('e0e7e049-64ae-410a-bba7-c3e8509fa3e3', '72a08353-7870-4d93-84b0-3241ff5d3d46', 'matrix', 'Questions 18–20', '', '<p data-start="628" data-end="710">Write the correct letter, <strong data-start="677" data-end="684">A–F</strong>, next to Questions 18–20.</p>
<p data-start="716" data-end="732"><img src="data:image/png;base64," width="375" height="310" loading="lazy"></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "gallery ", "correctCategoryLetter": "C"}, {"itemText": "woodland ", "correctCategoryLetter": "F"}, {"itemText": "gift shop", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('ccd9f540-ba6d-4b5b-abfe-46092d8bb3ba', '9c785f96-eb67-439a-b7ea-d01f8f297493', 'matrix', 'Questions 14–17', NULL, '<p>Reading Passage 2 has six paragraphs, A–F.</p>
<p>Which paragraph contains the following information?</p>
', 'other', NULL, '[{"option": "A", "correct": false}, {"option": "B", "correct": false}, {"option": "C", "correct": false}, {"option": "D", "correct": false}, {"option": "E", "correct": false}, {"option": "F", "correct": false}]', '{"layoutType": "heading", "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "how a type of plant functions as a natural protection for coastlines", "correctCategoryLetter": "C"}, {"itemText": "a prediction about how long it could take to stop noticing the effects of climate change", "correctCategoryLetter": "A"}, {"itemText": "a reference to the fact that a solution is particularly cost-effective", "correctCategoryLetter": "D"}, {"itemText": "a mention of a technology used to locate areas most in need of intervention", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p>14. Paragraph C<br />(Đoạn: “&#8230; ecosystems of trees and shrubs that help defend coastal areas by trapping sediment in their net-like root systems, elevating the sea bed and dampening the energy of waves and tidal currents.”)<br />→ Mô tả cách cây ngập mặn (mangrove) bảo vệ tự nhiên cho đường bờ biển bằng việc giữ trầm tích và giảm năng lượng sóng. → C.</p>\n<p> <br />15. Paragraph A<br />(Đoạn: “Even if we stopped all CO2 emissions tomorrow… global warming would continue for around 40 years.”)<br />→ Đưa ra dự đoán mất khoảng 40 năm để ngừng nhận thấy tác động của biến đổi khí hậu. → A.</p>\n<p> <br />16. Paragraph D<br />(Đoạn: “It’s much cheaper than permanently elevating houses… about a third of what it would cost…”)<br />→ Nói rõ giải pháp nhà nổi rẻ hơn nhiều so với việc nâng móng cố định — rất tiết kiệm chi phí. → D.</p>\n<p> <br />17. Paragraph F<br />(Đoạn: “Using a Geographic Information System data mapping tool, the programme identified streets with low tree canopy cover&#8230;”)<br />→ Nhắc đến công nghệ bản đồ GIS dùng để xác định khu vực cần can thiệp nhất. → F.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('1ea5f5f6-83a2-414d-9d1a-86192c3c54d6', 'b1c799ef-3ccf-4080-bc81-a248236e8575', 'matching', 'Questions 11 – 15', '', '<p>Which change is proposed for each of the following problem areas?</p>
<p>Choose<strong> FIVE </strong>answers from the box and write the correct letter, <strong>A-G</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Problem areas</strong></p>\n<p> </p>\n<p>Shared access paths {create new grassy areas}</p>\n<p> </p>\n<p>Highway {plant native trees}</p>\n<p> </p>\n<p>Housing estate {build a noise barrier}</p>\n<p> </p>\n<p>Local roads {provide more bus stops}</p>\n<p> </p>\n<p>Picnic area {add flowering plants}</p>", "answerOptions": [{"optionText": "improve the road surface"}, {"optionText": "add flowering plants"}, {"optionText": "provide more bus stops"}, {"optionText": "plant native trees"}, {"optionText": "create new grassy areas"}, {"optionText": "build a noise barrier"}, {"optionText": "install traffic lights"}], "matchingItems": []}', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 2: ROAD AND RAIL IMPROVEMENT PROJECT</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Speaker:</strong> Welcome everyone, thanks for coming to this information evening. The purpose of this meeting is to give you a chance to learn more about the road and rail improvement project. We’ve identified several problem areas and we’ve come up with some changes that we think will improve the local environment.</p>\n<p data-path-to-node=\"4\">For the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"8\">(11) shared access paths</strong></span>—by those I mean the paths shared by both bikes and pedestrians—we plan to <strong data-path-to-node=\"4\" data-index-in-node=\"107\">turn these into open areas with grass around them [Answer: E – create new grassy areas]</strong>. Cyclists and pedestrians need to be able to see each other clearly to avoid any accidents, so we’ve decided to remove the large native trees from the area for that reason.</p>\n<p data-path-to-node=\"5\">Now along the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"14\">(12) highway</strong></span>, we want to <strong data-path-to-node=\"5\" data-index-in-node=\"39\">put trees that are native to this area [Answer: D – plant native trees]</strong> to add shade and make it more attractive. We thought possibly the spotted gum, which grows naturally here.</p>\n<p data-path-to-node=\"6\">Now I know those of you who live in the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"40\">(13) housing estate</strong></span> are disturbed by the sound of traffic nearby. We’re aiming to solve this problem by <strong data-path-to-node=\"6\" data-index-in-node=\"144\">constructing a wall between the estate and the road [Answer: F – build a noise barrier]</strong>, and possibly in the future, we might consider adding some artwork to it. We think this will be quite an effective solution.</p>\n<p data-path-to-node=\"7\">Moving on now to the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"21\">(14) local roads</strong></span>, we want to encourage more public transport use and solve some of our traffic problems. So we’re going to <strong data-path-to-node=\"7\" data-index-in-node=\"144\">add a considerable number of stops to the bus routes [Answer: C – provide more bus stops]</strong> that run along those roads.</p>\n<p data-path-to-node=\"8\">Just finally, as a way of thanking the community for their cooperation, we plan to make the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"92\">(15) picnic area</strong></span> in the park near the bus terminal more attractive. So we’re <strong data-path-to-node=\"8\" data-index-in-node=\"169\">adding some colourful new rose beds [Answer: B – add flowering plants]</strong> that our gardeners will be putting in at the completion of the project.</p>\n<hr data-path-to-node=\"9\">\n<h3 data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">RENOVATIONS TO RICHMOND STATION (Questions 16–20)</strong></h3>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Speaker:</strong> Now I’d like to give you more information about the renovations to Richmond’s train station. Can you all see a copy of the plan?</p>\n<p data-path-to-node=\"12\">We envisage Richmond station as more than just a train station; it’ll be a transport hub linking all forms of transport in the area. To this end, we’re building an underground <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"176\">(16) park and ride car park [Answer: A]</strong>. </span> so commuters can drive to the station, park and then ride to work on the train.That’s the entrance to it on the corner of Progress and Garden Road; you can drive into it from Progress Road.</p>\n<p data-path-to-node=\"13\">Now, on the Progress Road side of the site, on the top left of your map, is where we plan to put the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"101\">(17) bus interchange [Answer: G]</strong></span>. Commuters will have direct access to the platform from the bus interchange via a covered walkway.</p>\n<p data-path-to-node=\"14\">Cycling is an important part of our city’s transport plan, so cyclists will also be fully catered for with 80 new <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"114\">(18) bicycle lockers [Answer: C]</strong></span>. You can see where they are on the plan, in the bottom left-hand corner next to the bike path. Cyclists can ride to the station, store their bikes in the lockers and board the train.</p>\n<p data-path-to-node=\"15\">Oh, and I forgot the most important thing! You’ll even be able to <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"66\">(19) shower [Answer: D]</strong></span> at the station after your bike ride, as we’re installing showers between the toilets and the platform.</p>\n<p data-path-to-node=\"16\">We’ll also install a fountain at the station to make the area more attractive; you can see it in the centre of the plan. And between the fountain and the ticket machine, we’re putting in a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"189\">(20) lift [Answer: F]</strong></span> for our elderly and disabled passengers. They will be able to buy their ticket, then pass directly to the platform via the lift.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Speaker:</strong> So I hope that gives you a much better idea of the new facilities that will be available at Richland Station. Now we would like your feedback about the project so……</p>"}]', 0);
INSERT INTO public.questions VALUES ('2d751372-e68a-4da6-9fc0-c56fb522c8bf', 'e445732a-855b-4052-b4d2-7c385bd9b466', 'radio', 'Questions 1–4', '', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Ruamahanga River often floods."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "When Tobin first found the object in the river, he mistook it for something else."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Tobin could not decide what part of the body the bone came from."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Tobin''s mother was surprised that the skull caused debate among specialists."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">1. The Ruamahanga River often floods.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a four-metre-high flood bank testifies to its natural tendency to flood.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một bờ đê ngăn lũ cao 4 mét là bằng chứng cho thấy con sông này có xu hướng tự nhiên là hay bị lũ lụt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">2. When Tobin first found the object in the river, he mistook it for something else.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…he noticed what he initially took to be a whitish rock…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Lúc đầu Sam Tobin đã nhầm hộp sọ là một <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"52\">viên đá trắng</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">3. Tobin could not decide what part of the body the bone came from.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “As he picked it up, he saw it was a <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"48\">skull</strong>, discoloured with age.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói Tobin không thể quyết định mảnh xương từ bộ phận nào, nhưng bài đọc khẳng định ngay khi cầm lên anh đã nhận ra đó là một <strong data-path-to-node=\"11,2,0\" data-index-in-node=\"145\">hộp sọ</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">4. Tobin’s mother was surprised that the skull caused debate among specialists.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…hurried home to tell his mother what the river had delivered to their doorstep.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói Sam về nhà kể cho mẹ nghe về khám phá, không đề cập đến cảm xúc “ngạc nhiên” của bà trước những tranh luận của các chuyên gia sau này.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('8252f58d-cd33-4fb1-b596-25b03dc436c5', 'e445732a-855b-4052-b4d2-7c385bd9b466', 'fillup', 'Questions 5–9', '<p>Complete the flow-chart below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> from the passage for each answer.</p>
<h3 style="text-align: center;">The events after the river flooded</h3>
<p style="text-align: center;">Tobin found a human skull.</p>
<p class="MsoNormal"><img style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">The  {POLICE}   were initially involved in trying to explain the presence of the skull.</p>
<p style="text-align: center;"><img style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">Dr Ferris believed the skull belonged to a female.</p>
<p style="text-align: center;"><img style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">Dr Koelmeyer suggested it was a  {EUROPEAN}   skull.</p>
<p style="text-align: center;"><img style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">Dr Watt recommended  {Radiocarbon dating}   to establish the skull’s age.</p>
<p style="text-align: center;"><img style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">A bone  {SAMPLE}  was sent to the GNS.</p>
<p style="text-align: center;"><img style="display: block; margin-left: auto; margin-right: auto;" src="data:image/png;base64," width="20" height="25" loading="lazy"></p>
<p style="text-align: center;">The age of the skull was about  {296}   years.</p>', NULL, 'short_answer', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5 . </strong><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> POLICE</p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The police were immediately called, but despite a thorough search could find nothing…”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi Sam kể cho gia đình, cảnh sát là lực lượng đầu tiên tham gia vào việc tìm kiếm và cố gắng giải thích sự xuất hiện của hộp sọ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. </strong><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> EUROPEAN</p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the skull appeared to be European in origin.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bác sĩ Koelmeyer, sau khi tham vấn, đã đưa ra nhận định quan trọng rằng hộp sọ này có đặc điểm nhân chủng học của người Châu Âu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7 . </strong><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> Radiocarbon dating</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…proposed the use of radiocarbon dating to make sure it wasn’t a recent death.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tiến sĩ Watt đã đề xuất sử dụng phương pháp đo carbon phóng xạ để xác định chính xác thời điểm tử vong và đảm bảo đây không phải là một vụ án gần đây.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">8. </strong><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Đáp án:</strong> SAMPLE</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…provided with a sample of bone that had originated in the top of the skull.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong data-path-to-node=\"19,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một mẫu xương (sample) lấy từ phần đỉnh hộp sọ đã được gửi tới Viện Khoa học Địa chất và Hạt nhân (GNS) để phân tích.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">9. </strong><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Đáp án:</strong> 296</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…conventional radiocarbon age approximately 296 years.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong data-path-to-node=\"21,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Kết quả từ phòng thí nghiệm GNS xác định tuổi của hộp sọ là xấp xỉ 296 năm, một con số gây kinh ngạc vì nó lâu đời hơn rất nhiều so với các giả định trước đó.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('feaf8efd-b368-4cd8-b73b-68f1ff7a9dd2', 'e445732a-855b-4052-b4d2-7c385bd9b466', 'fillup', 'Questions 10–13', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>Problem of the skull’s origins</strong></p>
<p>Old bones common in NZ – Maori living there for 800 years – Ruamahanga skull surprising because of its<br>– Age<br>–  {Race}<br>– Gender</p>
<p>Mendana expedition<br>Possible source of skull<br>But probably did not visit NZ<br>Evidence of this expedition found elsewhere by  {archaeologists}</p>
<p>New Zealand<br>First European explorer arrived in 1642<br>Hagerty and Edgar arrived in 1806 from  {Australia}   where they had been imprisoned</p>
<p>Possible solution<br>Ruamahanga skull may have reached NZ in 17th century after a  {shipwreck}</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">10 </strong><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Đáp án:</strong> RACE</p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The fascinating question, however, was how a skull of this race, let alone this gender, had reached these remote islands…”</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong data-path-to-node=\"26,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Hộp sọ gây ngạc nhiên không chỉ bởi giới tính nữ mà còn bởi chủng tộc (race) của nó, vì nó có niên đại trước khi người Châu Âu định cư tại New Zealand.</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">11  </strong><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án:</strong> ARCHAEOLOGISTS</p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…while a team of archaeologists working in the Solomon Islands in 1970 did discover the remains of European vessels dating from the 16th century.”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong data-path-to-node=\"28,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù không thấy bằng chứng của đoàn thám hiểm Mendana tại NZ, nhưng các nhà khảo cổ (archaeologists) đã tìm thấy dấu vết tàu Châu Âu thế kỷ 16 tại quần đảo Solomon.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">12  </strong><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Đáp án:</strong> AUSTRALIA</p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Two centuries were to pass before the first recorded European females arrived in New Zealand, both having escaped from prison in Australia.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong data-path-to-node=\"30,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những phụ nữ Châu Âu đầu tiên chính thức được ghi nhận đến NZ vào năm 1806, xuất thân là những tù nhân trốn thoát từ Úc (Australia).</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">13  </strong><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Đáp án:</strong> SHIPWRECK</p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the most likely explanation is that a Spanish or Portuguese trading-ship was washed onto these wild shores as a result of a shipwreck and a woman got ashore.”</p>\n</li>\n<li>\n<p data-path-to-node=\"32,2,0\"><strong data-path-to-node=\"32,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Giải thích khả thi nhất cho sự hiện diện của hộp sọ này là kết quả từ một vụ đắm tàu (shipwreck) của Tây Ban Nha hoặc Bồ Đào Nha, giúp một người phụ nữ may mắn sống sót dạt vào bờ.</p>\n</li>\n</ul>"}]', 2);
SET session_replication_role = DEFAULT;
